def check_and_install_dependencies():
    """
    Проверяет наличие всех необходимых библиотек и устанавливает отсутствующие
    """
    required_packages = {
        'websockets': 'websockets',
        'pdfplumber': 'pdfplumber',
        'PIL': 'Pillow',
        'win32com': 'pywin32',
        'tkcalendar': 'tkcalendar',
        'babel': 'babel',
        'openpyxl': 'openpyxl',
        'matplotlib': 'matplotlib',
        'psutil': 'psutil',
        'pandas': 'pandas',       # Для экспорта в Excel
        'xlrd': 'xlrd',           # Для чтения .xls файлов
    }

    missing_packages = []

    print("=" * 60)
    print("Проверка зависимостей...")
    print("=" * 60)

    for module_name, package_name in required_packages.items():
        spec = importlib.util.find_spec(module_name)
        if spec is None:
            print(f"[X] Отсутствует: {package_name}")
            missing_packages.append(package_name)
        else:
            print(f"[OK] Установлено: {package_name}")

    if missing_packages:
        print("\n" + "=" * 60)
        print(f"Найдено {len(missing_packages)} отсутствующих пакетов")
        print("Начинаю автоматическую установку...")
        print("=" * 60 + "\n")

        for package in missing_packages:
            try:
                print(f"[>>] Устанавливаю {package}...")
                subprocess.check_call([
                    sys.executable,
                    "-m",
                    "pip",
                    "install",
                    package,
                    "--quiet"
                ])
                print(f"[OK] {package} успешно установлен!\n")
            except subprocess.CalledProcessError as e:
                print(f"[ERROR] Ошибка при установке {package}: {e}")
                print(f"Попробуйте установить вручную: pip install {package}\n")
                return False

        print("=" * 60)
        print("[OK] Все зависимости установлены успешно!")
        print("=" * 60 + "\n")
    else:
        print("\n[OK] Все зависимости уже установлены!\n")

    return True

