FALLBACK_LABELS_ROOTS = []

def resolve_labels_folder(preferred_folder=None):
    """Resolve labels folder without mandatory SMB dependency."""
    if WISO_SERVER_LABELS_ENABLED:
        try:
            LOCAL_SERVER_LABELS_CACHE_ROOT.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        preferred_name = ""
        try:
            preferred_name = str(Path(str(preferred_folder or "")).name or "").strip()
        except Exception:
            preferred_name = ""
        if preferred_name and preferred_name != LOCAL_SERVER_LABELS_CACHE_ROOT.name:
            return LOCAL_SERVER_LABELS_CACHE_ROOT / preferred_name
        return LOCAL_SERVER_LABELS_CACHE_ROOT

    preferred = str(preferred_folder or "").strip().strip('"')
    env_root = str(os.getenv("WISO_LABELS_FOLDER") or "").strip().strip('"')

    candidates = []
    if env_root and preferred:
        pref_path = Path(preferred)
        try:
            candidates.append(str(Path(env_root) / pref_path.name))
        except Exception:
            pass
    if preferred:
        candidates.append(preferred)
    if env_root:
        candidates.append(env_root)
    candidates.extend(FALLBACK_LABELS_ROOTS)
    candidates.append(PRIMARY_LABELS_ROOT)

    for c in candidates:
        try:
            p = Path(c)
            if p.exists():
                return p
        except Exception:
            continue
    return Path(preferred or PRIMARY_LABELS_ROOT)

class ToggleSwitch(tk.Canvas):
    def __init__(self, parent, width=50, height=26, bg_color="#E0E5F2", active_color="#4318FF", command=None, state=False):
        super().__init__(parent, width=width, height=height, bg=parent['bg'], highlightthickness=0)
        self.command = command
        self.is_on = state
        self.bg_color = bg_color
        self.active_color = active_color
        self.width = width
        self.height = height
        
        # Рисуем фон (округлый)
        self.rect = self.create_oval(0, 0, height, height, fill=bg_color, outline="")
        self.rect2 = self.create_oval(width-height, 0, width, height, fill=bg_color, outline="")
        self.rect_main = self.create_rectangle(height/2, 0, width-height/2, height, fill=bg_color, outline="")
        
        # Рисуем кружок (переключатель)
        self.thumb = self.create_oval(2, 2, height-2, height-2, fill="white", outline="")
        
        self.bind("<Button-1>", self.toggle)
        self.update_visuals()

    def toggle(self, event=None):
        self.is_on = not self.is_on
        self.animate()
        if self.command:
            self.command()

    def update_visuals(self):
        color = self.active_color if self.is_on else self.bg_color
        self.itemconfig(self.rect, fill=color)
        self.itemconfig(self.rect2, fill=color)
        self.itemconfig(self.rect_main, fill=color)
        
        if self.is_on:
            self.coords(self.thumb, self.width-self.height+2, 2, self.width-2, self.height-2)
        else:
            self.coords(self.thumb, 2, 2, self.height-2, self.height-2)

    def animate(self):
        # Простая анимация или мгновенное переключение
        self.update_visuals()


class ModernButton(tk.Canvas):
    """
    Современная кнопка с закруглёнными углами и эффектами.
    Стили: primary (синий), success (зелёный), danger (красный), warning (оранжевый), secondary (серый)
    """
    STYLES = {
        'primary':   {'bg': '#2563EB', 'hover': '#1D4ED8', 'fg': '#FFFFFF'},  # Синий - основные действия
        'success':   {'bg': '#16A34A', 'hover': '#15803D', 'fg': '#FFFFFF'},  # Зелёный - успех
        'danger':    {'bg': '#DC2626', 'hover': '#B91C1C', 'fg': '#FFFFFF'},  # Красный - опасность
        'warning':   {'bg': '#F59E0B', 'hover': '#D97706', 'fg': '#FFFFFF'},  # Оранжевый - предупреждение
        'secondary': {'bg': '#E5E7EB', 'hover': '#D1D5DB', 'fg': '#1F2937'},  # Серый - второстепенные
        'outline':   {'bg': 'transparent', 'hover': '#EFF6FF', 'fg': '#2563EB', 'border': '#2563EB'},
    }

    def __init__(self, parent, text="Button", icon=None, style='primary', width=120, height=36,
                 corner_radius=8, command=None, font_size=10, **kwargs):
        # Получаем цвет фона родителя
        try:
            parent_bg = parent.cget('bg')
        except:
            parent_bg = '#FFFFFF'

        super().__init__(parent, width=width, height=height, bg=parent_bg,
                        highlightthickness=0, **kwargs)

        self.command = command
        self.text = text
        self.icon = icon
        self.width = width
        self.height = height
        self.corner_radius = corner_radius
        self.font_size = font_size
        self.parent_bg = parent_bg

        # Получаем цвета стиля
        style_data = self.STYLES.get(style, self.STYLES['primary'])
        self.bg_color = style_data['bg']
        self.hover_color = style_data['hover']
        self.fg_color = style_data['fg']
        self.border_color = style_data.get('border', None)
        self.is_outline = (style == 'outline')

        self._is_hovered = False
        self._is_pressed = False

        self._draw_button()
        self._bind_events()

    def _draw_rounded_rect(self, x1, y1, x2, y2, radius, **kwargs):
        """Рисует прямоугольник с закруглёнными углами"""
        points = [
            x1 + radius, y1,
            x2 - radius, y1,
            x2, y1,
            x2, y1 + radius,
            x2, y2 - radius,
            x2, y2,
            x2 - radius, y2,
            x1 + radius, y2,
            x1, y2,
            x1, y2 - radius,
            x1, y1 + radius,
            x1, y1,
        ]
        return self.create_polygon(points, smooth=True, **kwargs)

    def _draw_button(self):
        self.delete("all")

        # Определяем текущий цвет
        if self._is_pressed:
            bg = self.hover_color
        elif self._is_hovered:
            bg = self.hover_color
        else:
            bg = self.bg_color if not self.is_outline else self.parent_bg

        # Рисуем фон кнопки
        if self.border_color and self.is_outline:
            # Кнопка с рамкой (outline стиль)
            self._draw_rounded_rect(1, 1, self.width-1, self.height-1,
                                   self.corner_radius, fill=bg, outline=self.border_color, width=2)
        else:
            self._draw_rounded_rect(0, 0, self.width, self.height,
                                   self.corner_radius, fill=bg, outline="")

        # Текст кнопки
        display_text = f"{self.icon} {self.text}" if self.icon else self.text
        text_color = self.fg_color if not (self.is_outline and not self._is_hovered) else self.border_color

        self.create_text(self.width/2, self.height/2, text=display_text,
                        fill=text_color, font=("Segoe UI", self.font_size, "bold"))

    def _bind_events(self):
        self.bind("<Enter>", self._on_enter)
        self.bind("<Leave>", self._on_leave)
        self.bind("<Button-1>", self._on_press)
        self.bind("<ButtonRelease-1>", self._on_release)

    def _on_enter(self, event):
        self._is_hovered = True
        self._draw_button()
        self.config(cursor="hand2")

    def _on_leave(self, event):
        self._is_hovered = False
        self._is_pressed = False
        self._draw_button()
        self.config(cursor="")

    def _on_press(self, event):
        self._is_pressed = True
        self._draw_button()

    def _on_release(self, event):
        self._is_pressed = False
        self._draw_button()
        if self._is_hovered and self.command:
            self.command()

    def configure_text(self, text):
        """Изменить текст кнопки"""
        self.text = text
        self._draw_button()

    def configure_style(self, style):
        """Изменить стиль кнопки"""
        style_data = self.STYLES.get(style, self.STYLES['primary'])
        self.bg_color = style_data['bg']
        self.hover_color = style_data['hover']
        self.fg_color = style_data['fg']
        self.border_color = style_data.get('border', None)
        self.is_outline = (style == 'outline')
        self._draw_button()


class ModernEntry(tk.Frame):
    """Современное поле ввода с закруглёнными углами и иконкой"""
    def __init__(self, parent, placeholder="", icon=None, width=200, height=36, **kwargs):
        try:
            parent_bg = parent.cget('bg')
        except:
            parent_bg = '#FFFFFF'

        super().__init__(parent, bg=parent_bg, **kwargs)

        self.placeholder = placeholder
        self.placeholder_color = '#A3AED0'
        self.text_color = '#2B3674'
        self.bg_color = '#F4F7FE'
        self.border_color = '#E0E5F2'
        self.focus_border = '#4318FF'

        # Контейнер с рамкой
        self.container = tk.Frame(self, bg=self.bg_color, highlightbackground=self.border_color,
                                 highlightthickness=1, highlightcolor=self.focus_border)
        self.container.pack(fill=tk.BOTH, expand=True)

        # Иконка (если есть)
        if icon:
            icon_label = tk.Label(self.container, text=icon, bg=self.bg_color, fg=self.placeholder_color,
                                 font=("Segoe UI", 12))
            icon_label.pack(side=tk.LEFT, padx=(10, 5))

        # Поле ввода
        self.entry = tk.Entry(self.container, bg=self.bg_color, fg=self.text_color,
                             font=("Segoe UI", 10), relief="flat", width=width//10,
                             insertbackground=self.text_color)
        self.entry.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=10, pady=8)

        # Placeholder
        self._show_placeholder()
        self.entry.bind("<FocusIn>", self._on_focus_in)
        self.entry.bind("<FocusOut>", self._on_focus_out)

    def _show_placeholder(self):
        if not self.entry.get():
            self.entry.insert(0, self.placeholder)
            self.entry.config(fg=self.placeholder_color)

    def _on_focus_in(self, event):
        if self.entry.get() == self.placeholder:
            self.entry.delete(0, tk.END)
            self.entry.config(fg=self.text_color)

    def _on_focus_out(self, event):
        if not self.entry.get():
            self._show_placeholder()

    def get(self):
        value = self.entry.get()
        return "" if value == self.placeholder else value

    def set(self, value):
        self.entry.delete(0, tk.END)
        self.entry.insert(0, value)
        self.entry.config(fg=self.text_color)


class SegmentedControl(tk.Canvas):
    """
    Современный сегментированный переключатель (как в iOS/macOS).
    Используется для выбора периода, режима и т.д.
    """
    def __init__(self, parent, options, default=0, command=None,
                 bg_color="#E5E7EB", active_color="#2563EB", text_color="#1F2937",
                 active_text="#FFFFFF", height=36, segment_width=80, corner_radius=8,
                 font_size=11, **kwargs):

        self.options = options  # [(text, value), ...]
        self.command = command
        self.selected_index = default
        self.bg_color = bg_color
        self.active_color = active_color
        self.text_color = text_color
        self.active_text = active_text
        self.segment_width = segment_width
        self.height = height
        self.corner_radius = corner_radius
        self.font_size = font_size

        total_width = segment_width * len(options) + 2

        try:
            parent_bg = parent.cget('bg')
        except:
            parent_bg = '#FFFFFF'

        super().__init__(parent, width=total_width, height=height, bg=parent_bg,
                        highlightthickness=0, **kwargs)

        self._draw()
        self.bind("<Button-1>", self._on_click)

    def _draw_rounded_rect(self, x1, y1, x2, y2, radius, **kwargs):
        """Рисует сглаженный скруглённый прямоугольник."""
        r = int(max(1, min(radius, (x2 - x1) / 2, (y2 - y1) / 2)))
        points = [
            x1 + r, y1,
            x2 - r, y1,
            x2, y1,
            x2, y1 + r,
            x2, y2 - r,
            x2, y2,
            x2 - r, y2,
            x1 + r, y2,
            x1, y2,
            x1, y2 - r,
            x1, y1 + r,
            x1, y1,
        ]
        return self.create_polygon(points, smooth=True, splinesteps=24, **kwargs)

    def _draw(self):
        self.delete("all")

        total_width = self.segment_width * len(self.options) + 2

        # Фон (общий контейнер)
        self._draw_rounded_rect(1, 1, total_width - 1, self.height - 1, self.corner_radius,
                               fill=self.bg_color, outline="")

        # Тонкие разделители между сегментами
        for i in range(1, len(self.options)):
            x = i * self.segment_width + 1
            self.create_line(x, 8, x, self.height - 8, fill="#D8E0EE", width=1)

        # Рисуем активный сегмент поверх разделителей
        active_x = self.selected_index * self.segment_width + 1
        self._draw_rounded_rect(
            active_x + 2,
            2,
            active_x + self.segment_width - 2,
            self.height - 2,
            max(2, self.corner_radius - 3),
            fill=self.active_color,
            outline=""
        )

        # Рисуем текст для каждого сегмента
        for i, (text, value) in enumerate(self.options):
            x = i * self.segment_width + self.segment_width / 2 + 1
            y = self.height / 2
            color = self.active_text if i == self.selected_index else self.text_color
            self.create_text(x, y, text=text, fill=color, font=("Segoe UI", self.font_size, "bold"))

    def _on_click(self, event):
        # Определяем какой сегмент кликнули
        clicked_index = event.x // self.segment_width
        if 0 <= clicked_index < len(self.options):
            self.selected_index = clicked_index
            self._draw()
            if self.command:
                self.command(self.options[clicked_index][1])

    def get(self):
        """Получить текущее значение"""
        return self.options[self.selected_index][1]

    def set(self, value):
        """Установить значение"""
        for i, (text, val) in enumerate(self.options):
            if val == value:
                self.selected_index = i
                self._draw()
                break


class ModernCard(tk.Frame):
    """Карточка с реально скругленными углами через Canvas."""
    def __init__(self, parent, bg="#FFFFFF", padding=20, radius=24, border="#DCE6F5",
                 parent_bg=None, width=None, height=None, **kwargs):
        try:
            detected_parent_bg = parent.cget('bg')
        except:
            detected_parent_bg = '#F4F7FE'

        self.parent_bg = parent_bg or detected_parent_bg
        self.card_bg = bg
        self.card_padding = padding
        self.radius = radius
        self.border = border

        super().__init__(parent, bg=self.parent_bg, **kwargs)

        if width is not None:
            self.configure(width=width)
        if height is not None:
            self.configure(height=height)
            self.grid_propagate(False)
            self.pack_propagate(False)

        self.canvas = tk.Canvas(self, bg=self.parent_bg, highlightthickness=0, bd=0)
        self.canvas.pack(fill=tk.BOTH, expand=True)

        self.card = tk.Frame(self.canvas, bg=self.card_bg)
        self._card_window = self.canvas.create_window(
            (self.card_padding, self.card_padding),
            window=self.card,
            anchor="nw"
        )

        self.canvas.bind("<Configure>", self._redraw)

    def _rounded_points(self, x1, y1, x2, y2, r):
        return [
            x1 + r, y1, x2 - r, y1, x2, y1, x2, y1 + r,
            x2, y2 - r, x2, y2, x2 - r, y2, x1 + r, y2,
            x1, y2, x1, y2 - r, x1, y1 + r, x1, y1
        ]

    def _redraw(self, event):
        w = max(event.width, 2)
        h = max(event.height, 2)
        self.canvas.delete("card_bg")

        r = min(self.radius, w // 2 - 1, h // 2 - 1)
        if r < 1:
            r = 1

        self.canvas.create_polygon(
            self._rounded_points(1, 1, w - 1, h - 1, r),
            smooth=True,
            fill=self.card_bg,
            outline=self.border,
            width=1,
            tags="card_bg"
        )
        self.canvas.tag_lower("card_bg")

        inner_w = max(1, w - self.card_padding * 2)
        inner_h = max(1, h - self.card_padding * 2)
        self.canvas.coords(self._card_window, self.card_padding, self.card_padding)
        self.canvas.itemconfigure(self._card_window, width=inner_w, height=inner_h)

    def get_inner(self):
        """Получить внутренний фрейм для размещения контента"""
        return self.card


class ModernToolbar(tk.Frame):
    """
    Современный тулбар с кнопками в едином стиле (как SegmentedControl).
    Кнопки выглядят как на скриншоте - с закруглениями и hover эффектами.
    """
    def __init__(self, parent, bg_color=None, **kwargs):
        try:
            parent_bg = parent.cget('bg')
        except:
            parent_bg = '#F4F7FE'

        self.bg_color = bg_color or parent_bg

        super().__init__(parent, bg=self.bg_color, **kwargs)

        self.buttons = []

    def add_button(self, text, command=None, style='default', icon=None, side=tk.LEFT):
        """
        Добавить кнопку в тулбар.
        style: 'default', 'primary', 'success', 'danger', 'warning'
        """
        btn = ToolbarButton(self, text=text, icon=icon, style=style,
                           command=command, bg_color=self.bg_color)
        btn.pack(side=side, padx=3, pady=5)
        self.buttons.append(btn)
        return btn

    def add_separator(self):
        """Добавить разделитель"""
        sep = tk.Frame(self, width=1, height=24, bg='#E0E5F2')
        sep.pack(side=tk.LEFT, padx=10, pady=5)

    def add_spacer(self):
        """Добавить растягивающийся пробел"""
        spacer = tk.Frame(self, bg=self.bg_color)
        spacer.pack(side=tk.LEFT, fill=tk.X, expand=True)


class ToolbarButton(tk.Canvas):
    """Отдельная кнопка для тулбара с современным стилем"""
    STYLES = {
        # Secondary (серый) - для второстепенных действий (Excel, Settings)
        'default':  {'bg': '#E5E7EB', 'hover': '#D1D5DB', 'fg': '#1F2937', 'active_bg': '#2563EB', 'active_fg': '#FFFFFF'},
        # Primary (синий) - для основных действий (Рассчитать)
        'primary':  {'bg': '#2563EB', 'hover': '#1D4ED8', 'fg': '#FFFFFF', 'active_bg': '#1D4ED8', 'active_fg': '#FFFFFF'},
        # Success (зелёный) - для позитивных действий
        'success':  {'bg': '#16A34A', 'hover': '#15803D', 'fg': '#FFFFFF', 'active_bg': '#15803D', 'active_fg': '#FFFFFF'},
        # Danger (красный) - для деструктивных действий
        'danger':   {'bg': '#DC2626', 'hover': '#B91C1C', 'fg': '#FFFFFF', 'active_bg': '#B91C1C', 'active_fg': '#FFFFFF'},
        # Warning (оранжевый) - для предупреждений
        'warning':  {'bg': '#F59E0B', 'hover': '#D97706', 'fg': '#FFFFFF', 'active_bg': '#D97706', 'active_fg': '#FFFFFF'},
    }

    def __init__(self, parent, text="Button", icon=None, style='default', command=None,
                 bg_color='#F4F7FE', height=32, padding=16, corner_radius=8, **kwargs):

        self.text = f"{icon} {text}" if icon else text
        self.command = command
        self.height = height
        self.padding = padding
        self.corner_radius = corner_radius
        self.parent_bg = bg_color

        # Получаем цвета стиля
        style_data = self.STYLES.get(style, self.STYLES['default'])
        self.bg_color = style_data['bg']
        self.hover_color = style_data['hover']
        self.fg_color = style_data['fg']

        self._is_hovered = False
        self._is_pressed = False

        # Вычисляем ширину на основе текста
        temp_font = ("Segoe UI", 10)
        # Примерная ширина: 8 пикселей на символ + padding
        self.width = len(self.text) * 8 + padding * 2

        super().__init__(parent, width=self.width, height=height, bg=self.parent_bg,
                        highlightthickness=0, **kwargs)

        self._draw()
        self._bind_events()

    def _draw_rounded_rect(self, x1, y1, x2, y2, radius, **kwargs):
        points = [
            x1 + radius, y1, x2 - radius, y1, x2, y1, x2, y1 + radius,
            x2, y2 - radius, x2, y2, x2 - radius, y2, x1 + radius, y2,
            x1, y2, x1, y2 - radius, x1, y1 + radius, x1, y1,
        ]
        return self.create_polygon(points, smooth=True, **kwargs)

    def _draw(self):
        self.delete("all")

        bg = self.hover_color if (self._is_hovered or self._is_pressed) else self.bg_color

        self._draw_rounded_rect(0, 0, self.width, self.height, self.corner_radius,
                               fill=bg, outline="")

        self.create_text(self.width/2, self.height/2, text=self.text,
                        fill=self.fg_color, font=("Segoe UI", 10))

    def _bind_events(self):
        self.bind("<Enter>", self._on_enter)
        self.bind("<Leave>", self._on_leave)
        self.bind("<Button-1>", self._on_press)
        self.bind("<ButtonRelease-1>", self._on_release)

    def _on_enter(self, event):
        self._is_hovered = True
        self._draw()
        self.config(cursor="hand2")

    def _on_leave(self, event):
        self._is_hovered = False
        self._is_pressed = False
        self._draw()

    def _on_press(self, event):
        self._is_pressed = True
        self._draw()

    def _on_release(self, event):
        self._is_pressed = False
        self._draw()
        if self._is_hovered and self.command:
            self.command()


class ModernTabBar(tk.Frame):
    """
    Современная панель вкладок с плавным индикатором (как на iOS/Material Design).
    Заменяет ttk.Notebook для более красивого UI.
    """
    def __init__(self, parent, tabs, on_change=None,
                 bg_color="#F4F6F8", indicator_color="#2563EB",
                 text_color="#1F2937", active_text="#1F2937",
                 height=50, tab_padding=20, corner_radius=25, **kwargs):
        """
        tabs: список кортежей [(название, ключ), ...]
        on_change: callback(key) при смене вкладки
        """
        super().__init__(parent, bg=bg_color, **kwargs)

        self.tabs = tabs
        self.on_change = on_change
        self.bg_color = bg_color
        self.indicator_color = indicator_color
        self.text_color = text_color
        self.active_text = active_text
        self.height = height
        self.tab_padding = tab_padding
        self.corner_radius = corner_radius

        self.selected_index = 0
        self.tab_labels = []
        self.tab_positions = []  # (x, width) для каждой вкладки

        # Контейнер для вкладок
        self.tabs_container = tk.Frame(self, bg=bg_color, height=height)
        self.tabs_container.pack(fill=tk.X, padx=10, pady=5)

        # Canvas для индикатора (под текстом)
        self.canvas = tk.Canvas(self.tabs_container, bg=bg_color,
                               height=height, highlightthickness=0)
        self.canvas.place(x=0, y=0, relwidth=1, relheight=1)

        # Создаём вкладки
        self._create_tabs()

        # Привязка для пересчёта при изменении размера
        self.bind("<Configure>", self._on_resize)

    def _create_tabs(self):
        """Создание элементов вкладок"""
        # Контейнер для текста вкладок (поверх canvas)
        self.labels_frame = tk.Frame(self.tabs_container, bg=self.bg_color)
        self.labels_frame.place(x=0, y=0, relwidth=1, relheight=1)

        for i, (name, key) in enumerate(self.tabs):
            lbl = tk.Label(self.labels_frame, text=name,
                          font=("Segoe UI", 11),
                          bg=self.bg_color,
                          fg=self.active_text if i == 0 else self.text_color,
                          cursor="hand2")
            lbl.pack(side=tk.LEFT, padx=self.tab_padding, pady=10)
            lbl.bind("<Button-1>", lambda e, idx=i: self.select(idx))
            self.tab_labels.append(lbl)

        # Отложенная отрисовка индикатора
        self.after(50, self._draw_indicator)

    def _calculate_positions(self):
        """Вычисляем позиции вкладок"""
        self.tab_positions = []
        for lbl in self.tab_labels:
            x = lbl.winfo_x()
            w = lbl.winfo_width()
            self.tab_positions.append((x, w))

    def _draw_indicator(self):
        """Рисуем индикатор под активной вкладкой"""
        self.canvas.delete("indicator")

        self._calculate_positions()

        if not self.tab_positions or self.selected_index >= len(self.tab_positions):
            return

        x, w = self.tab_positions[self.selected_index]

        # Добавляем отступы для индикатора
        padding = 8
        ind_x = x - padding
        ind_w = w + padding * 2
        ind_h = self.height - 10
        ind_y = 5

        # Рисуем закруглённый прямоугольник
        self._draw_rounded_rect(ind_x, ind_y, ind_x + ind_w, ind_y + ind_h,
                               self.corner_radius, fill=self.indicator_color,
                               tags="indicator")

        # Перемещаем labels_frame наверх
        self.labels_frame.lift()

        # Обновляем цвета текста
        for i, lbl in enumerate(self.tab_labels):
            if i == self.selected_index:
                lbl.config(fg="#FFFFFF", bg=self.indicator_color)
            else:
                lbl.config(fg=self.text_color, bg=self.bg_color)

    def _draw_rounded_rect(self, x1, y1, x2, y2, radius, **kwargs):
        """Рисуем закруглённый прямоугольник на canvas"""
        points = [
            x1 + radius, y1,
            x2 - radius, y1,
            x2, y1,
            x2, y1 + radius,
            x2, y2 - radius,
            x2, y2,
            x2 - radius, y2,
            x1 + radius, y2,
            x1, y2,
            x1, y2 - radius,
            x1, y1 + radius,
            x1, y1,
        ]
        return self.canvas.create_polygon(points, smooth=True, **kwargs)

    def _on_resize(self, event):
        """При изменении размера перерисовываем"""
        self.after(10, self._draw_indicator)

    def select(self, index):
        """Выбрать вкладку по индексу"""
        if index == self.selected_index:
            return

        self.selected_index = index
        self._draw_indicator()

        if self.on_change:
            key = self.tabs[index][1]
            self.on_change(key)

    def get_selected(self):
        """Получить ключ выбранной вкладки"""
        return self.tabs[self.selected_index][1]


class ModernNotebook(tk.Frame):
    """
    Современный Notebook с красивыми вкладками.
    Полная замена ttk.Notebook.
    """
    def __init__(self, parent, bg_color="#F4F6F8", indicator_color="#2563EB",
                 text_color="#1F2937", active_text="#1F2937", **kwargs):
        super().__init__(parent, bg=bg_color, **kwargs)

        self.bg_color = bg_color
        self.indicator_color = indicator_color
        self.text_color = text_color
        self.active_text = active_text

        self.tabs_data = []  # [(name, key, frame), ...]
        self.frames = {}     # key -> frame
        self.current_frame = None
        self.tab_bar = None

        # Контейнер для содержимого
        self.content_frame = tk.Frame(self, bg=bg_color)
        self.content_frame.pack(fill=tk.BOTH, expand=True)

    def add(self, frame, text, key=None):
        """Добавить вкладку"""
        if key is None:
            key = f"tab_{len(self.tabs_data)}"

        self.tabs_data.append((text, key, frame))
        self.frames[key] = frame

        # Скрываем фрейм
        frame.pack_forget()

        # Перестраиваем tab_bar
        self._rebuild_tab_bar()

        # Показываем первую вкладку
        if len(self.tabs_data) == 1:
            self._show_frame(key)

    def _rebuild_tab_bar(self):
        """Перестроить панель вкладок"""
        if self.tab_bar:
            self.tab_bar.destroy()

        tabs = [(name, key) for name, key, _ in self.tabs_data]

        self.tab_bar = ModernTabBar(
            self,
            tabs=tabs,
            on_change=self._on_tab_change,
            bg_color=self.bg_color,
            indicator_color=self.indicator_color,
            text_color=self.text_color,
            active_text=self.active_text
        )
        self.tab_bar.pack(fill=tk.X, before=self.content_frame)

    def _on_tab_change(self, key):
        """Обработчик смены вкладки"""
        self._show_frame(key)

    def _show_frame(self, key):
        """Показать фрейм по ключу"""
        # Скрываем текущий
        if self.current_frame:
            self.current_frame.pack_forget()

        # Показываем новый
        frame = self.frames.get(key)
        if frame:
            frame.pack(in_=self.content_frame, fill=tk.BOTH, expand=True)
            self.current_frame = frame

    def select(self, index_or_key):
        """Выбрать вкладку"""
        if isinstance(index_or_key, int):
            if 0 <= index_or_key < len(self.tabs_data):
                key = self.tabs_data[index_or_key][1]
                self.tab_bar.select(index_or_key)
                self._show_frame(key)
        else:
            for i, (_, key, _) in enumerate(self.tabs_data):
                if key == index_or_key:
                    self.tab_bar.select(i)
                    self._show_frame(key)
                    break


