# ОКНО ВХОДА
# ============================================
class LoginWindow(tk.Toplevel):
    def __init__(self, parent, on_success):
        super().__init__(parent)

        self.on_success = on_success
        self.result = None

        self.title("Вход в систему")
        self.geometry("400x300")
        self.resizable(False, False)

        # Центрируем окно
        self.update_idletasks()
        x = (self.winfo_screenwidth() // 2) - (400 // 2)
        y = (self.winfo_screenheight() // 2) - (300 // 2)
        self.geometry(f'400x300+{x}+{y}')

        self.create_widgets()

        # Модальное окно
        self.transient(parent)
        self.grab_set()
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)

    def create_widgets(self):
        # Логотип/Заголовок
        title_frame = ttk.Frame(self)
        title_frame.pack(pady=30)

        ttk.Label(title_frame, text="🏷️ WISO GoLabel", font=("Arial", 24, "bold")).pack()
        ttk.Label(title_frame, text="Система печати этикеток", font=("Arial", 10)).pack()

        # Форма входа
        form_frame = ttk.Frame(self)
        form_frame.pack(pady=20, padx=40, fill=tk.BOTH, expand=True)

        ttk.Label(form_frame, text="Имя пользователя:", font=("Arial", 10)).pack(anchor=tk.W, pady=(0, 5))
        self.username_entry = ttk.Entry(form_frame, font=("Arial", 11))
        self.username_entry.pack(fill=tk.X, pady=(0, 15))
        self.username_entry.focus()

        ttk.Label(form_frame, text="Пароль:", font=("Arial", 10)).pack(anchor=tk.W, pady=(0, 5))
        self.password_entry = ttk.Entry(form_frame, show="●", font=("Arial", 11))
        self.password_entry.pack(fill=tk.X, pady=(0, 20))

        # Кнопки
        btn_frame = ttk.Frame(form_frame)
        btn_frame.pack(fill=tk.X)

        ttk.Button(btn_frame, text="Войти", command=self.on_login).pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(0, 5))
        ttk.Button(btn_frame, text="Отмена", command=self.on_cancel).pack(side=tk.RIGHT, expand=True, fill=tk.X, padx=(5, 0))

        # Сообщение об ошибке
        self.error_label = ttk.Label(self, text="", foreground="red", font=("Arial", 9))
        self.error_label.pack(pady=(0, 10))

        # Bind Enter key
        self.username_entry.bind('<Return>', lambda e: self.password_entry.focus())
        self.password_entry.bind('<Return>', lambda e: self.on_login())

    def on_login(self):
        username = self.username_entry.get().strip()
        password = self.password_entry.get()

        if not username or not password:
            self.error_label.config(text="Введите имя пользователя и пароль")
            return

        self.result = {
            'username': username,
            'password': password
        }

        self.grab_release()
        self.destroy()

        if self.on_success:
            self.on_success(self.result)

    def on_cancel(self):
        self.result = None
        self.grab_release()
        self.destroy()

