# ПРИНТЕР ЭТИКЕТОК (для склада)
# ============================================
class LabelPrinter:
    def __init__(self):
        # Автоматический поиск GoLabel.exe
        self.golabel_path = self._find_golabel_exe()
        self.templates_folder = resolve_labels_folder(CONFIG['PATHS']['templates_folder'])
        self.box_template_path = self.templates_folder / CONFIG['PATHS']['box_template_name']
        self.temp_folder = CONFIG['PATHS']['temp_folder']
        self.temp_folder.mkdir(parents=True, exist_ok=True)
        # Анти-дубль: защита от случайного повторного вызова печати
        self._last_print_sig = None
        self._last_print_ts = 0.0
        self._last_cleanup_ts = 0.0
        self._template_lookup_cache = {}

    def _find_golabel_exe(self):
        """Автоматический поиск GoLabel.exe в системе"""
        # Список возможных путей
        possible_paths = [
            CONFIG['GOLABEL']['exe_path'],  # Из конфигурации
            r'C:\Program Files (x86)\Godex\GoLabel\GoLabel.exe',
            r'C:\Program Files\Godex\GoLabel\GoLabel.exe',
            r'C:\Program Files (x86)\GoLabel\GoLabel.exe',
            r'C:\Program Files\GoLabel\GoLabel.exe',
            r'C:\GoLabel\GoLabel.exe'
        ]

        # Проверяем каждый путь
        for path in possible_paths:
            if Path(path).exists():
                print(f"[OK] GoLabel найден: {path}")
                return path

        # Пробуем найти через поиск в Program Files
        for program_files in [r'C:\Program Files (x86)', r'C:\Program Files']:
            if os.path.exists(program_files):
                for root, dirs, files in os.walk(program_files):
                    if 'GoLabel.exe' in files:
                        found_path = os.path.join(root, 'GoLabel.exe')
                        print(f"[OK] GoLabel найден автоматически: {found_path}")
                        return found_path

        # Если не найден - используем путь из конфига (может не существовать)
        print(f"[!] ВНИМАНИЕ: GoLabel.exe не найден! Используется путь из конфига: {CONFIG['GOLABEL']['exe_path']}")
        print(f"[!] Установите GoLabel или проверьте путь в CONFIG")
        return CONFIG['GOLABEL']['exe_path']

    def print_template(self, template_path, qty=1, data=None, pre_cleanup=True):
        """Печать шаблона"""
        import time

        # Жесткий reset GoLabel перед каждым заданием, чтобы не тащить состояние прошлого запуска.
        if pre_cleanup:
            self._kill_all_golabel_processes()

        # Проверяем что GoLabel существует
        if not Path(self.golabel_path).exists():
            raise FileNotFoundError(
                f"GoLabel.exe не найден!\n"
                f"Путь: {self.golabel_path}\n\n"
                f"Установите GoLabel на этот компьютер:\n"
                f"1. Скачайте GoLabel с сайта Godex\n"
                f"2. Установите в стандартную папку\n"
                f"3. Перезапустите программу"
            )

        # Проверяем что шаблон существует
        if not template_path.exists():
            raise FileNotFoundError(
                f"Шаблон этикетки не найден!\n"
                f"Путь: {template_path}\n\n"
                f"Проверьте:\n"
                f"1. Путь к папке с этикетками правильный\n"
                f"2. Файл этикетки существует\n"
                f"3. Доступ к сетевой папке"
            )

        local_path = self.temp_folder / template_path.name
        shutil.copy2(template_path, local_path)

        # Защита от двойного вызова (двойной клик/повторный event)
        try:
            sig = (str(template_path).lower(), int(float(qty or 0)))
        except Exception:
            sig = (str(template_path).lower(), 0)
        now_ts = time.time()
        if self._last_print_sig == sig and (now_ts - self._last_print_ts) < 0.35:
            print(f"[PRINT] SKIP duplicate call: {template_path.name} x{qty}")
            local_path.unlink(missing_ok=True)
            return True
        self._last_print_sig = sig
        self._last_print_ts = now_ts

        cmd = [self.golabel_path, '-f', str(local_path), '-c', str(qty)]

        data_path = None
        if data:
            data_path = self.temp_folder / "data.json"
            data_path.write_text(json.dumps(data, ensure_ascii=False), 'utf-8')
            cmd.extend(['-d', str(data_path)])

        # ДЕТАЛЬНОЕ ЛОГИРОВАНИЕ
        print(f"\n[PRINT] ==========================================")
        print(f"[PRINT] Template: {template_path.name}")
        print(f"[PRINT] Quantity: {qty}")
        print(f"[PRINT] Command: {' '.join(cmd)}")
        print(f"[PRINT] ==========================================\n")

        try:
            # ВАЖНО: Используем Popen для контроля над процессом
            process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)

            # Ждем завершения с таймаутом
            try:
                stdout, stderr = process.communicate(timeout=90)

                if process.returncode != 0:
                    error_msg = f"GoLabel завершился с ошибкой:\n"
                    error_msg += f"Код: {process.returncode}\n"
                    if stderr:
                        error_msg += f"Ошибка: {stderr}\n"
                    if stdout:
                        error_msg += f"Вывод: {stdout}\n"
                    raise Exception(error_msg)

                print(f"[PRINT] ✓ Success: {template_path.name} x {qty}")
                return True

            except subprocess.TimeoutExpired:
                # Принудительно завершаем процесс
                process.kill()
                process.wait()
                raise Exception("Timeout: GoLabel не отвечает более 90 секунд")

        except Exception as e:
            raise Exception(f"Ошибка печати: {e}")
        finally:
            local_path.unlink(missing_ok=True)
            if data_path:
                data_path.unlink(missing_ok=True)

    def clean_temp_folder(self):
        """Очистка временной папки от всех файлов"""
        try:
            for file in self.temp_folder.glob('*'):
                if file.is_file():
                    file.unlink(missing_ok=True)
            print(f"[CLEANUP] Temp папка очищена")
        except Exception as e:
            print(f"[CLEANUP] Ошибка при очистке temp папки: {e}")

    def _kill_all_golabel_processes(self, force=False):
        """Завершить все запущенные процессы GoLabel.exe для очистки очереди печати"""
        import time
        now = time.time()
        if not force and (now - self._last_cleanup_ts) < 2.0:
            return
        self._last_cleanup_ts = now

        try:
            import psutil
            killed_count = 0
            for proc in psutil.process_iter(['name', 'pid']):
                try:
                    if proc.info['name'] and 'golabel.exe' in proc.info['name'].lower():
                        proc.kill()
                        killed_count += 1
                        print(f"[CLEANUP] Завершен процесс GoLabel.exe (PID: {proc.info['pid']})")
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass

            if killed_count > 0:
                import time
                time.sleep(0.5)  # Даем время на полное завершение
                print(f"[CLEANUP] Завершено {killed_count} процессов GoLabel.exe")
        except ImportError:
            # Если psutil не установлен, используем taskkill
            try:
                subprocess.run(['taskkill', '/F', '/IM', 'GoLabel.exe'],
                             capture_output=True, timeout=1.5)
                time.sleep(0.5)
                print(f"[CLEANUP] GoLabel процессы завершены через taskkill")
            except:
                print(f"[CLEANUP] Не удалось завершить GoLabel процессы (psutil не установлен)")
        except Exception as e:
            print(f"[CLEANUP] Ошибка при завершении GoLabel процессов: {e}")

    def print_products(self, artikel_list, labels_folder=None):
        """
        Печать списка товаров.
        ИСПРАВЛЕНО:
        1. Если этикетки нет -> просто пропускаем товар (для украшений).
        2. Количество жестко берется из ключа 'menge'.
        3. ОЧИСТКА перед печатью + завершение GoLabel процессов
        """
        folder = Path(labels_folder) if labels_folder else self.templates_folder

        print(f"[PRINT] Начало печати {len(artikel_list)} позиций...")

        # КРИТИЧЕСКИ ВАЖНО: Очистка temp папки перед началом печати
        self.clean_temp_folder()

        # КРИТИЧЕСКИ ВАЖНО: Завершаем все процессы GoLabel перед печатью
        self._kill_all_golabel_processes(force=True)

        def _normalize_article(n):
            raw = str(n or '').strip()
            if '-' in raw:
                raw = raw.split('-')[-1].strip()
            if raw.isdigit():
                return raw.zfill(5)
            return raw

        # Схлопываем дубли артикула в заказе: один артикул печатаем один раз с суммой количества.
        grouped = {}
        for artikel in (artikel_list or []):
            nummer_raw = str(artikel.get('nummer') or artikel.get('artikel_nr') or '').strip()
            nummer = _normalize_article(nummer_raw)
            if not nummer:
                continue
            try:
                qty = int(float(artikel.get('menge', 1)))
            except Exception:
                qty = 1
            if qty <= 0:
                continue
            if nummer not in grouped:
                grouped[nummer] = {'qty': 0}
            grouped[nummer]['qty'] += qty

        print(f"[PRINT] Уникальных артикулов после объединения: {len(grouped)}")
        for nummer, agg in grouped.items():
            qty = int(agg.get('qty', 0) or 0)
            if qty <= 0:
                continue

            cache_key = (str(folder).lower(), nummer)
            cached = self._template_lookup_cache.get(cache_key, None)
            template_file = None

            if cached is False:
                print(f"[SKIP] Нет этикетки для артикула {nummer}. Пропуск.")
                continue
            if isinstance(cached, str):
                cpath = Path(cached)
                if cpath.exists():
                    template_file = cpath

            if template_file is None:
                # Поиск шаблона (исходная логика без полного сканирования дерева)
                templates = []
                templates.extend(list(folder.glob(f"{nummer} *.ezpx")))
                if not templates:
                    templates.extend(list(folder.glob(f"{nummer}_*.ezpx")))
                if not templates:
                    templates.extend(list(folder.glob(f"{nummer}*.ezpx")))
                if not templates:
                    for sub in folder.iterdir():
                        if sub.is_dir():
                            templates.extend(list(sub.glob(f"{nummer} *.ezpx")))
                            if not templates:
                                templates.extend(list(sub.glob(f"{nummer}_*.ezpx")))
                            if not templates:
                                templates.extend(list(sub.glob(f"{nummer}*.ezpx")))
                            if templates:
                                break

                if not templates:
                    self._template_lookup_cache[cache_key] = False
                    print(f"[SKIP] Нет этикетки для артикула {nummer}. Пропуск.")
                    continue
                template_file = templates[0]
                self._template_lookup_cache[cache_key] = str(template_file)

            print(f"[PRINT] Печатаем: {template_file.name} (Кол-во: {qty})")

            # Вызываем печать одной этикетки
            self.print_template(template_file, qty=qty, pre_cleanup=False)

    def print_box(self, kunde, address, box_num, total_boxes, lieferschein):
        """Печать этикетки коробки (старый метод для совместимости)"""
        box_data = {
            'KUNDE': kunde,
            'ADRESSE': address,
            'BOX_NUM': f"{box_num} из {total_boxes}",
            'LIEFERSCHEIN': lieferschein
        }

        self.print_template(self.box_template_path, qty=1, data=box_data)

    @staticmethod
    def _format_weight_kg(value):
        """Format weight in kg for label text (German decimal comma)."""
        txt = f"{float(value):.3f}".rstrip('0').rstrip('.')
        return txt.replace('.', ',')

    def print_zakaznoj_weight_label(self, weight_kg, qty=1):
        """
        Print dedicated Zakaznoj label (05525) via dummy_data.txt in template folder.
        Template remains unchanged; only Gewicht value in text "DB" file is updated.
        """
        import csv
        import shutil
        import subprocess

        if not Path(self.golabel_path).exists():
            raise FileNotFoundError(f"GoLabel.exe не найден: {self.golabel_path}")

        try:
            qty_i = max(1, int(float(qty or 1)))
        except Exception:
            qty_i = 1

        try:
            weight_val = float(str(weight_kg).replace(',', '.'))
        except Exception as exc:
            raise ValueError("Некорректный вес для печати.") from exc
        if weight_val <= 0:
            raise ValueError("Вес должен быть больше нуля.")

        zakaznoj_dir = self.templates_folder / "zakaznoj"
        template_path = zakaznoj_dir / "05525_Zakaznoj.ezpx"
        if not template_path.exists():
            raise FileNotFoundError("Не найден шаблон Zakaznoj (05525_Zakaznoj.ezpx).")
        # Runtime-файлы держим рядом с временным шаблоном, чтобы GoLabel
        # гарантированно читал свежие данные именно этой печати.
        local_template = self.temp_folder / "05525_Zakaznoj_runtime.ezpx"
        local_dummy_path = self.temp_folder / "dummy_data.txt"
        local_schema_path = self.temp_folder / "schema.ini"

        self._kill_all_golabel_processes()

        weight_text = self._format_weight_kg(weight_val)

        try:
            schema_lines = [
                "[dummy_data.txt]",
                "ColNameHeader=True",
                "Format=Delimited(;)",
                "CharacterSet=1252",
                'Col1="Gewicht" Text',
                'Col2="NoName" Text',
            ]
            local_schema_path.write_text("\n".join(schema_lines) + "\n", encoding="cp1252", errors="replace")

            with open(local_dummy_path, "w", newline="", encoding="cp1252", errors="replace") as f:
                writer = csv.writer(f, delimiter=';', lineterminator="\n")
                writer.writerow(["Gewicht", ""])
                writer.writerow([weight_text, ""])
        except Exception as exc:
            raise RuntimeError(f"Не удалось записать dummy_data/schema для Zakaznoj: {exc}") from exc

        # Печатаем всегда с временной копии шаблона, чтобы GoLabel не изменял оригинал
        # (иначе в некоторых конфигурациях накапливается смещение объектов).
        try:
            shutil.copy2(template_path, local_template)
            # Критично для Zakaznoj: часть шаблонов хранит абсолютный путь к БД.
            # Принудительно указываем runtime dummy_data.txt.
            tpl_text = local_template.read_text(encoding='utf-8')
            import re as _re
            db_match = _re.search(r'<DataBaseFilePath>.*?</DataBaseFilePath>', tpl_text)
            if db_match:
                tpl_text = tpl_text.replace(
                    db_match.group(0),
                    f'<DataBaseFilePath>{local_dummy_path}</DataBaseFilePath>'
                )
                local_template.write_text(tpl_text, encoding='utf-8')
        except Exception as exc:
            raise RuntimeError(f"Не удалось подготовить временный шаблон Zakaznoj: {exc}") from exc

        cmd = [self.golabel_path, '-f', str(local_template), '-c', str(qty_i)]
        print(f"[ZAKAZNOJ] Weight={weight_text} kg, qty={qty_i}")
        print(f"[ZAKAZNOJ] dummy_data: {local_dummy_path}")
        print(f"[ZAKAZNOJ] Command: {' '.join(cmd)}")

        try:
            process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            stdout, stderr = process.communicate(timeout=30)
            if process.returncode != 0:
                raise RuntimeError(f"GoLabel code {process.returncode}: {stderr or stdout}")
            return True
        except subprocess.TimeoutExpired:
            process.kill()
            raise RuntimeError("GoLabel TIMEOUT (30s) при печати Zakaznoj.")
        finally:
            try:
                local_template.unlink(missing_ok=True)
            except Exception:
                pass

    def _get_default_printer(self):
        """Получить принтер по умолчанию"""
        try:
            import win32print

            # Получаем принтер по умолчанию
            default_printer = win32print.GetDefaultPrinter()

            print(f"[PRINTER] Используется принтер по умолчанию: {default_printer}")
            return default_printer

        except ImportError:
            raise ImportError("Модуль win32print не установлен. Установите: pip install pywin32")
        except Exception as e:
            raise Exception(f"Ошибка получения принтера по умолчанию: {e}")

    # УДАЛЕН - используется только print_box_label_via_worker через PrintWorker

    # Искать в файле: clients/unified_client.py

    # Искать в файле: clients/unified_client.py, в классе LabelPrinter

    def print_box_label(self, box_data):
        """
        Печать паспорта. 
        ИСПРАВЛЕНО: Убран ключ -d, чтобы GoLabel использовал относительный путь.
        """
        import csv
        import shutil
        import subprocess

        server_template_path = self.templates_folder / "Passport" / "Passport.ezpx"
        if not server_template_path.exists():
            server_template_path = self.templates_folder / "Passport.ezpx"
        if not server_template_path.exists():
            print(f"[ERROR] Шаблон не найден: {server_template_path}")
            return False

        # --- КЛЮЧЕВОЕ ИЗМЕНЕНИЕ ---
        # Файл данных будет лежать РЯДОМ с шаблоном во временной папке
        data_filename = "dummy_data.txt" 
        local_template_path = self.temp_folder / "Passport.ezpx"
        local_data_path = self.temp_folder / data_filename

        try:
            shutil.copy2(server_template_path, local_template_path)
        except Exception as e:
            print(f"[ERROR] Не удалось скопировать шаблон: {e}")
            return False

        headers = ['KUNDE', 'ADRESSE', 'BOX_NUM', 'BESTELLUNG_NUMMER', 'REGION', 'VERPACKUNGSDATUM', 'KUNDE_NUMMER']
        row_data = {key: str(box_data.get(key, '')) for key in headers}

        try:
            with open(local_data_path, 'w', newline='', encoding='cp1252', errors='replace') as f:
                writer = csv.DictWriter(f, fieldnames=headers, delimiter=';')
                writer.writeheader()
                writer.writerow(row_data)
        except Exception as e:
            print(f"[ERROR] Ошибка записи файла данных: {e}")
            return False

        # --- КЛЮЧЕВОЕ ИЗМЕНЕНИЕ ---
        # Убираем ключ -d из команды. GoLabel сам найдет dummy_data.txt рядом с шаблоном.
        cmd = [
            self.golabel_path,
            '-f', str(local_template_path),
            '-c', '1'
        ]

        try:
            process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            stdout, stderr = process.communicate(timeout=25)
            if process.returncode == 0:
                print(f"[PRINT] ✅ Паспорт {row_data['BOX_NUM']} отправлен на печать")
                return True
            else:
                print(f"[ERROR] GoLabel code {process.returncode}: {stderr or stdout}")
                return False
        except Exception as e:
            print(f"[ERROR] Сбой запуска GoLabel: {e}")
            return False

    def print_box_label_via_worker(self, box_data):
        """
        Печать этикетки коробки через print_worker.py (как в arbeitet)
        Создает файл задания, который обрабатывается отдельным процессом

        Args:
            box_data: dict с полями 'KUNDE', 'ADRESSE', 'BOX_NUM', 'LIEFERSCHEIN'
        """
        import time

        # Путь к файлу задания (тот же что в arbeitet/print_worker.py)
        job_file_path = Path(os.getenv("TEMP")) / "WISO_Labels_Temp" / "box_print_job.txt"

        # Формируем содержимое файла (с дополнительными полями)
        content = (
            f"KUNDE:{box_data.get('KUNDE', '')}\n"
            f"ADRESSE:{box_data.get('ADRESSE', '')}\n"
            f"BOX_NUM:{box_data.get('BOX_NUM', '')}\n"
            f"LIEFERSCHEIN:{box_data.get('LIEFERSCHEIN', '')}\n"
            f"REGION:{box_data.get('REGION', '')}\n"
            f"ARTIKEL_NAME:{box_data.get('ARTIKEL_NAME', '')}\n"
            f"VORGANGS_NR:{box_data.get('VORGANGS_NR', '')}\n"
            f"KOLI_GESAMT:{box_data.get('KOLI_GESAMT', '')}\n"
            f"VERPACKUNGSDATUM:{box_data.get('VERPACKUNGSDATUM', '')}\n"
        )

        # Ждем пока предыдущее задание обработается
        timeout = 30
        start_time = time.time()
        while job_file_path.exists() and time.time() - start_time < timeout:
            time.sleep(0.5)

        if job_file_path.exists():
            print("[WORKER] ⚠️ Print Worker не обработал предыдущее задание вовремя")
            raise RuntimeError("Print Worker не отвечает. Убедитесь что print_worker.py запущен!")

        # Создаем новый файл задания
        job_file_path.parent.mkdir(parents=True, exist_ok=True)
        job_file_path.write_text(content, encoding='utf-8')
        print(f"[WORKER] ✓ Создано задание для печати: {box_data.get('BOX_NUM', '')}")

        # Даем воркеру время на обработку
        time.sleep(2)
        return True

    def print_box_label(self, box_data):
        """
        Печать паспорта через GoLabel.
        Исправлено: Кодировка cp1252 (ANSI) для корректного чтения заголовков Windows-программами.
        """
        import csv
        import shutil
        import subprocess
        import os

        # 1. ПУТЬ К ШАБЛОНУ НА СЕРВЕРЕ
        server_template_path = self.templates_folder / "Passport" / "Passport.ezpx"
        if not server_template_path.exists():
            server_template_path = self.templates_folder / "Passport.ezpx"

        if not server_template_path.exists():
            print(f"[ERROR] Шаблон не найден: {server_template_path}")
            return False

        # 2. ПОДГОТОВКА ФАЙЛОВ
        # Используем фиксированное имя файла данных
        data_filename = "dummy_data.txt" 
        
        local_template_path = self.temp_folder / "Passport.ezpx"
        local_data_path = self.temp_folder / data_filename

        # Копируем шаблон и обновляем путь к файлу данных внутри шаблона
        try:
            shutil.copy2(server_template_path, local_template_path)
            # ВАЖНО: GoLabel использует DataBaseFilePath из шаблона, а не параметр -d
            # Обновляем путь чтобы указывал на фактическое расположение dummy_data.txt
            tpl_text = local_template_path.read_text(encoding='utf-8')
            # Замена пути к файлу данных (str.replace вместо re.sub чтобы не ломалось на \Users)
            import re as _re
            db_match = _re.search(r'<DataBaseFilePath>.*?</DataBaseFilePath>', tpl_text)
            if db_match:
                tpl_text = tpl_text.replace(db_match.group(0), f'<DataBaseFilePath>{local_data_path}</DataBaseFilePath>')
            local_template_path.write_text(tpl_text, encoding='utf-8')
        except Exception as e:
            print(f"[ERROR] Не удалось скопировать/обновить шаблон: {e}")
            return False

        # 3. ЗАПИСЬ ДАННЫХ
        # Заголовки должны быть ИДЕНТИЧНЫ тем, что в шаблоне
        headers = ['KUNDE', 'ADRESSE', 'BOX_NUM', 'BESTELLUNG_NUMMER', 'REGION', 'VERPACKUNGSDATUM', 'KUNDE_NUMMER']

        row_data = {
            'KUNDE': str(box_data.get('KUNDE', '')),
            'ADRESSE': str(box_data.get('ADRESSE', '')),
            'BOX_NUM': str(box_data.get('BOX_NUM', '')),
            'BESTELLUNG_NUMMER': str(box_data.get('BESTELLUNG_NUMMER', '')),
            'REGION': str(box_data.get('REGION', '')),
            'VERPACKUNGSDATUM': str(box_data.get('VERPACKUNGSDATUM', '')),
            'KUNDE_NUMMER': str(box_data.get('KUNDE_NUMMER', ''))
        }

        print(f"[PASSPORT] Data: {row_data}")

        try:
            with open(local_data_path, 'w', newline='', encoding='cp1252', errors='replace') as f:
                writer = csv.DictWriter(f, fieldnames=headers, delimiter=';')
                writer.writeheader()
                writer.writerow(row_data)

            # Верификация: читаем файл обратно
            with open(local_data_path, 'r', encoding='cp1252') as f:
                file_content = f.read()
            print(f"[PASSPORT] Data file: {local_data_path}")
            print(f"[PASSPORT] Data content:\n{file_content}")

        except Exception as e:
            print(f"[PASSPORT ERROR] Ошибка записи файла: {e}")
            return False

        # Проверяем DataBaseFilePath в шаблоне
        try:
            tpl_check = local_template_path.read_text(encoding='utf-8')
            import re as _re2
            db_match = _re2.search(r'<DataBaseFilePath>(.*?)</DataBaseFilePath>', tpl_check)
            if db_match:
                print(f"[PASSPORT] Template DataBaseFilePath: {db_match.group(1)}")
            else:
                print(f"[PASSPORT WARNING] No DataBaseFilePath in template!")
        except Exception as e:
            print(f"[PASSPORT WARNING] Cannot read template: {e}")

        # 4. ЗАПУСК GOLABEL
        cmd = [
            self.golabel_path,
            '-f', str(local_template_path),
            '-c', '1'
        ]

        print(f"[PASSPORT] GoLabel cmd: {' '.join(cmd)}")

        try:
            process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            stdout, stderr = process.communicate(timeout=30)

            print(f"[PASSPORT] GoLabel returncode: {process.returncode}")
            if stdout:
                print(f"[PASSPORT] GoLabel stdout: {stdout.strip()}")
            if stderr:
                print(f"[PASSPORT] GoLabel stderr: {stderr.strip()}")

            if process.returncode == 0:
                print(f"[PASSPORT] OK: {row_data['BOX_NUM']}")
                return True
            else:
                print(f"[PASSPORT ERROR] GoLabel code {process.returncode}")
                return False

        except subprocess.TimeoutExpired:
            process.kill()
            print(f"[PASSPORT ERROR] GoLabel TIMEOUT (30s) — процесс убит")
            return False
        except Exception as e:
            print(f"[PASSPORT ERROR] Сбой GoLabel: {e}")
            return False

    def search_and_print(self, search_term, quantity=1):
        """Поиск и печать этикетки по артикулу"""
        pattern = f"{search_term}*"
        templates = list(self.templates_folder.glob(pattern))

        if not templates:
            raise FileNotFoundError(f"Шаблон не найден для '{search_term}'")

        self.print_template(templates[0], qty=quantity)
        return templates[0].name

# ============================================
# ФОНОВЫЙ WORKER ДЛЯ ПЕЧАТИ КОРОБОК
# ============================================
class PrintWorker:
    """
    Фоновый процесс для печати этикеток коробок
    Следит за файлом заданий и автоматически печатает когда он появляется
    """
    def __init__(self, printer_name="BPZ430i+"):
        self.printer_name = printer_name
        self.job_file = Path(os.getenv("TEMP")) / "WISO_Labels_Temp" / "box_print_job.txt"
        self.running = False
        self.thread = None

    def start(self):
        """Запустить worker в фоновом потоке"""
        if self.running:
            print("[WORKER] Уже запущен")
            return

        self.running = True
        self.thread = threading.Thread(target=self._worker_loop, daemon=True)
        self.thread.start()
        print(f"[WORKER] ✅ Запущен (версия 7.0 - HORIZONTAL). Принтер: {self.printer_name}")

    def stop(self):
        """Остановить worker"""
        self.running = False
        if self.thread:
            self.thread.join(timeout=2)
        print("[WORKER] Остановлен")

    def _worker_loop(self):
        """Основной цикл worker'а (выполняется в фоновом потоке)"""
        import time

        while self.running:
            try:
                if self.job_file.exists():
                    print(f"[WORKER] 📄 Найден файл задания: {self.job_file.name}")

                    # Читаем файл
                    job_data = {}
                    try:
                        with open(self.job_file, 'r', encoding='utf-8') as f:
                            for line in f:
                                if ':' in line:
                                    key, value = line.split(':', 1)
                                    job_data[key.strip()] = value.strip()

                        # Удаляем файл
                        self.job_file.unlink()

                        # Печатаем
                        if job_data:
                            self._print_label(job_data)

                    except Exception as e:
                        print(f"[WORKER] ❌ Ошибка обработки файла: {e}")
                        if self.job_file.exists():
                            self.job_file.unlink()

            except Exception as e:
                print(f"[WORKER] ❌ Ошибка в цикле worker: {e}")

            time.sleep(1)

    def _print_label(self, data):
        """Печать этикетки коробки"""
        try:
            import win32print

            # Получаем данные с значениями по умолчанию
            kunde = data.get("KUNDE", "")
            adresse = data.get("ADRESSE", "")
            box_num = data.get("BOX_NUM", "")
            lieferschein = data.get("LIEFERSCHEIN", "")
            region = data.get("REGION", "MITTE")  # По умолчанию MITTE
            artikel_name = data.get("ARTIKEL_NAME", "")
            vorgangs_nr = data.get("VORGANGS_NR", lieferschein)
            koli_gesamt = data.get("KOLI_GESAMT", "")

            # Дата - если нет, берем текущую
            verpackungsdatum = data.get("VERPACKUNGSDATUM", "")
            if not verpackungsdatum:
                from datetime import datetime
                verpackungsdatum = datetime.now().strftime('%d.%m.%Y')

            # Генерируем ZPL-код
            # ^POR = Поворот на 270° (визуально это 90° вправо/по часовой стрелке)
            # Размеры: 100x150мм = 1200x800 dots при 203dpi

            zpl_code = f"""^XA
^POR
^PW1200
^LL800
^CI28

^FO50,50^A0N,80,80^FD{kunde}^FS
^FO50,150^A0N,50,50^FD{adresse}^FS
^FO50,250^A0N,70,70^FDBox: {box_num}^FS
^FO50,350^A0N,50,50^FDLieferschein: {lieferschein}^FS
^FO50,450^A0N,50,50^FDRegion: {region}^FS
^FO50,550^A0N,50,50^FDDatum: {verpackungsdatum}^FS

^XZ"""

            # Очищаем пробелы
            zpl_code = "\n".join(line.strip() for line in zpl_code.strip().split("\n"))

            print(f"[WORKER] Печать: {box_num}")
            print(f"[WORKER] ZPL код:\n{zpl_code}")

            # Отправляем на принтер
            h_printer = win32print.OpenPrinter(self.printer_name)
            try:
                win32print.StartDocPrinter(h_printer, 1, ("Box Label ZPL", None, "RAW"))
                try:
                    win32print.StartPagePrinter(h_printer)
                    win32print.WritePrinter(h_printer, zpl_code.encode('utf-8'))
                    win32print.EndPagePrinter(h_printer)
                finally:
                    win32print.EndDocPrinter(h_printer)
            finally:
                win32print.ClosePrinter(h_printer)

            print(f"[WORKER] ✓ Отправлено на принтер '{self.printer_name}'")
            return True

        except Exception as e:
            print(f"[WORKER] ❌ Ошибка печати: {e}")
            import traceback
            traceback.print_exc()
            return False


class VMIRecommendationsFrame(tk.Frame):
    """UI frame for VMI recommendations workflow."""

    def __init__(self, parent, app):
        super().__init__(parent, bg=app.colors["bg_card"])
        self.app = app
        self._selected = {}  # key: (article_nr, region) -> bool
        self._build_ui()

    def _build_ui(self):
        toolbar = tk.Frame(self, bg=self.app.colors["bg_card"])
        toolbar.pack(fill=tk.X, padx=8, pady=(8, 6))

        ttk.Button(
            toolbar,
            text="Рассчитать VMI план",
            command=self.app.request_vmi_recommendations
        ).pack(side=tk.LEFT, padx=(0, 8))

        ttk.Button(
            toolbar,
            text="Утвердить выбранное в План",
            command=self._approve_selected
        ).pack(side=tk.LEFT)

        self.vmi_status_label = tk.Label(
            toolbar,
            text="Готово к расчету",
            bg=self.app.colors["bg_card"],
            fg=self.app.colors["text_light"],
            font=("Segoe UI", 9)
        )
        self.vmi_status_label.pack(side=tk.RIGHT, padx=4)

        table_wrap = tk.Frame(self, bg=self.app.colors["bg_card"])
        table_wrap.pack(fill=tk.BOTH, expand=True, padx=8, pady=(0, 8))

        cols = (
            "selected",
            "article_nr",
            "region",
            "current_stock",
            "burn_rate",
            "recommend_pallets",
            "recommend_pieces",
        )
        self.tree = ttk.Treeview(table_wrap, columns=cols, show='headings')
        self.tree.heading("selected", text="Выбрано")
        self.tree.heading("article_nr", text="Артикул")
        self.tree.heading("region", text="Регион")
        self.tree.heading("current_stock", text="Текущий остаток")
        self.tree.heading("burn_rate", text="Скорость продаж (шт/день)")
        self.tree.heading("recommend_pallets", text="Рекомендовано (Паллет)")
        self.tree.heading("recommend_pieces", text="Рекомендовано (Штук)")

        self.tree.column("selected", width=90, anchor="center")
        self.tree.column("article_nr", width=110, anchor="center")
        self.tree.column("region", width=120, anchor="center")
        self.tree.column("current_stock", width=130, anchor="center")
        self.tree.column("burn_rate", width=170, anchor="center")
        self.tree.column("recommend_pallets", width=160, anchor="center")
        self.tree.column("recommend_pieces", width=170, anchor="center")

        sy = ttk.Scrollbar(table_wrap, orient=tk.VERTICAL, command=self.tree.yview)
        self.tree.configure(yscrollcommand=sy.set)
        self.tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        sy.pack(side=tk.RIGHT, fill=tk.Y)

        self.tree.bind("<Double-1>", self._toggle_row_selected)

    def set_status(self, text):
        if hasattr(self, "vmi_status_label"):
            self.vmi_status_label.config(text=str(text or ""))

    def set_recommendations(self, recommendations):
        self.tree.delete(*self.tree.get_children())
        self._selected = {}

        for rec in recommendations or []:
            article_nr = str(rec.get("article_nr", "")).strip()
            region = str(rec.get("region", "")).strip()
            key = (article_nr, region)
            self._selected[key] = False

            self.tree.insert("", tk.END, values=(
                "Нет",
                article_nr,
                region,
                int(rec.get("current_stock", 0) or 0),
                float(rec.get("burn_rate", 0.0) or 0.0),
                int(rec.get("recommend_pallets", 0) or 0),
                int(rec.get("recommend_pieces", 0) or 0),
            ))

        self.set_status(f"Найдено рекомендаций: {len(recommendations or [])}")

    def _toggle_row_selected(self, _event=None):
        item_id = self.tree.focus()
        if not item_id:
            return
        values = list(self.tree.item(item_id, "values"))
        if len(values) < 3:
            return

        article_nr = str(values[1]).strip()
        region = str(values[2]).strip()
        key = (article_nr, region)
        current = bool(self._selected.get(key, False))
        new_value = not current
        self._selected[key] = new_value
        values[0] = "Да" if new_value else "Нет"
        self.tree.item(item_id, values=values)

    def get_selected_items(self):
        selected = []
        for item_id in self.tree.get_children():
            values = self.tree.item(item_id, "values")
            if len(values) < 7:
                continue
            if str(values[0]).strip().lower() != "да":
                continue
            selected.append({
                "article_nr": str(values[1]).strip(),
                "region": str(values[2]).strip(),
                "recommend_pieces": int(float(values[6]) if values[6] else 0),
            })
        return selected

    def _approve_selected(self):
        items = self.get_selected_items()
        if not items:
            messagebox.showinfo("VMI", "Выберите позиции (двойной клик по строке).")
            return
        self.app.approve_vmi_recommendations(items)


