    def get_all_selected_order_ids(self, tree):
        """
        НОВЫЙ МЕТОД: Возвращает список уникальных ID заказов из текущего выделения.
        Работает с множественным выбором (Ctrl/Shift).
        """
        selection = tree.selection()
        if not selection: return []

        unique_ids = set()

        for item_id in selection:
            # Получаем теги и значения
            tags = tree.item(item_id, 'tags')
            values = tree.item(item_id, 'values')
            parent_id = tree.parent(item_id)
            
            # 1. Если это ГРУППА ДАТЫ -> пропускаем
            if 'date_group' in tags or 'today_group' in tags:
                continue

            # 2. Если это АРТИКУЛ (есть родитель, и родитель не дата) -> берем ID родителя
            # Но в нашей структуре (Дата -> Заказ -> Артикул) артикул это 3-й уровень.
            # Либо (Заказ -> Артикул) если без дат.
            # Проще проверить: есть ли values и похож ли values[0] на ID заказа.
            
            # Попробуем определить, это заказ или артикул
            # У заказа в values[0] стоит ID (или чистый ID)
            # У артикула в values[0] стоит "└ 05501"
            
            first_col = str(values[0]) if values else ""
            
            if "â""" in first_col: 
                # Это артикул. Родитель - это заказ.
                parent_item = tree.item(parent_id)
                # Если родитель - это группа даты, значит структура была нарушена, но обычно parent - это заказ
                if parent_item and parent_item['values']:
                     # ID заказа обычно в первой колонке родителя
                     # Но там "чистый" ID. Нам нужно найти полный ID в self.orders
                     clean_id = str(parent_item['values'][0])
                     unique_ids.add(clean_id)
            else:
                # Это сам заказ
                unique_ids.add(first_col)

        # Теперь нужно превратить "чистые" ID (2003196...) обратно в полные ключи (AB-2003196...), 
        # которые лежат в self.orders
        final_list = []
        for clean_id in unique_ids:
            # Ищем совпадение в базе заказов
            found = False
            for real_oid in self.orders.keys():
                # Сравниваем очищенные версии (поддержка AB- и MO- заказов)
                real_clean = str(real_oid).replace('AB-', '').replace('MO-', '').replace(' ', '').split('.')[0]
                if real_clean == str(clean_id) or str(real_oid) == str(clean_id):
                    final_list.append(real_oid)
                    found = True
                    break
            
            if not found:
                # Если не нашли (редкий случай), добавляем как есть, вдруг это и есть ключ
                final_list.append(clean_id)

        return list(final_list)    

    def _admin_get_visible_order_ids(self):
        """Получить все ID заказов, которые сейчас отображаются в таблице 'Все заказы'."""
        if not hasattr(self, 'admin_orders_tree'):
            return []

        tree = self.admin_orders_tree
        clean_ids = set()

        def walk(parent=''):
            for item in tree.get_children(parent):
                values = tree.item(item, 'values') or ()
                tags = set(tree.item(item, 'tags') or ())

                # Пропускаем группы дат
                if 'date_group' in tags or 'today_group' in tags:
                    walk(item)
                    continue

                if values:
                    first_col = str(values[0]).strip()
                    # Пропускаем строки позиций (артикулы внутри заказа)
                    if first_col and ('└' not in first_col) and ('â""' not in first_col):
                        clean_ids.add(first_col)

                walk(item)

        walk('')

        # Преобразуем отображаемые ID в реальные ключи self.orders
        final_ids = []
        for clean_id in clean_ids:
            found = False
            for real_oid in self.orders.keys():
                real_clean = str(real_oid).replace('AB-', '').replace('MO-', '').replace(' ', '').split('.')[0]
                if real_clean == str(clean_id) or str(real_oid) == str(clean_id):
                    final_ids.append(real_oid)
                    found = True
                    break
            if not found:
                final_ids.append(clean_id)

        return final_ids

    def admin_actualize_logistics(self):
        """
        Массовая актуализация логистики:
        - если есть выделение: только выделенные заказы
        - если выделения нет: все заказы, отображаемые в таблице
        """
        selected_ids = self.get_all_selected_order_ids(self.admin_orders_tree)
        if selected_ids:
            order_ids = selected_ids
            scope_text = "выбранных"
        else:
            order_ids = self._admin_get_visible_order_ids()
            scope_text = "всех видимых"

        if not order_ids:
            messagebox.showwarning("Внимание", "Нет заказов для актуализации логистики")
            return

        if not messagebox.askyesno(
            "Актуализация логистики",
            f"Актуализировать логистику для {len(order_ids)} {scope_text} заказов?\n"
            "Система пересчитает ближайшую дату по правилам маршрутов."
        ):
            return

        for oid in order_ids:
            self.send_ws_message({
                'type': 'recalc_order_logistics',
                'order_id': oid
            })

        messagebox.showinfo("Готово", f"Запущена актуализация: {len(order_ids)} заказ(ов)")
    
    def on_weekly_plan_double_click(self, event):
        """Обработка двойного клика по недельному плану (Открытие карточки)"""
        if not hasattr(self, 'weekly_tree'): return
        
        item_id = self.weekly_tree.identify_row(event.y)
        if not item_id: return
        
        values = self.weekly_tree.item(item_id)['values']
        if not values: return
        
        # Артикул - первый элемент
        art_nr = str(values[0])
        
        # Если это строка разделителя или заголовка - игнорируем
        if not art_nr or not art_nr[0].isdigit(): return

        # Здесь можно открыть ту же карточку, что и в дневном плане, 
        # или просто информационное окно
