        end_date_picker.pack(side=tk.LEFT, padx=5)

        content_frame = ttk.Frame(stats_window)
        content_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=5)

        left_f = ttk.LabelFrame(content_frame, text="Детальный отчет")
        left_f.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        cols = ('Сборщик', 'Заказов', 'Тортов (шт)')
        self.current_stats_tree = ttk.Treeview(left_f, columns=cols, show='headings')
        for c in cols: self.current_stats_tree.heading(c, text=c)
        self.current_stats_tree.pack(fill=tk.BOTH, expand=True)

        right_f = ttk.LabelFrame(content_frame, text="Диаграмма нагрузки")
