    def _configure_tree_tags(self, tree):
        """Настройка цветов строк таблицы на основе темы"""
        c = self.colors
        
        # Основные статусы
        tree.tag_configure('completed', background=c["row_completed"], foreground=c["text_main"])
        tree.tag_configure('order_completed', background=c["row_completed"], foreground=c["text_main"])
        
        tree.tag_configure('in_progress', background=c["row_in_progress"], foreground=c["text_main"])
        tree.tag_configure('order_in_progress', background=c["row_in_progress"], foreground=c["text_main"])
        
        tree.tag_configure('not_started', background=c["row_default"], foreground=c["text_main"])
        tree.tag_configure('order', background=c["row_default"], foreground=c["text_main"])
        
        tree.tag_configure('printed', background=c["row_printed"], foreground=c["text_main"])
        tree.tag_configure('locked', background=c["row_locked"], foreground=c["text_main"])

        # API заказы (без жирного)
        tree.tag_configure('api_new', background=c["row_default"], foreground=c["text_main"])
        tree.tag_configure('api_new_in_progress', background=c["row_in_progress"], foreground=c["text_main"])

        # Группы
        tree.tag_configure('date_group', background=c["row_group"], foreground=c["text_main"], font=('Segoe UI', 10, 'bold'))
        tree.tag_configure('today_group', background=c["accent"], foreground="#FFFFFF", font=('Segoe UI', 10, 'bold'))
        
        # Артикулы (вложенные)
        tree.tag_configure('artikel', background=c["bg_card"], foreground=c["text_light"])
        # Поисковое совпадение (поверх обычных тегов)
        tree.tag_configure('search_match', background='#FFF3B0', foreground='#1F2937')

    def on_double_click(self, event, tree):
        """
        Умный клик:
        - План (6) -> Раскрыть список
        - Запас(4)/Факт(7) -> Быстрый ввод
        - Остальное -> Большая карточка (Диалог)
        """
        region = tree.identify_region(event.x, event.y)
        if region != "cell": return
    
        column = tree.identify_column(event.x)
        item_id = tree.identify_row(event.y)
        
        # Если кликнули по дочерней строке (заказу) - игнорируем
        if tree.parent(item_id): return

        try:
            col_idx = int(column[1:]) - 1
        except: return
        
        values = tree.item(item_id)['values']
        if not values: return

        # === ЛОГИКА 1: РАСКРЫТИЕ (Клик по Плану) ===
        if col_idx == 6:
            if tree.item(item_id, 'open'):
                tree.item(item_id, open=False)
            else:
                tree.item(item_id, open=True)
                self.on_plan_tree_open(None) # Подгрузка данных
            return "break"

        # === ЛОГИКА 2: БЫСТРОЕ РЕДАКТИРОВАНИЕ (Запас / Факт) ===
        if col_idx in [4, 7]:
            current_val = values[col_idx]
            display_val = str(current_val)
            if display_val == "-" or display_val == "0": display_val = ""
        
            x, y, w, h = tree.bbox(item_id, column)
            entry = tk.Entry(tree, font=("Arial", 10))
            entry.insert(0, display_val)
            entry.place(x=x, y=y, width=w, height=h)
            entry.focus_set()
            entry.selection_range(0, tk.END)

            def save_edit(event_inner=None):
                new_val = entry.get().strip().replace(',', '.')
                num_val = float(new_val) if new_val else 0.0
                
                # Визуальное обновление
                new_values_list = list(tree.item(item_id)['values'])
                new_values_list[col_idx] = num_val if num_val != 0 else "-"
                tree.item(item_id, values=new_values_list)
                
                art_nr = str(new_values_list[1])
                date_str = self.plan_date_entry.get_date().strftime('%Y-%m-%d')
                
                if col_idx == 7: # Факт
                    self.send_ws_message({'type': 'update_production_fact', 'date': date_str, 'article_nr': art_nr, 'fact_qty': num_val})
                elif col_idx == 4: # Запас
                    self.send_ws_message({'type': 'adjust_stock', 'date': date_str, 'article_nr': art_nr, 'new_qty': num_val})

                entry.destroy()
                tree.focus_set()

            entry.bind("<Return>", save_edit)
            entry.bind("<KP_Enter>", save_edit)
            entry.bind("<Escape>", lambda e: entry.destroy())
            entry.bind("<FocusOut>", lambda e: entry.destroy())
            return

        # === ЛОГИКА 3: БОЛЬШОЕ ОКНО (Клик в любом другом месте) ===
        # Если кликнули по Названию, Артикулу и т.д. -> Открываем карточку
        self.show_production_detail_dialog(event)

    def operator_apply_filter(self):
        """Фильтр оператора: По диапазону доставки"""
        if not hasattr(self, 'operator_tree'): return
        self.operator_tree.delete(*self.operator_tree.get_children())
        
        # Получаем даты из календарей
        d_from = self.op_date_from.get_date()
        d_to = self.op_date_to.get_date()
        
        orders_by_delivery = {}

        for order_id, order_info in self.orders.items():
            data = order_info['data']
            
            # Дата доставки
            delivery_str = data.get('delivery_date', '9999-12-31')
            try:
                del_date = datetime.strptime(delivery_str, "%Y-%m-%d").date()
            except:
                continue # Пропускаем если дата битая
            
            # Фильтр: показываем только то, что попадает в календарь
            if not (d_from <= del_date <= d_to):
                continue
                
            if delivery_str not in orders_by_delivery:
                orders_by_delivery[delivery_str] = []
            orders_by_delivery[delivery_str].append((order_id, data))

        # Сортировка create_interface
        sorted_dates = sorted(orders_by_delivery.keys())

        for date_str in sorted_dates:
            orders = orders_by_delivery[date_str]
            
            # Красивая дата
            try:
                d_obj = datetime.strptime(date_str, "%Y-%m-%d")
                wd = d_obj.strftime("%A") # День недели
                # ... (тут можно добавить перевод дней недели) ...
                d_disp = f"🚚 {d_obj.strftime('%d.%m.%Y')} ({wd})"
            except: d_disp = date_str

            grp_id = self.operator_tree.insert('', tk.END, text='📅',
                values=(d_disp, "", "", "", f"{len(orders)} зак.", "", "", "", ""),
                tags=('date_group',), open=True
            )
            
            # Вставляем заказы внутри группы даты
            for order_id, data in orders:
                art_list = data.get('artikel', [])
                total = len(art_list)
                picked_count = sum(1 for a in art_list if a.get('checked'))
                
                # Логика цвета (теги)
                tag = 'not_started'
                is_printed = data.get('printed', False)
                if picked_count >= total and total > 0: tag = 'completed'
                elif picked_count > 0: tag = 'in_progress'
                elif is_printed: tag = 'printed'
                
                lbl_st = '✅' if is_printed else '⏳'
                inv_st = data.get('invoice_status', '⏳')
                box_st = f"📦 {data.get('boxes_count')}" if data.get('boxes_count') else '-'
                pick_status_str = f"{picked_count}/{total} поз."
                
                # Вставка строки заказа
                # Очищаем номер от пробелов
                display_auftrag = self.clean_order_number(data.get('auftrag_nr', order_id))
                ord_item = self.operator_tree.insert(grp_id, tk.END, text='📦',
                    values=(
                        display_auftrag,
                        data.get('kunden_nr', ''),
                        data.get('kunde', ''),
                        data.get('address', ''),
                        pick_status_str,
                        lbl_st,
                        inv_st,
                        box_st,
                        data.get('status', '')
                    ), tags=(tag,))

                # Вставка артикулов внутри заказа
                for idx, art in enumerate(art_list, 1):
                    p_qty = art.get('picked', 0)
                    m_qty = art.get('menge', 0)
                    check = art.get('checked', False)
                    st_icon = "✅" if check else ("🔄" if p_qty > 0 else "⏳")
                    
                    art_name = art.get('beschreibung', art.get('name', '')) # Название товара
                    
                    self.operator_tree.insert(ord_item, tk.END, text=f'  â"" {idx}',
                        values=(
                            f"Арт: {art.get('artikel_nr', art.get('nummer',''))}",
                            "", 
                            art_name, 
                            "", 
                            f"{st_icon} {p_qty}/{m_qty}", 
                            "", "", "", ""
                        ), tags=('artikel',))

    def center_dialog(self, dialog, width, height):
        """
        Центрировать диалоговое окно на АКТИВНОМ мониторе

        Args:
            dialog: Toplevel окно для центрирования
            width: ширина окна
            height: высота окна
        """
        # Единая логика: подгоняем размер под контент и центрируем на экране
        self._fit_and_center_dialog(dialog, min_width=width, min_height=height)

        # Сделать окно активным
        dialog.lift()
        dialog.focus_force()

    def show_login(self):
        """Показать современное окно входа"""
        # Цветовая палитра
        COLORS = {
            "bg": "#F4F5F7",       # Серый фон окна
            "card": "#FFFFFF",     # Белая карточка
            "primary": "#0052CC",  # Синий (кнопка входа)
            "danger": "#DE350B",   # Красный (кнопка выхода)
            "text": "#172B4D",     # Темный текст
            "subtext": "#6B778C",  # Серый текст
            "border": "#DFE1E6"    # Границы полей
        }

        # Очищаем окно
        for widget in self.winfo_children():
            widget.destroy()

        # Настраиваем само окно
        self.configure(bg=COLORS["bg"])
        self.geometry("450x550") # Чуть больше для воздуха
        
        # Центрируем окно на мониторе
        screen_width = self.winfo_screenwidth()
        screen_height = self.winfo_screenheight()
        x = (screen_width // 2) - (450 // 2)
        y = (screen_height // 2) - (550 // 2)
        self.geometry(f"450x550+{x}+{y}")

        # === ЦЕНТРАЛЬНАЯ КАРТОЧКА ===
        # Используем Frame для создания белого блока по центру
        card = tk.Frame(self, bg=COLORS["card"], padx=40, pady=40)
        card.place(relx=0.5, rely=0.5, anchor="center", relwidth=0.85)
        
        # Логотип / Заголовок
        logo_path = self._get_logo_path()
        if logo_path.exists():
            try:
                raw_logo = tk.PhotoImage(file=str(logo_path))
                max_w = 220
                max_h = 90
                div_w = max(1, (raw_logo.width() + max_w - 1) // max_w)
                div_h = max(1, (raw_logo.height() + max_h - 1) // max_h)
                div = max(div_w, div_h)
                self.login_logo_image = raw_logo.subsample(div, div)
                tk.Label(card, image=self.login_logo_image, bg=COLORS["card"]).pack(pady=(0, 8))
            except Exception as e:
                print(f"[LOGO] Не удалось загрузить logo.png: {e}")
                tk.Label(card, text="WISO GoLabel", font=("Segoe UI", 22, "bold"),
                         bg=COLORS["card"], fg=COLORS["primary"]).pack(pady=(0, 5))
        else:
            tk.Label(card, text="WISO GoLabel", font=("Segoe UI", 22, "bold"),
                     bg=COLORS["card"], fg=COLORS["primary"]).pack(pady=(0, 5))
        
        tk.Label(card, text="Авторизация", font=("Segoe UI", 11), 
                 bg=COLORS["card"], fg=COLORS["subtext"]).pack(pady=(0, 30))

        # --- ПОЛЯ ВВОДА (ИСПРАВЛЕНО) ---
        
        # Логин
        tk.Label(card, text="Имя пользователя", font=("Segoe UI", 10, "bold"), 
                 bg=COLORS["card"], fg=COLORS["text"]).pack(anchor="w", pady=(0, 5))
        
        # Используем highlightthickness для создания цветной рамки
        self.username_entry = tk.Entry(card, font=("Segoe UI", 11), 
                                       relief="flat", bg="#FAFBFC", fg=COLORS["text"],
                                       highlightbackground=COLORS["border"], 
                                       highlightcolor=COLORS["primary"],
                                       highlightthickness=1, bd=5) # bd=5 создает внутренний отступ (padding)
        self.username_entry.pack(fill="x", pady=(0, 15), ipady=3) # ipady увеличивает высоту поля

        # Пароль
        tk.Label(card, text="Пароль", font=("Segoe UI", 10, "bold"), 
                 bg=COLORS["card"], fg=COLORS["text"]).pack(anchor="w", pady=(0, 5))
        
        self.password_entry = tk.Entry(card, show="●", font=("Segoe UI", 11), 
                                       relief="flat", bg="#FAFBFC", fg=COLORS["text"],
                                       highlightbackground=COLORS["border"], 
                                       highlightcolor=COLORS["primary"],
                                       highlightthickness=1, bd=5)
        self.password_entry.pack(fill="x", pady=(0, 25), ipady=3)

        # --- КНОПКИ ---
        
        # Кнопка ВОЙТИ (Синяя, большая)
        login_btn = tk.Button(card, text="Войти в систему", command=self.on_login,
                              font=("Segoe UI", 11, "bold"),
                              bg=COLORS["primary"], fg="white",
                              activebackground="#0065FF", activeforeground="white",
                              relief="flat", cursor="hand2", pady=8)
        login_btn.pack(fill="x", pady=(0, 10))

        # Кнопка ВЫЙТИ (Текст или красная рамка)
        exit_btn = tk.Button(card, text="Выход", command=self.on_closing,
                             font=("Segoe UI", 10),
                             bg=COLORS["card"], fg=COLORS["danger"],
                             activebackground="#FFFAE6", activeforeground=COLORS["danger"],
                             relief="flat", cursor="hand2", bd=0)
        exit_btn.pack(fill="x")

        # Сообщение об ошибке
        self.error_label = tk.Label(card, text="", foreground=COLORS["danger"], 
                                    bg=COLORS["card"], font=("Segoe UI", 9))
        self.error_label.pack(pady=(15, 0))

        # Фокус и Enter
        self.username_entry.focus()
        self.username_entry.bind('<Return>', lambda e: self.password_entry.focus())
        self.password_entry.bind('<Return>', lambda e: self.on_login())

    def logistics_add_client(self):
        """Добавить нового клиента вручную"""
        self.client_editor_dialog(mode='add')

    def logistics_edit_client(self):
        """Редактировать выбранного клиента"""
        sel = self.logistics_tree.selection()
        if not sel:
            messagebox.showwarning("Внимание", "Выберите клиента для редактирования")
            return
        
        item_vals = self.logistics_tree.item(sel[0])['values']
        client_id = str(item_vals[0])
        
        # Ищем полные данные в памяти
        client_data = next((c for c in self.logistics_clients if str(c['client_id']) == client_id), None)
        if client_data:
            self.client_editor_dialog(mode='edit', data=client_data)

    def logistics_delete_client(self):
        """Удалить клиента"""
        sel = self.logistics_tree.selection()
        if not sel:
            messagebox.showwarning("Внимание", "Выберите клиента")
            return
            
        item_vals = self.logistics_tree.item(sel[0])['values']
        client_id = str(item_vals[0])
        client_name = str(item_vals[1])
        
        if messagebox.askyesno("Удаление", f"Удалить клиента {client_name} (ID: {client_id})?"):
            # Удаляем локально (мгновенный эффект)
            self.logistics_clients = [c for c in self.logistics_clients if str(c['client_id']) != client_id]
            self.logistics_filter_clients()
            
            # Отправляем на сервер
            self.send_ws_message({
                'type': 'delete_client',
                'client_id': client_id
            })

    def client_editor_dialog(self, mode='add', data=None):
        """Единый диалог карточки клиента с субвкладками: данные + правила логистики."""
        if data is None:
            data = {
                'client_id': '',
                'monolith_client_id': '',
                'client_name': '',
                'email': '',
                'first_name': '',
                'last_name': '',
                'company_name': '',
                'website_url': '',
                'vat_id': '',
                'phone': '',
                'position_title': '',
                'address': '',
                'plz': '',
                'city': '',
                'country': 'Deutschland',
                'price_list': 'Händlerpreise',
                'discount_enabled': 0,
                'discount_percent': 0,
                'payment_terms': '30 Tage Netto',
                'tags': '',
                'route_id': 'free',
                'transport_type': 'Eigenes Auto',
                'delivery_point': 'Geschäft',
                'route_rules': '[]'
            }

        dialog = tk.Toplevel(self)
        title = "Einstellungen für Kundendaten" if mode == 'add' else f"Einstellungen für Kundendaten: {data.get('client_name', '')}"
        dialog.title(title)
        dialog.transient(self)
        dialog.grab_set()
        # Для этого диалога отключаем глобальный авто-layout:
        # он иногда повторно сжимает окно до "контентного" размера.
        dialog._skip_auto_layout = True
        # Делаем окно заметно больше (примерно в 2 раза), с ограничением по экрану.
        screen_w = int(self.winfo_screenwidth() or 1366)
        screen_h = int(self.winfo_screenheight() or 900)
        preferred_w = max(1180, min(1500, screen_w - 40))
        preferred_h = max(820, min(1040, screen_h - 40))
        self.center_dialog(dialog, preferred_w, preferred_h)
        dialog.geometry(f"{preferred_w}x{preferred_h}")
        dialog.minsize(980, 720)
        dialog.configure(bg="#E9EDF5")

        card = tk.Frame(dialog, bg="#F7F9FC", highlightbackground="#D7DCE8", highlightthickness=1)
        card.pack(fill=tk.BOTH, expand=True, padx=14, pady=14)

        top = tk.Frame(card, bg="#F7F9FC", padx=10, pady=8)
        top.pack(fill=tk.X)
        tk.Label(top, text="◂", font=("Segoe UI", 10), bg="#F7F9FC", fg="#4F67D9").pack(side=tk.LEFT, padx=(0, 6))
        tk.Label(top, text="Einstellungen für Kundendaten", font=("Segoe UI", 12, "bold"), bg="#F7F9FC", fg="#1F2937").pack(side=tk.LEFT)
        tk.Label(top, text="✕", font=("Segoe UI", 14), bg="#F7F9FC", fg="#4B5563", cursor="hand2").pack(side=tk.RIGHT)
        top.winfo_children()[-1].bind("<Button-1>", lambda _e: dialog.destroy())

        tk.Frame(card, bg="#E3E8F2", height=1).pack(fill=tk.X, padx=0, pady=(0, 8))

        tabs = ttk.Notebook(card)
        tabs.pack(fill=tk.BOTH, expand=True, padx=8, pady=(0, 6))

        tab_data = ttk.Frame(tabs)
        tab_rules = ttk.Frame(tabs)
        tabs.add(tab_data, text="Kundendaten")
        tabs.add(tab_rules, text="Logistikregeln")

        def _make_scrollable_tab(parent, bg="#F7F9FC"):
            wrap = tk.Frame(parent, bg=bg)
            wrap.pack(fill=tk.BOTH, expand=True)

            canvas = tk.Canvas(wrap, bg=bg, highlightthickness=0, bd=0)
            y_scroll = ttk.Scrollbar(wrap, orient=tk.VERTICAL, command=canvas.yview)
            inner = ttk.Frame(canvas, padding=6)
            inner_window = canvas.create_window((0, 0), window=inner, anchor="nw")

            def _on_inner_configure(_event=None):
                try:
                    canvas.configure(scrollregion=canvas.bbox("all"))
                except Exception:
                    pass

            def _on_canvas_configure(event):
                try:
                    canvas.itemconfigure(inner_window, width=event.width)
                except Exception:
                    pass

            inner.bind("<Configure>", _on_inner_configure)
            canvas.bind("<Configure>", _on_canvas_configure)
            canvas.configure(yscrollcommand=y_scroll.set)

            canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
            y_scroll.pack(side=tk.RIGHT, fill=tk.Y)

            def _wheel(event):
                try:
                    if event.delta:
                        canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
                    elif getattr(event, "num", None) == 4:
                        canvas.yview_scroll(-3, "units")
                    elif getattr(event, "num", None) == 5:
                        canvas.yview_scroll(3, "units")
                except Exception:
                    pass

            def _bind_wheel(_event=None):
                canvas.bind_all("<MouseWheel>", _wheel)
                canvas.bind_all("<Button-4>", _wheel)
                canvas.bind_all("<Button-5>", _wheel)

            def _unbind_wheel(_event=None):
                canvas.unbind_all("<MouseWheel>")
                canvas.unbind_all("<Button-4>")
                canvas.unbind_all("<Button-5>")

            canvas.bind("<Enter>", _bind_wheel)
            canvas.bind("<Leave>", _unbind_wheel)

            return inner

        tab_data_inner = _make_scrollable_tab(tab_data)
        tab_rules_inner = _make_scrollable_tab(tab_rules)

        left = ttk.Frame(tab_data_inner, padding=6)
        right = ttk.Frame(tab_data_inner, padding=6)
        left.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        right.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        # Vars
        v_id = tk.StringVar(value=str(data.get('client_id', '') or ''))
        v_monolith = tk.StringVar(value=str(data.get('monolith_client_id', '') or ''))
        v_name = tk.StringVar(value=str(data.get('client_name', '') or ''))
        v_email = tk.StringVar(value=str(data.get('email', '') or ''))
        v_first_name = tk.StringVar(value=str(data.get('first_name', '') or ''))
        v_last_name = tk.StringVar(value=str(data.get('last_name', '') or ''))
        v_company = tk.StringVar(value=str(data.get('company_name', '') or ''))
        v_web = tk.StringVar(value=str(data.get('website_url', '') or ''))
        v_vat = tk.StringVar(value=str(data.get('vat_id', '') or ''))
        v_phone = tk.StringVar(value=str(data.get('phone', '') or ''))
        v_position = tk.StringVar(value=str(data.get('position_title', '') or ''))
        v_addr = tk.StringVar(value=str(data.get('address', '') or ''))
        v_plz = tk.StringVar(value=str(data.get('plz', '') or ''))
        v_city = tk.StringVar(value=str(data.get('city', '') or ''))
        v_country = tk.StringVar(value=str(data.get('country', '') or 'Deutschland'))
        v_price_list = tk.StringVar(value=str(data.get('price_list', '') or 'Händlerpreise'))
        v_discount_enabled = tk.BooleanVar(value=bool(data.get('discount_enabled')))
        try:
            _dp = float(data.get('discount_percent') or 0)
        except Exception:
            _dp = 0.0
        v_discount_percent = tk.StringVar(value=f"{_dp:g}")
        v_payment_terms = tk.StringVar(value=str(data.get('payment_terms', '') or '30 Tage Netto'))
        v_tags = tk.StringVar(value=str(data.get('tags', '') or ''))

        route_from_data = str(
            data.get('route_id')
            or data.get('route_name')
            or ''
        ).strip() or 'free'
        if route_from_data.lower() in ('none', 'null', 'не назначен', '-', 'nan'):
            route_from_data = 'free'
        v_route = tk.StringVar(value=route_from_data)
        v_transport = tk.StringVar(value=str(data.get('transport_type', '') or 'Eigenes Auto'))
        v_point = tk.StringVar(value=str(data.get('delivery_point', '') or 'Geschäft'))

        routes = []
        route_alias_map = {}
        seen_routes = set()
        for r in getattr(self, 'logistics_routes', []):
            rid = str(r.get('route_id', '')).strip()
            rname = str(r.get('route_name', '')).strip()

            if rid:
                rid_key = rid.casefold()
                if rid_key not in seen_routes:
                    routes.append(rid)
                    seen_routes.add(rid_key)
                if rname:
                    route_alias_map[rname.casefold()] = rid
        if not routes:
            routes = ['free']

        # Гарантируем, что текущее значение маршрута есть в списке и корректно выбрано.
        selected_route = str(v_route.get() or '').strip() or 'free'
        if selected_route not in routes:
            # Если в данных клиента хранится route_name, переводим его в route_id.
            selected_route = route_alias_map.get(selected_route.casefold(), selected_route)
        if selected_route not in routes:
            # Попытка case-insensitive сопоставления
            lower_map = {x.lower(): x for x in routes}
            selected_route = lower_map.get(selected_route.lower(), selected_route)
        if selected_route not in routes:
            routes.append(selected_route)
        v_route.set(selected_route)

        def _field(parent, label, var, width=30):
            ttk.Label(parent, text=label, font=("Segoe UI", 9)).pack(anchor='w', pady=(2, 1))
            ttk.Entry(parent, textvariable=var, width=width, font=("Segoe UI", 10)).pack(fill=tk.X, ipady=1, pady=(0, 4))

        _field(left, "Vorname", v_first_name)
        _field(left, "Nachname", v_last_name)
        _field(left, "Firma", v_company)
        _field(left, "Telefon", v_phone)
        _field(left, "Position", v_position)
        _field(left, "Adresse", v_addr)
        _field(left, "PLZ", v_plz)
        _field(left, "Stadt", v_city)

        _field(right, "E-Mail", v_email)
        _field(right, "URL", v_web)
        _field(right, "USt-IdNr.", v_vat)
        _field(right, "Kundennummer (intern)", v_id)
        _field(right, "Monolith ID", v_monolith)
        ttk.Label(right, text="Land", font=("Segoe UI", 9)).pack(anchor='w', pady=(2, 1))
        ttk.Combobox(right, textvariable=v_country, values=['Deutschland', 'Polen', 'Frankreich', 'Niederlande', 'Belgien'], state='normal', font=("Segoe UI", 10)).pack(fill=tk.X, ipady=1, pady=(0, 4))
        ttk.Label(right, text="Preisliste", font=("Segoe UI", 9)).pack(anchor='w', pady=(2, 1))
        ttk.Combobox(right, textvariable=v_price_list, values=['Händlerpreise', 'Standard', 'B2B'], state='normal', font=("Segoe UI", 10)).pack(fill=tk.X, ipady=1, pady=(0, 4))

        disc_row = ttk.Frame(right)
        disc_row.pack(fill=tk.X, pady=(3, 0))
        ttk.Checkbutton(disc_row, text="Rabatt aktivieren", variable=v_discount_enabled).pack(side=tk.LEFT)
        ttk.Label(disc_row, text="Rabatt, %").pack(side=tk.LEFT, padx=(12, 4))
        ttk.Entry(disc_row, textvariable=v_discount_percent, width=8).pack(side=tk.LEFT)

        ttk.Label(right, text="Zahlungsbedingung", font=("Segoe UI", 9)).pack(anchor='w', pady=(3, 1))
        ttk.Combobox(right, textvariable=v_payment_terms, values=['30 Tage Netto', '14 Tage Netto', 'Vorkasse'], state='normal', font=("Segoe UI", 10)).pack(fill=tk.X, ipady=1, pady=(0, 4))
        _field(right, "Tags (через запятую)", v_tags)
        _field(right, "Kundenname (отображение)", v_name)

        # Rules tab
        rules_top = ttk.Frame(tab_rules_inner, padding=6)
        rules_top.pack(fill=tk.X)
        ttk.Label(rules_top, text="Основной маршрут").grid(row=0, column=0, sticky='w')
        route_combo = ttk.Combobox(rules_top, textvariable=v_route, values=routes, state='readonly', width=32)
        route_combo.grid(row=0, column=1, sticky='w', padx=8)
        # Устанавливаем значение сразу и без отложенных таймеров (без "пустого" состояния).
        vals = [str(v) for v in route_combo.cget('values')]
        if selected_route not in vals:
            vals.append(selected_route)
            route_combo.configure(values=vals)
        route_combo.set(selected_route)
        v_route.set(selected_route)
        route_combo.bind("<<ComboboxSelected>>", lambda _e: v_route.set((route_combo.get() or '').strip()), add="+")

        def _on_rules_tab_show(_event=None):
            try:
                current_tab = tabs.select()
                if current_tab == str(tab_rules):
                    cur = str(v_route.get() or '').strip()
                    if cur:
                        route_combo.set(cur)
            except Exception:
                pass
        tabs.bind("<<NotebookTabChanged>>", _on_rules_tab_show, add="+")

        def _get_route_value():
            val = str(route_combo.get() or v_route.get() or '').strip()
            if not val:
                val = selected_route if selected_route else 'free'
            return val
        ttk.Label(rules_top, text="Транспорт").grid(row=1, column=0, sticky='w', pady=(8, 0))
        ttk.Combobox(rules_top, textvariable=v_transport, values=['Eigenes Auto', 'Spedition', 'Spedition Nürnberg'], state='readonly', width=24).grid(row=1, column=1, sticky='w', padx=8, pady=(8, 0))
        ttk.Label(rules_top, text="Точка доставки").grid(row=2, column=0, sticky='w', pady=(8, 0))
        ttk.Combobox(rules_top, textvariable=v_point, values=['Geschäft', 'Lager'], state='readonly', width=24).grid(row=2, column=1, sticky='w', padx=8, pady=(8, 0))

        rules_box = ttk.LabelFrame(tab_rules_inner, text="Правила маршрута по сумме", padding=6)
        rules_box.pack(fill=tk.BOTH, expand=True, padx=6, pady=(4, 6))
        r_cols = ('min_sum', 'route')
        rules_tree = ttk.Treeview(rules_box, columns=r_cols, show='headings', height=6)
        rules_tree.heading('min_sum', text='Мин. сумма (€)')
        rules_tree.heading('route', text='Маршрут')
        rules_tree.column('min_sum', width=160, anchor='center')
        rules_tree.column('route', width=220, anchor='center')
        rules_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        r_scroll = ttk.Scrollbar(rules_box, orient=tk.VERTICAL, command=rules_tree.yview)
        rules_tree.configure(yscrollcommand=r_scroll.set)
        r_scroll.pack(side=tk.RIGHT, fill=tk.Y)

        try:
            loaded_rules = json.loads(str(data.get('route_rules') or '[]'))
            if isinstance(loaded_rules, list):
                for r in loaded_rules:
                    rules_tree.insert('', tk.END, values=(r.get('limit', 0), r.get('route_id', '')))
        except Exception:
            pass

        rules_btns = ttk.Frame(tab_rules_inner, padding=(6, 0, 6, 6))
        rules_btns.pack(fill=tk.X)

        def _add_rule():
            w = tk.Toplevel(dialog)
            w.title("Добавить правило")
            w.transient(dialog)
            w.grab_set()
            self.center_dialog(w, 320, 170)
            fr = ttk.Frame(w, padding=8)
            fr.pack(fill=tk.BOTH, expand=True)
            ttk.Label(fr, text="Минимальная сумма (€)").pack(anchor='w')
            v_lim = tk.StringVar()
            ttk.Entry(fr, textvariable=v_lim).pack(fill=tk.X, pady=(2, 8))
            ttk.Label(fr, text="Маршрут").pack(anchor='w')
            v_rr = tk.StringVar(value=_get_route_value())
            ttk.Combobox(fr, textvariable=v_rr, values=routes, state='readonly').pack(fill=tk.X, pady=(2, 10))
            def _ok():
                try:
                    lim = float((v_lim.get() or '0').replace(',', '.'))
                except Exception:
                    messagebox.showerror("Ошибка", "Сумма должна быть числом", parent=w)
                    return
                rules_tree.insert('', tk.END, values=(lim, v_rr.get()))
                w.destroy()
            ttk.Button(fr, text="Добавить", command=_ok).pack(fill=tk.X, pady=(4, 0))

        def _del_rule():
            sel = rules_tree.selection()
            if sel:
                rules_tree.delete(sel[0])

        ttk.Button(rules_btns, text="➕ Добавить правило", command=_add_rule).pack(side=tk.LEFT)
        ttk.Button(rules_btns, text="🗑 Удалить правило", command=_del_rule).pack(side=tk.LEFT, padx=8)

        # Bottom actions
        tk.Frame(card, bg="#E3E8F2", height=1).pack(fill=tk.X, padx=0, pady=(0, 8))
        actions = ttk.Frame(card, padding=(10, 0, 10, 8))
        actions.pack(fill=tk.X)

        def save():
            cid = v_id.get().strip()
            cname = v_name.get().strip() or v_company.get().strip()
            if not cid or not cname:
                messagebox.showwarning("Ошибка", "Заполните Kundennummer и имя клиента.", parent=dialog)
                return

            new_rules = []
            for iid in rules_tree.get_children():
                vals = rules_tree.item(iid, 'values')
                try:
                    limit = float(vals[0])
                except Exception:
                    continue
                route_id = str(vals[1]).strip()
                if route_id:
                    new_rules.append({'limit': limit, 'route_id': route_id})

            try:
                discount_percent_val = float((v_discount_percent.get() or '0').replace(',', '.'))
            except Exception:
                discount_percent_val = 0.0

            payload = {
                'client_id': cid,
                'monolith_client_id': v_monolith.get().strip(),
                'client_name': cname,
                'email': v_email.get().strip(),
                'first_name': v_first_name.get().strip(),
                'last_name': v_last_name.get().strip(),
                'company_name': v_company.get().strip(),
                'website_url': v_web.get().strip(),
                'vat_id': v_vat.get().strip(),
                'phone': v_phone.get().strip(),
                'position_title': v_position.get().strip(),
                'address': v_addr.get().strip(),
                'plz': v_plz.get().strip(),
                'city': v_city.get().strip(),
                'country': v_country.get().strip(),
                'price_list': v_price_list.get().strip(),
                'discount_enabled': 1 if v_discount_enabled.get() else 0,
                'discount_percent': discount_percent_val,
                'payment_terms': v_payment_terms.get().strip(),
                'tags': v_tags.get().strip(),
                'route_id': _get_route_value(),
                'transport_type': v_transport.get().strip() or 'Eigenes Auto',
                'delivery_point': v_point.get().strip() or 'Geschäft',
                'route_rules': json.dumps(new_rules, ensure_ascii=False),
            }

            found = False
            for i, c in enumerate(self.logistics_clients):
                if str(c.get('client_id')) == cid:
                    self.logistics_clients[i].update(payload)
                    found = True
                    break
            if not found:
                self.logistics_clients.append(payload)

            self.logistics_filter_clients()
            self.send_ws_message({'type': 'save_client_full', 'client_data': payload})
            dialog.destroy()

        tk.Button(
            actions, text="Speichern", command=save,
            font=("Segoe UI", 10, "bold"), bg="#3B82F6", fg="white",
            activebackground="#2563EB", activeforeground="white",
            relief=tk.FLAT, bd=0, padx=16, pady=6
        ).pack(side=tk.LEFT)

    def show_order_context_menu(self, event):
        """Показать кастомное меню при клике правой кнопкой (с поддержкой мультивыбора)."""
        # Определяем строку под курсором
        item = self.admin_orders_tree.identify_row(event.y)
        if not item:
            current_selection = self.admin_orders_tree.selection()
            if current_selection:
                item = current_selection[0]

        if item:
            current_selection = self.admin_orders_tree.selection()

            # ВАЖНО: Если кликнули на уже выделенный элемент - сохраняем множественное выделение
            # Если кликнули на новый элемент - выделяем только его
            if item not in current_selection:
                self.admin_orders_tree.selection_set(item)

            # Устанавливаем фокус на кликнутый элемент
            self.admin_orders_tree.focus(item)

            # Снимаем жирный с API заказов при открытии контекстного меню
            order_ids = self.get_all_selected_order_ids(self.admin_orders_tree)
            for oid in order_ids:
                if oid.startswith('MO-'):
                    o = self.orders.get(oid, {})
                    d = o.get('data', o)
                    if d.get('is_api_new'):
                        self.send_ws_message({'type': 'mark_api_order_seen', 'order_id': oid})

            # Показываем кастомное меню
            self._show_order_context_popup(event.x_root, event.y_root)
            return "break"

    def _show_order_context_popup(self, x_root, y_root):
        """Кастомное контекстное меню заказов."""
        menu_items = [
            ("➕", "Добавить клиента в базу логистики", self.add_client_from_order, True),
            ("☑", "Отметить как напечатано", self.admin_mark_orders_printed, False),
            ("✕", "Снять отметку печати", self.admin_unmark_orders_printed, False),
            None,
            ("🗓", "Изменить дату доставки", self.ask_change_delivery_date, False),
            ("🚚", "Сменить маршрут", self.ask_change_route_admin, False),
            None,
            ("↪", "Перенести на след. маршрут", self.admin_move_order_next_route, False),
        ]
        self._show_styled_context_popup(x_root, y_root, menu_items, min_width=250)

    def _show_warehouse_context_popup(self, x_root, y_root):
        """Кастомное контекстное меню склада."""
        menu_items = [
            ("☑", "Отметить собрано", self.warehouse_mark_orders_collected, True),
            ("✕", "Снять отметку собрано", self.warehouse_unmark_orders_collected, False),
            None,
            ("🚚", "Сменить маршрут", self.ask_change_route_warehouse, False),
        ]
        self._show_styled_context_popup(x_root, y_root, menu_items, min_width=235)

    def _is_widget_inside_popup(self, widget, popup):
        while widget is not None:
            if widget == popup:
                return True
            widget = getattr(widget, "master", None)
        return False

    def _on_global_click_styled_popup(self, event):
        popup = getattr(self, "styled_context_popup", None)
        if not popup or not popup.winfo_exists():
            return
        if not self._is_widget_inside_popup(event.widget, popup):
            self._hide_styled_context_popup()

    def _show_styled_context_popup(self, x_root, y_root, menu_items, min_width=220):
        """Единый стиль popup-меню для разделов 'Все заказы' и 'Склад'."""
        self._hide_styled_context_popup()
        c = self.colors

        popup = tk.Toplevel(self)
        popup.withdraw()
        popup.overrideredirect(True)
        popup.transient(self)
        popup.configure(bg=c["bg_main"])
        popup.attributes("-topmost", True)
        popup._skip_auto_layout = True
        popup.lift(self)

        menu_card = ModernCard(
            popup,
            bg=c["bg_card"],
            parent_bg=c["bg_main"],
            radius=18,
            border=c["border"],
            padding=5
        )
        menu_card.pack(fill=tk.BOTH, expand=True)
        body = menu_card.get_inner()

        def on_enter(row, is_primary):
            color = "#DCE8FF" if is_primary else "#F3F6FD"
            for widget in (row, *row._hover_widgets):
                widget.configure(bg=color)

        def on_leave(row, is_primary):
            color = "#E8F0FF" if is_primary else c["bg_card"]
            for widget in (row, *row._hover_widgets):
                widget.configure(bg=color)

        total_inner_h = 0
        for item in menu_items:
            if item is None:
                tk.Frame(body, bg=c["border"], height=1).pack(fill=tk.X, pady=4, padx=5)
                total_inner_h += 1 + 8  # line + pady(top+bottom)
                continue

            icon, title, action, is_primary = item
            row_bg = "#E8F0FF" if is_primary else c["bg_card"]
            row_h = 31 if is_primary else 29
            row = tk.Frame(body, bg=row_bg, height=row_h)
            row.pack(fill=tk.X, pady=1)
            row.pack_propagate(False)
            total_inner_h += row_h + 2  # pady(top+bottom)

            icon_lbl = tk.Label(
                row, text=icon, bg=row_bg, fg=c["accent"] if is_primary else c["text_light"],
                font=("Segoe UI", 12 if is_primary else 11)
            )
            icon_lbl.pack(side=tk.LEFT, padx=(7, 6))

            text_lbl = tk.Label(
                row, text=title, bg=row_bg, fg=c["text_main"],
                font=("Segoe UI", 8 if is_primary else 8, "bold" if is_primary else "normal"),
                anchor="w"
            )
            text_lbl.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=(0, 6))

            row._hover_widgets = (icon_lbl, text_lbl)

            def run_action(cb=action):
                self._hide_styled_context_popup()
                self.after(10, cb)

            for w in (row, icon_lbl, text_lbl):
                w.bind("<Enter>", lambda e, r=row, p=is_primary: on_enter(r, p))
                w.bind("<Leave>", lambda e, r=row, p=is_primary: on_leave(r, p))
                w.bind("<Button-1>", lambda e, fn=run_action: fn())

        popup.update_idletasks()
        inner_pad = int(getattr(menu_card, "card_padding", 0))
        w = max(min_width, popup.winfo_reqwidth())
        h = max(24, total_inner_h + inner_pad * 2 + 2)
        vs_x, vs_y, screen_w, screen_h = self._get_virtual_screen_bounds()
        x = min(max(x_root + 2, vs_x + 8), vs_x + screen_w - w - 8)
        y = min(max(y_root + 2, vs_y + 8), vs_y + screen_h - h - 8)
        popup.geometry(f"{w}x{h}+{x}+{y}")
        popup.deiconify()
        popup.lift(self)

        self.styled_context_popup = popup
        self._styled_popup_click_bind = self.bind("<Button-1>", self._on_global_click_styled_popup, add="+")
        self._styled_popup_escape_bind = self.bind("<Escape>", lambda e: self._hide_styled_context_popup(), add="+")

    def _hide_order_context_popup(self):
        self._hide_styled_context_popup()

    def _hide_styled_context_popup(self):
        popup = getattr(self, "styled_context_popup", None)
        if popup and popup.winfo_exists():
            popup.destroy()
        self.styled_context_popup = None

        if getattr(self, "_styled_popup_click_bind", None):
            try:
                self.unbind("<Button-1>", self._styled_popup_click_bind)
            except Exception:
                pass
            self._styled_popup_click_bind = None

        if getattr(self, "_styled_popup_escape_bind", None):
            try:
                self.unbind("<Escape>", self._styled_popup_escape_bind)
            except Exception:
                pass
            self._styled_popup_escape_bind = None

    def ask_change_delivery_date(self):
        """МАССОВАЯ смена даты доставки"""
        try:
            # 1. Получаем список ID
            order_ids = self.get_all_selected_order_ids(self.admin_orders_tree)
            
            if not order_ids:
                messagebox.showwarning("Ошибка", "Ничего не выбрано")
                return

            count = len(order_ids)
            
            # Берем дату первого заказа как пример
            first_order = self.orders.get(order_ids[0])
            first_data = first_order.get('data', first_order)
            current_date_str = first_data.get('delivery_date', '')

            # Диалог
            dialog = tk.Toplevel(self)
            dialog.title(f"Смена даты для {count} заказов")
            dialog.transient(self)
            dialog.grab_set()
            self.center_dialog(dialog, 400, 250)

            ttk.Label(dialog, text=f"Выбрано заказов: {count}", font=("Arial", 11, "bold")).pack(pady=10)
            ttk.Label(dialog, text="Новая дата доставки:").pack()

            try:
                init_date = datetime.strptime(current_date_str, "%Y-%m-%d").date()
            except:
                init_date = datetime.now().date()

            date_picker = DateEntry(dialog, width=20, date_pattern='yyyy-mm-dd', 
                                   year=init_date.year, month=init_date.month, day=init_date.day)
            date_picker.pack(pady=10)

            def save_bulk():
                new_date = date_picker.get_date().strftime('%Y-%m-%d')
                
                if not messagebox.askyesno("Подтверждение", f"Установить дату {new_date} для {count} заказов?"):
                    return

                for oid in order_ids:
                    # Отправляем на сервер
                    self.send_ws_message({
                        'type': 'update_order_date',
                        'order_id': oid,
                        'delivery_date': new_date
                    })
                    # Оптимистичное обновление локально (для скорости интерфейса)
                    if oid in self.orders:
                        target = self.orders[oid].get('data', self.orders[oid])
                        target['delivery_date'] = new_date

                # Обновляем таблицу
                self.admin_refresh_orders()
                dialog.destroy()
                messagebox.showinfo("Готово", "Даты обновлены!")

            ttk.Button(dialog, text="💾 Применить ко всем", command=save_bulk).pack(pady=10, fill=tk.X, padx=20)

        except Exception as e:
            messagebox.showerror("Ошибка", f"{e}")

    def recalc_logistics_single(self):
        """Пересчитать логистику для одного заказа (Авто режим)"""
        selection = self.admin_orders_tree.selection()
        if not selection: return
        
        order_id = self.get_order_id_from_selection(self.admin_orders_tree, selection)
        if not order_id: return
        
        if messagebox.askyesno("Пересчет", f"Сбросить ручную дату и пересчитать логистику для {order_id}?"):
            self.send_ws_message({
                'type': 'recalc_order_logistics',
                'order_id': order_id
            })

    def export_plan_smart(self):
        """Умный экспорт - выбирает функцию в зависимости от режима (дневной/недельный)"""
        mode = self.plan_mode_var.get()

        if mode == 'weekly':
            self.export_weekly_plan()
        else:
            self.export_production_plan()

    def export_production_plan(self):
        """
        Экспорт плана в Excel (ФИНАЛЬНАЯ ВЕРСИЯ):
        1. Берет данные с сервера (безопасно, без ошибок индексов).
        2. Распределяет по вкладкам согласно категории из Базы Тортов (Biskuit, Medowik...).
        3. Применяет новый синий дизайн.
        """
        
        # 1. Проверка наличия данных
        if not hasattr(self, 'current_plan_data') or not self.current_plan_data.get('plan'):
            messagebox.showwarning("Экспорт", "Нет данных для экспорта. Сначала рассчитайте план.")
            return

        date_str = str(self.plan_date_entry.get_date())
        filename = filedialog.asksaveasfilename(
            defaultextension=".xlsx",
            filetypes=[("Excel файл", "*.xlsx")],
            initialfile=f"Produktionsplan_{date_str}.xlsx"
        )
        
        if not filename: return

        try:
            import pandas as pd
            from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
            
            # --- СБОР ДАННЫХ ---
            # Мы берем данные из self.current_plan_data, так как в таблице (Treeview) 
            # некоторых колонок может не быть визуально, что вызывало ошибку.
            plan_list = self.current_plan_data.get('plan', [])
            
            all_data = []
            dough_map = {}

            for item in plan_list:
                # 1. Получаем категорию именно так, как она записана в базе
                category = item.get('category', '')
                if not category or category == 'None': 
                    category = 'Sonstiges' # Если совсем пусто, то в прочее
                
                # 2. Артикул и Название
                raw_art = str(item.get('article_nr', '')).strip()
                art_nr = raw_art.zfill(5) if raw_art.isdigit() else raw_art
                name = item.get('name', '')
                
                # 3. План (количество)
                try: plan = int(float(item.get('quantity', 0)))
                except: plan = 0
                
                # 4. Тесто и Замесы
                dough_name = item.get('dough_name', '-')
                try: batches = float(item.get('batches', 0))
                except: batches = 0.0

                # Добавляем в список только то, что нужно производить
                if plan > 0:
                    all_data.append({
                        'Цех': category,  # Это будет названием вкладки
                        'Артикул': art_nr,
                        'Название': name,
                        'План (шт)': plan,
                        'Замесов': batches,
                        'Тесто': dough_name
                    })

                # Считаем сводку по тесту
                if dough_name != "-" and batches > 0:
                    dough_map[dough_name] = dough_map.get(dough_name, 0) + batches

            # Создаем DataFrame
            df_all = pd.DataFrame(all_data)

            if df_all.empty:
                messagebox.showinfo("Экспорт", "План пуст.")
                return

            # Сортировка по Артикулу (по возрастанию)
            df_all = df_all.sort_values(by='Артикул')

            # --- ФУНКЦИЯ ДИЗАЙНА ---
            def format_sheet(ws, num_rows, col_widths):
                """Красит таблицу: Синяя шапка, границы, зебра"""
                # Стили
                header_fill = PatternFill(start_color="4472C4", end_color="4472C4", fill_type="solid")
                header_font = Font(bold=True, size=11, color="FFFFFF")
                thin_border = Border(left=Side(style='thin'), right=Side(style='thin'), top=Side(style='thin'), bottom=Side(style='thin'))
                zebra_light = PatternFill(start_color="FFFFFF", end_color="FFFFFF", fill_type="solid")
                zebra_dark = PatternFill(start_color="E8F4FD", end_color="E8F4FD", fill_type="solid")
                center = Alignment(horizontal='center', vertical='center')

                # Шапка
                for cell in ws[1]:
                    cell.fill = header_fill
                    cell.font = header_font
                    cell.alignment = center
                    cell.border = thin_border

                # Данные
                for row_idx in range(2, num_rows + 2):
                    fill = zebra_light if (row_idx % 2 == 0) else zebra_dark
                    for cell in ws[row_idx]:
                        cell.fill = fill
                        cell.border = thin_border
                        cell.alignment = center

                # Ширина колонок
                for col, width in col_widths.items():
                    ws.column_dimensions[col].width = width

                # Настройка печати
                ws.freeze_panes = 'A2'
                ws.page_setup.orientation = 'landscape'
                ws.page_setup.fitToWidth = 1

            # --- ЗАПИСЬ ФАЙЛА ---
            with pd.ExcelWriter(filename, engine='openpyxl') as writer:
                
                # 1. ОБЩИЙ ПЛАН
                df_all.to_excel(writer, sheet_name='ОБЩИЙ ПЛАН', index=False)
                ws = writer.sheets['ОБЩИЙ ПЛАН']
                format_sheet(ws, len(df_all), {'A': 15, 'B': 12, 'C': 45, 'D': 10, 'E': 10, 'F': 25})
                # Названия влево
                for row in range(2, len(df_all) + 2):
                    ws.cell(row, 3).alignment = Alignment(horizontal='left')

                # 2. ЗАМЕСЫ ТЕСТА
                dough_list = [{'Тип Теста': k, 'Всего Партий': round(v, 1)} for k,v in sorted(dough_map.items())]
                df_dough = pd.DataFrame(dough_list)
                if not df_dough.empty:
                    df_dough.to_excel(writer, sheet_name='ЗАМЕСЫ', index=False)
                    ws_dough = writer.sheets['ЗАМЕСЫ']
                    format_sheet(ws_dough, len(df_dough), {'A': 35, 'B': 15})
                    for row in range(2, len(df_dough) + 2):
                        ws_dough.cell(row, 1).alignment = Alignment(horizontal='left')

                # 3. ВКЛАДКИ ПО КАТЕГОРИЯМ (Biskuit, Medowik, etc.)
                # Получаем уникальные категории из данных
                unique_cats = sorted(df_all['Цех'].unique())
                
                for cat in unique_cats:
                    # Фильтруем данные только для этой категории
                    cat_df = df_all[df_all['Цех'] == cat].copy()
                    
                    if cat_df.empty: continue

                    # Убираем колонку "Цех", так как мы уже внутри вкладки этой категории
                    cat_df = cat_df.drop(columns=['Цех'])

                    # Имя вкладки (очищаем от недопустимых символов)
                    sheet_name = str(cat)[:30].replace('/', ' ').replace('*', '').replace(':', '').replace('?', '')
                    if not sheet_name: sheet_name = "Other"

                    # Записываем
                    cat_df.to_excel(writer, sheet_name=sheet_name, index=False)

                    # Дизайн
                    ws = writer.sheets[sheet_name]
                    # Колонки сдвинулись: A=Артикул, B=Название...
                    format_sheet(ws, len(cat_df), {'A': 12, 'B': 45, 'C': 10, 'D': 10, 'E': 25})
                    
                    # Названия влево
                    for row in range(2, len(cat_df) + 2):
                        ws.cell(row, 2).alignment = Alignment(horizontal='left')

            messagebox.showinfo("Успех", f"Файл сохранен!\n\nСозданы вкладки:\n" + ", ".join(unique_cats))
            try: os.startfile(filename)
            except: pass
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            messagebox.showerror("Ошибка", f"Сбой экспорта: {e}")

    def show_plan_context_menu(self, event):
        """Показать контекстное меню в плане производства"""
        # 1. Определяем строку под курсором
        item_id = self.plan_tree.identify_row(event.y)
        
        if item_id:
            # 2. Выделяем эту строку (чтобы юзер видел, куда нажал)
            self.plan_tree.selection_set(item_id)
            self.plan_tree.focus(item_id)
            
            # 3. Проверяем: это Заказ (ребенок) или Торт (родитель)?
            parent_id = self.plan_tree.parent(item_id)
            
            if parent_id:
                # Если есть родитель -> это Заказ. Показываем меню переноса.
                self.plan_context_menu.post(event.x_root, event.y_root)
            else:
                # Если родителя нет -> это Торт. Меню не показываем (или можно показать другое).
                pass

    def move_plan_order(self):
        """Перенос заказа из плана производства - запрашиваем следующую дату"""
        sel = self.plan_tree.selection()
        if not sel: return

        # Мы спрятали ID заказа в первой колонке (индекс 0) в fill_plan_breakdown
        order_id = self.plan_tree.item(sel[0])['values'][0]

        if not order_id: return

        # Запрашиваем у сервера следующую доступную дату
        self.send_ws_message({
            'type': 'get_next_delivery_date',
            'order_id': order_id
        })        

    def export_weekly_plan(self):
        """Экспорт недельного плана в Excel"""
        # Проверить, есть ли данные
        if not hasattr(self, 'weekly_tree') or not self.weekly_tree.get_children():
            messagebox.showwarning("Экспорт", "Нет данных для экспорта. Сначала рассчитайте недельный план.")
            return

        # Собрать данные из таблицы
        data = []
        for item in self.weekly_tree.get_children():
            values = self.weekly_tree.item(item)['values']
            data.append({
                'Art.Nr.': values[0],
                'Artikelname': values[1],
                'Prognose': values[2],      # ИСПРАВЛЕНО: Добавлена пропущенная колонка Прогноз
                'Rest KW': values[3],       # ИСПРАВЛЕНО: Сдвинуто с 2 на 3
                'Vorb. KW': values[4],      # ИСПРАВЛЕНО: Сдвинуто с 3 на 4
                'Mo': values[5],            # ИСПРАВЛЕНО: Сдвинуто с 4 на 5
                'Di': values[6],            # ИСПРАВЛЕНО: Сдвинуто с 5 на 6
                'Mi': values[7],            # ИСПРАВЛЕНО: Сдвинуто с 6 на 7
                'Do': values[8],            # ИСПРАВЛЕНО: Сдвинуто с 7 на 8
                'Fr': values[9],            # ИСПРАВЛЕНО: Сдвинуто с 8 на 9
                'Sa': values[10],           # ИСПРАВЛЕНО: Сдвинуто с 9 на 10
                'So': values[11],           # ИСПРАВЛЕНО: Сдвинуто с 10 на 11
                'Ges. KW': values[12],      # ИСПРАВЛЕНО: Сдвинуто с 11 на 12
                'Woche': values[13]         # ИСПРАВЛЕНО: Сдвинуто с 12 на 13
            })

        if not data:
            messagebox.showwarning("Экспорт", "Нет данных для экспорта")
            return

        # Диалог сохранения
        from tkinter import filedialog
        week_number = data[0]['Woche']
        default_filename = f"Wochenplan_KW{week_number}.xlsx"
        filepath = filedialog.asksaveasfilename(
            defaultextension=".xlsx",
            filetypes=[("Excel files", "*.xlsx"), ("All files", "*.*")],
            initialfile=default_filename
        )

        if not filepath:
            return

        try:
            import pandas as pd
            from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
            from openpyxl.utils import get_column_letter

            # Создать DataFrame
            df = pd.DataFrame(data)

            # Экспорт с форматированием
            with pd.ExcelWriter(filepath, engine='openpyxl') as writer:
                # Основной лист
                df.to_excel(writer, sheet_name='Wochenplan', index=False)

                # Получить workbook и worksheet для форматирования
                workbook = writer.book
                worksheet = writer.sheets['Wochenplan']

                # Стиль заголовков
                header_fill = PatternFill(start_color="4472C4", end_color="4472C4", fill_type="solid")
                header_font = Font(color="FFFFFF", bold=True, size=11)
                header_alignment = Alignment(horizontal='center', vertical='center')

                # Зебра - чередующиеся цвета строк
                zebra_light = PatternFill(start_color="FFFFFF", end_color="FFFFFF", fill_type="solid")
                zebra_dark = PatternFill(start_color="E8F4FD", end_color="E8F4FD", fill_type="solid")

                # Границы
                thin_border = Border(
                    left=Side(style='thin'),
                    right=Side(style='thin'),
                    top=Side(style='thin'),
                    bottom=Side(style='thin')
                )

                # Форматирование заголовков
                for cell in worksheet[1]:
                    cell.fill = header_fill
                    cell.font = header_font
                    cell.alignment = header_alignment
                    cell.border = thin_border

                # Форматирование данных с зеброй
                for row_idx, row in enumerate(worksheet.iter_rows(min_row=2, max_row=len(df)+1)):
                    row_fill = zebra_light if row_idx % 2 == 0 else zebra_dark
                    for cell in row:
                        cell.border = thin_border
                        cell.alignment = Alignment(horizontal='center', vertical='center')
                        cell.fill = row_fill

                # Выравнивание названий по левому краю
                for row in range(2, len(df) + 2):
                    worksheet.cell(row, 2).alignment = Alignment(horizontal='left', vertical='center')

                # Ширина колонок (ИСПРАВЛЕНО: добавлена колонка Prognose)
                column_widths = {
                    'A': 10,  # Art.Nr.
                    'B': 30,  # Artikelname
                    'C': 10,  # Prognose (ДОБАВЛЕНО)
                    'D': 10,  # Rest KW (было C)
                    'E': 10,  # Vorb. KW (было D)
                    'F': 8,   # Mo (было E)
                    'G': 8,   # Di (было F)
                    'H': 8,   # Mi (было G)
                    'I': 8,   # Do (было H)
                    'J': 8,   # Fr (было I)
                    'K': 8,   # Sa (было J)
                    'L': 8,   # So (было K)
                    'M': 10,  # Ges. KW (было L)
                    'N': 8    # Woche (было M)
                }

                for col, width in column_widths.items():
                    worksheet.column_dimensions[col].width = width

                # Добавить итоговую строку
                totals_row = len(df) + 2
                worksheet.cell(totals_row, 1, "ИТОГО:")
                worksheet.cell(totals_row, 1).font = Font(bold=True, size=11)
                worksheet.cell(totals_row, 1).alignment = Alignment(horizontal='right')
                worksheet.cell(totals_row, 1).fill = PatternFill(start_color="D3D3D3", end_color="D3D3D3", fill_type="solid")

                # Суммы по дням (колонки F-L: Mo-So) - ИСПРАВЛЕНО: сдвинуто на одну колонку вправо
                day_columns = ['F', 'G', 'H', 'I', 'J', 'K', 'L']  # Было E-K, теперь F-L
                for col_letter in day_columns:
                    formula = f"=SUM({col_letter}2:{col_letter}{len(df)+1})"
                    cell = worksheet[f"{col_letter}{totals_row}"]
                    cell.value = formula
                    cell.font = Font(bold=True)
                    cell.alignment = Alignment(horizontal='center')
                    cell.border = thin_border
                    cell.fill = PatternFill(start_color="D3D3D3", end_color="D3D3D3", fill_type="solid")

                # Общая сумма (колонка M: Ges. KW) - ИСПРАВЛЕНО: было L, теперь M
                formula = f"=SUM(M2:M{len(df)+1})"
                cell = worksheet[f"M{totals_row}"]
                cell.value = formula
                cell.font = Font(bold=True, size=11)
                cell.alignment = Alignment(horizontal='center')
                cell.border = thin_border
                cell.fill = PatternFill(start_color="FFD700", end_color="FFD700", fill_type="solid")

                # Заморозить первую строку
                worksheet.freeze_panes = 'A2'

                # Настройка печати - помещается на одну страницу по ширине
                worksheet.page_setup.fitToWidth = 1
                worksheet.page_setup.fitToHeight = 0
                worksheet.page_setup.orientation = 'landscape'

                # Добавить информационный лист
                info_sheet = workbook.create_sheet('Info')
                info_sheet['A1'] = f"Wochenplan KW {week_number}"
                info_sheet['A1'].font = Font(bold=True, size=14)
                info_sheet['A3'] = "Generiert mit Claude Code"
                info_sheet['A3'].font = Font(italic=True, size=10)

                from datetime import datetime
                info_sheet['A5'] = f"Exportiert am: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
                info_sheet.column_dimensions['A'].width = 40

            messagebox.showinfo("Экспорт", f"Файл сохранён:\n{filepath}")

            # Открыть файл
            import os
            os.startfile(filepath)

        except ImportError as e:
            messagebox.showerror("Ошибка", f"Не установлены необходимые библиотеки:\n{str(e)}\n\nУстановите: pip install pandas openpyxl")
        except Exception as e:
            import traceback
            traceback.print_exc()
            messagebox.showerror("Ошибка", f"Не удалось экспортировать:\n{str(e)}")

    def on_login(self):
        """Обработка входа"""
        print("Login button clicked")
        username = self.username_entry.get().strip()
        password = self.password_entry.get()

        if not username or not password:
            self.error_label.config(text="Enter username and password")
            return

        print(f"Authenticating user: {username}")
        self.user_data = {
            'username': username,
            'password': password
        }

        # Запускаем WebSocket для авторизации
        self.ws_thread = threading.Thread(target=self.run_websocket, daemon=True)
        self.ws_thread.start()

        self.error_label.config(text="Connecting to server...")

    @staticmethod
    def _parse_version_tuple(value: str) -> tuple:
        parts = re.findall(r"\d+", str(value or ""))
        if not parts:
            return (0,)
        return tuple(int(x) for x in parts[:6])

    def _is_version_newer(self, candidate: str, current: str) -> bool:
        return self._parse_version_tuple(candidate) > self._parse_version_tuple(current)

    def _update_client_version_caption(self):
        if not hasattr(self, 'client_version_label'):
            return
        base_text = f"Версия {CLIENT_VERSION}"
        if self.server_client_version and str(self.server_client_version).strip() and str(self.server_client_version) != str(CLIENT_VERSION):
            base_text += f" | сервер {self.server_client_version}"
        self.client_version_label.config(text=base_text)

    def on_authentication_success(self, user_info):
        """Вызывается после успешной авторизации на сервере"""
        print(f"Authentication success! Role: {user_info['role']}, Permissions: {user_info.get('permissions', '')}")

        # Если уже авторизованы - это реконнект, не пересоздаем интерфейс
        if self.authenticated:
            print("[AUTH] Реконнект - интерфейс уже создан, пропускаем")
            return

        # Сохраняем пароль перед перезаписью user_data
        saved_password = self.user_data.get('password', '') if self.user_data else ''
        self.user_data = user_info  # Сохраняем данные пользователя
        self.user_data['password'] = saved_password  # Восстанавливаем пароль для реконнекта
        self.current_user_id = user_info.get('user_id')
        self.user_role = user_info['role']
        self.warehouse_id = user_info.get('warehouse_id')
        self.user_permissions = user_info.get('permissions', '') or ''
        self.authenticated = True

        # Определяем эффективную роль на основе прав
        perms_list = [p.strip() for p in self.user_permissions.split(',') if p.strip()]

        # Инициализируем принтер в фоне, чтобы вход не зависал при недоступном SMB (домашняя сеть).
        # ВАЖНО: Админ тоже может печатать коробки.
        if 'warehouse' in perms_list or self.user_role == 'warehouse' or 'admin' in perms_list or self.user_role == 'admin':
            self._start_printer_init_async()
        else:
            print(f"[INIT] ℹ️ Принтер не инициализирован (роль: {self.user_role}, права: {self.user_permissions})")

        # Изменяем размер окна и показываем главный интерфейс
        self.geometry("1600x900")
        try:
            self.state('zoomed')  # Максимизируем окно
        except:
            pass

        self.after(0, self.create_interface)
        self.after(0, self.update_connection_status, True)

    def _start_printer_init_async(self):
        """Неблокирующая инициализация принтера."""
        if self.printer is not None:
            return
        if self._printer_init_started:
            return
        self._printer_init_started = True
        self._printer_init_failed = False

        def _worker():
            try:
                printer = LabelPrinter()
                self.printer = printer
                print("[INIT] ✅ Принтер инициализирован в фоне")
            except Exception as e:
                self._printer_init_failed = True
                print(f"[INIT] ⚠️ Фоновая инициализация принтера не удалась: {e}")
            finally:
                self._printer_init_started = False

        threading.Thread(target=_worker, daemon=True).start()

    def show_current_stocks_dialog(self):
        """Окно просмотра истории запасов (Админ)"""
        dialog = tk.Toplevel(self)
        dialog.title("История запасов (Отчеты склада)")
        self.center_dialog(dialog, 800, 600)
        
        # Панель управления
        top_frame = ttk.Frame(dialog)
        top_frame.pack(fill=tk.X, padx=10, pady=10)
        
        ttk.Label(top_frame, text="Дата отчета:").pack(side=tk.LEFT)
        
        # Календарь
        from tkcalendar import DateEntry
        stock_date = DateEntry(top_frame, width=12, date_pattern='yyyy-mm-dd')
        
        # По умолчанию ставим ВЧЕРАШНЮЮ дату относительно Плана
        # (Так как План на сегодня строится на основе Вчерашнего отчета)
        current_plan_date = self.plan_date_entry.get_date()
        stock_date.set_date(current_plan_date - timedelta(days=1))
        stock_date.pack(side=tk.LEFT, padx=5)
        
        # Таблица
        tree = ttk.Treeview(dialog, columns=('Арт', 'Название', 'Кол-во', 'Кто внес', 'Время'), show='headings')
        tree.heading('Арт', text='Арт')
        tree.heading('Название', text='Название')
        tree.heading('Кол-во', text='Кол-во')
        tree.heading('Кто внес', text='Кто внес')
        tree.heading('Время', text='Время')
        
        tree.column('Арт', width=80)
        tree.column('Название', width=350)
        tree.column('Кол-во', width=100, anchor='center')
        tree.column('Кто внес', width=100, anchor='center')
        tree.column('Время', width=80, anchor='center')
        
        tree.pack(fill=tk.BOTH, expand=True, padx=10, pady=5)
        
        # Ссылка для обновления из handle_ws_message
        self.current_stock_dialog_tree = tree 
        
        # Функция запроса
        def load_stocks(event=None):
            date_str = stock_date.get_date().strftime('%Y-%m-%d')
            self.current_stock_dialog_date = date_str
            # Очищаем таблицу перед загрузкой
            tree.delete(*tree.get_children())
            # Шлем запрос. Ответ придет в handle_ws_message -> update_report_ui
            self.send_ws_message({'type': 'get_daily_stock_report', 'date': date_str})
            
        ttk.Button(top_frame, text="Загрузить", command=load_stocks).pack(side=tk.LEFT, padx=5)
        stock_date.bind('<<DateEntrySelected>>', load_stocks)
        
        # Автозагрузка
        load_stocks()

