    # === SYNC STATUS METHODS ===

    def _set_update_action_button(self, text: str, mode: str = "check"):
        btn = getattr(self, 'client_update_action_btn', None)
        if btn is None:
            return
        btn.configure_text(text)
        if mode == "check":
            btn.command = self.check_client_updates
            btn.configure_style('outline')
            btn.border_color = self.colors.get("accent", "#2563EB")
            btn.fg_color = self.colors.get("accent", "#2563EB")
            btn.hover_color = "#EEF4FF"
        elif mode == "update":
            btn.command = self.trigger_client_update
            btn.configure_style('warning')
            btn.hover_color = "#D97706"
        elif mode == "busy":
            btn.command = None
            btn.configure_style('secondary')
            btn.hover_color = "#D1D5DB"
        else:
            btn.command = self.check_client_updates
            btn.configure_style('outline')
        btn._draw_button()

    def _refresh_client_update_ui(self):
        btn = getattr(self, 'client_update_action_btn', None)
        if btn is None:
            self._update_client_version_caption()
            return
        has_update = bool(self.client_update_available or self.client_update_required)
        if self.client_update_check_in_progress:
            self._set_update_action_button("Проверка...", mode="busy")
        elif self.client_update_in_progress:
            self._set_update_action_button("Обновление...", mode="busy")
        elif has_update:
            self._set_update_action_button("Обновить и перезапустить", mode="update")
        else:
            self._set_update_action_button("Проверить обновления", mode="check")
        self._update_client_version_caption()

    def check_client_updates(self):
        if self.client_update_in_progress or self.client_update_check_in_progress:
            return
        self.client_update_check_in_progress = True
        self.client_update_available = False
        self.client_update_required = False
        self.client_update_message = "Проверяю обновления..."
        self._refresh_client_update_ui()
        sent = self.send_ws_message({
            'type': 'check_client_update',
            'client_version': CLIENT_VERSION
        })
        if not sent:
            self.client_update_check_in_progress = False
            self.client_update_message = "Нет связи с сервером для проверки обновления."
            self._refresh_client_update_ui()

    def _resolve_launcher_cmd(self) -> Path:
        local = Path(os.getenv("LOCALAPPDATA", str(Path.home()))) / "WISO_GoLabel" / "launch.cmd"
        if local.exists():
            return local
        try:
            candidate = Path(__file__).resolve().parent.parent / "launch.cmd"
            if candidate.exists():
                return candidate
        except Exception:
            pass
        return local

    def _iter_client_updater_candidates(self):
        seen = set()
        raw_candidates = [
            WISO_CLIENT_UPDATER_BAT,
            r"\\server01\DATA\WISO_GOLABEL\UPDATE_WISO_CLIENT.bat",
        ]
        try:
            raw_candidates.append(str(Path(__file__).resolve().parent.parent / "UPDATE_WISO_CLIENT.bat"))
        except Exception:
            pass

        for raw in raw_candidates:
            value = str(raw or "").strip()
            if not value:
                continue
            key = value.lower()
            if key in seen:
                continue
            seen.add(key)
            yield Path(value)

    def _resolve_client_updater_bat(self):
        for candidate in self._iter_client_updater_candidates():
            try:
                if candidate.exists() and candidate.is_file():
                    return candidate
            except Exception:
                continue
        return None

    def _launch_external_client_updater(self):
        updater_bat = self._resolve_client_updater_bat()
        if updater_bat is None:
            return False, "Не найден UPDATE_WISO_CLIENT.bat"
        try:
            if hasattr(os, "startfile"):
                os.startfile(str(updater_bat))
            else:
                subprocess.Popen(["cmd", "/c", str(updater_bat)])
            return True, str(updater_bat)
        except Exception as e:
            return False, str(e)

    def _auto_trigger_client_update(self):
        if not self.client_update_available:
            return
        if self.client_update_in_progress or self.client_update_auto_started:
            return
        self.client_update_auto_started = True
        self.client_update_in_progress = True
        self.client_update_message = "Найдено обновление. Запускаю UPDATE_WISO_CLIENT.bat..."
        self._refresh_client_update_ui()

        launched, detail = self._launch_external_client_updater()
        if launched:
            self.after(0, lambda: messagebox.showinfo(
                "Обновление",
                f"Доступна новая версия {self.server_client_version}. "
                f"Запущен автоапдейтер:\n{detail}\n\nПриложение будет перезапущено."
            ))
            self.after(900, lambda: os._exit(0))
            return

        self.client_update_in_progress = False
        self.client_update_auto_started = False
        self.client_update_message = f"Автообновление не удалось: {detail}"
        self._refresh_client_update_ui()
        self.after(0, lambda d=detail: messagebox.showerror(
            "Обновление",
            f"Не удалось запустить UPDATE_WISO_CLIENT.bat:\n{d}"
        ))

    def trigger_client_update(self):
        if self.client_update_in_progress:
            return
        target_ver = str(self.server_client_version or "").strip() or "новая версия"
        if not messagebox.askyesno(
            "Обновление клиента",
            f"Установить обновление до {target_ver} и перезапустить приложение сейчас?"
        ):
            return
        self.client_update_in_progress = True
        self.client_update_auto_started = True
        self.client_update_message = "Запускаю UPDATE_WISO_CLIENT.bat..."
        self._refresh_client_update_ui()
        launched, detail = self._launch_external_client_updater()
        if launched:
            messagebox.showinfo(
                "Обновление",
                f"Запущен UPDATE_WISO_CLIENT.bat:\n{detail}\n\nПриложение будет перезапущено."
            )
            self.after(900, lambda: os._exit(0))
            return

        self.client_update_in_progress = False
        self.client_update_auto_started = False
        self.client_update_message = f"Ошибка запуска апдейтера: {detail}"
        self._refresh_client_update_ui()
        messagebox.showerror("Обновление", f"Не удалось запустить UPDATE_WISO_CLIENT.bat:\n{detail}")

    def _apply_client_update_bundle(self, data: dict):
        files = data.get('files') if isinstance(data.get('files'), list) else []
        if not files:
            raise RuntimeError("Пакет обновления пустой")
        project_dir = Path(__file__).resolve().parent.parent
        for item in files:
            rel_path = str(item.get('rel_path') or '').strip().replace("\\", "/")
            payload = str(item.get('data_b64') or '')
            if not rel_path or not payload:
                continue
            target_path = (project_dir / rel_path).resolve()
            if project_dir not in target_path.parents and target_path != project_dir:
                raise RuntimeError(f"Некорректный путь обновления: {rel_path}")
            target_path.parent.mkdir(parents=True, exist_ok=True)
            raw = base64.b64decode(payload.encode('ascii'), validate=False)
            tmp_path = target_path.with_suffix(target_path.suffix + ".new")
            tmp_path.write_bytes(raw)
            tmp_path.replace(target_path)

    def _restart_after_update(self):
        project_dir = Path(__file__).resolve().parent.parent
        try:
            subprocess.Popen(
                [sys.executable, "clients/unified_client.py"],
                cwd=str(project_dir),
                creationflags=getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0),
                close_fds=True
            )
            self.after(300, lambda: os._exit(0))
            return
        except Exception:
            pass
        launcher_cmd = self._resolve_launcher_cmd()
        try:
            os.startfile(str(launcher_cmd))
            self.after(450, lambda: os._exit(0))
        except Exception as e:
            self.client_update_in_progress = False
            self._refresh_client_update_ui()
            messagebox.showerror("Обновление", f"Обновление установлено, но перезапуск не удался:\n{e}")

    def _update_sync_status_ui(self):
        """Обновление UI статуса синхронизации"""
        if not hasattr(self, 'sync_status_icon'):
            return

        c = self.colors

        # ИСПРАВЛЕНИЕ: Если статус idle но заказы уже есть - показываем success
        if self.sync_status == "idle" and hasattr(self, 'orders') and self.orders:
            self.sync_status = "success"
            if not self.sync_last_update:
                self.sync_last_update = datetime.now()

        # Скрываем/показываем элементы в зависимости от статуса
        if self.sync_status == "loading":
            # Показываем прогресс-бар
            self.sync_progress_frame.pack(side=tk.RIGHT, padx=(0, 15))
            self.sync_progress_bar['value'] = self.sync_progress
            self.sync_progress_label.config(text=f"{self.sync_progress}%")
            self.sync_status_icon.config(text="⏳", fg=c["warning"])
            self.sync_status_label.config(text="Загрузка...", fg=c["warning"])
            self.sync_clear_btn.pack_forget()
        elif self.sync_status == "success":
            # Скрываем прогресс-бар
            self.sync_progress_frame.pack_forget()
            self.sync_status_icon.config(text="✅", fg=c["success"])
            self.sync_status_label.config(text="Обновлено", fg=c["success"])
            self.sync_clear_btn.pack_forget()
        elif self.sync_status == "error":
            # Скрываем прогресс-бар, показываем кнопку очистки
            self.sync_progress_frame.pack_forget()
            self.sync_status_icon.config(text="❌", fg=c["danger"])
            self.sync_status_label.config(text="Ошибка", fg=c["danger"])
            self.sync_clear_btn.pack(side=tk.RIGHT, padx=(0, 10))
        else:  # idle
            self.sync_progress_frame.pack_forget()
            self.sync_status_icon.config(text="⏳", fg=c["text_light"])
            self.sync_status_label.config(text="Ожидание...", fg=c["text_light"])
            self.sync_clear_btn.pack_forget()

        # Обновляем время последнего обновления
        if self.sync_last_update:
            time_str = self.sync_last_update.strftime("%H:%M:%S")
            self.sync_time_label.config(text=f"🕐 {time_str}")
        else:
            self.sync_time_label.config(text="")

    def start_sync(self, total_items: int = 0):
        """Начало синхронизации заказов"""
        self.sync_status = "loading"
        self.sync_progress = 0
        self.sync_error_message = ""
        self.after(0, self._update_sync_status_ui)

    def update_sync_progress(self, current: int, total: int):
        """Обновление прогресса синхронизации"""
        if total > 0:
            self.sync_progress = int((current / total) * 100)
        else:
            self.sync_progress = 0
        self.after(0, self._update_sync_status_ui)

    def complete_sync(self):
        """Успешное завершение синхронизации"""
        self.sync_status = "success"
        self.sync_progress = 100
        self.sync_last_update = datetime.now()
        self.after(0, self._update_sync_status_ui)

    def fail_sync(self, error_message: str = ""):
        """Ошибка синхронизации"""
        self.sync_status = "error"
        self.sync_error_message = error_message
        self.sync_last_update = datetime.now()
        self.after(0, self._update_sync_status_ui)

    def _clear_bestellung_folder(self):
        """Очистка папки bestellung от старых файлов"""
        import shutil
        from tkinter import messagebox

        # Путь к папке bestellung (из конфигурации)
        bestellung_path = Path(CONFIG.get('PATHS', {}).get('bestellung_folder', 'bestellung'))

        if not bestellung_path.exists():
            messagebox.showinfo("Информация", f"Папка {bestellung_path} не найдена")
            return

        # Подтверждение
        if not messagebox.askyesno(
            "Подтверждение",
            f"Очистить папку {bestellung_path}?\n\nВсе файлы в папке будут удалены!"
        ):
            return

        try:
            # Удаляем все файлы в папке
            files_deleted = 0
            for item in bestellung_path.iterdir():
                if item.is_file():
                    item.unlink()
                    files_deleted += 1
                elif item.is_dir():
                    shutil.rmtree(item)
                    files_deleted += 1

            messagebox.showinfo("Успех", f"Удалено {files_deleted} файлов/папок")

            # Сбрасываем статус
            self.sync_status = "idle"
            self.sync_error_message = ""
            self._update_sync_status_ui()

        except Exception as e:
            messagebox.showerror("Ошибка", f"Не удалось очистить папку:\n{e}")

    def _on_period_change(self, value):
        """Обработчик изменения периода в дашборде"""
        if hasattr(self, 'dashboard_period'):
            self.dashboard_period.set(value)
        self.update_dashboard()

    def update_dashboard(self):
        """Обновление данных дашборда (С поддержкой ТЕМЫ)"""
        if not hasattr(self, 'dashboard_kpi_labels'): return

        # Обновляем статус синхронизации при каждом обновлении дашборда
        self._update_sync_status_ui()

        c = self.colors # Текущие цвета
        
        # Настройка цветов графиков (Matplotlib)
        chart_bg = c["bg_card"]
        text_color = c["text_main"]
        
        try:
            # === СБОР ДАННЫХ (ТОТ ЖЕ КОД, ЧТО И РАНЬШЕ) ===
            period = self.dashboard_period.get() if hasattr(self, 'dashboard_period') else 'today'
            orders_to_analyze = []
            today = datetime.now().date()

            # ... (логика фильтрации по датам остается прежней, см. старый код) ...
            # Чтобы не загромождать ответ, я приведу только часть с обновлением UI
            # СКОПИРУЙТЕ ЛОГИКУ ФИЛЬТРАЦИИ ИЗ СТАРОГО МЕТОДА update_dashboard СЮДА
            # Или используйте тот же цикл перебора self.orders
            
            for oid, order in self.orders.items():
                order_data = order.get('data', order)
                # ... (логика определения даты) ...
                try:
                    d_str = order_data.get('delivery_date') or "0000-00-00"
                    if d_str != "0000-00-00": d_date = datetime.strptime(d_str[:10], '%Y-%m-%d').date()
                    else: d_date = today
                except: d_date = today
                
                # Фильтр периода
                diff = (d_date - today).days
                include = False
                if period == "today" and diff == 0: include = True
                elif period == "5days" and -2 <= diff <= 5: include = True
                elif period == "3days" and -2 <= diff <= 5: include = True
                elif period == "week" and -7 <= diff <= 7: include = True
                elif period == "month" and -30 <= diff <= 30: include = True
                elif period == "all": include = True
                
                if include: orders_to_analyze.append(order_data)

            # ... (подсчет статистики: completed, in_progress, printed и т.д.) ...
            completed, in_progress, not_started, printed, with_invoice = 0, 0, 0, 0, 0
            total_items, total_positions = 0, 0
            routes_count = {}
            clients_count = {}
            total_sum = 0.0
            
            total = len(orders_to_analyze)
            
            for o in orders_to_analyze:
                arts = o.get('artikel', [])
                total_positions += len(arts)
                
                # Простая логика статуса
                s_req = sum(float(a.get('menge', 0)) for a in arts)
                s_got = sum(float(a.get('picked', 0)) for a in arts)
                total_items += s_req
                
                is_printed = o.get('printed', False)
                box = int(o.get('boxes_count', 0))
                
                if s_req > 0:
                    if s_got >= s_req and is_printed and box > 0: completed += 1
                    elif s_got > 0: in_progress += 1
                    else: not_started += 1
                else: not_started += 1
                
                if is_printed: printed += 1
                if '✅' in str(o.get('invoice_status', '')): with_invoice += 1
                
                # Маршруты и Клиенты
                rt = o.get('route_name', o.get('route', 'Без маршрута'))
                routes_count[rt] = routes_count.get(rt, 0) + 1
                
                cl = o.get('client', o.get('kunde', 'Unknown'))
                clients_count[cl] = clients_count.get(cl, 0) + 1
                
                try: total_sum += float(o.get('total_value', o.get('sum', 0)))
                except: pass

            # === ОБНОВЛЕНИЕ UI ===
            
            # 1. Карточки
            progress_pct = (completed / total * 100) if total > 0 else 0
            kpis = {
                'active': total, # Сегодня / Активные
                'in_progress': in_progress,
                'not_started': not_started,
                'total_items': int(total_items), # Всего штук тортов
                'orders_total': total,
                'printed': printed,
                'progress_pct': f"{progress_pct:.0f}%",
                'with_invoice': with_invoice,
                'total_positions': total_positions
            }
            
            for k, v in kpis.items():
                if k in self.dashboard_kpi_labels:
                    self.dashboard_kpi_labels[k].config(text=str(v))

            # 2. График DONUT (Сборка)
            if hasattr(self, 'dashboard_ax_pie'):
                self.dashboard_ax_pie.clear()
                self.dashboard_fig_pie.patch.set_facecolor(chart_bg)
                
                # В референсе donut отображается как единое кольцо со значением в центре.
                self.dashboard_ax_pie.pie(
                    [1],
                    colors=["#EE3B3B"],
                    startangle=90,
                    wedgeprops=dict(width=0.42, edgecolor=chart_bg)
                )
                self.dashboard_ax_pie.text(
                    0, 0, str(total),
                    ha='center', va='center',
                    fontsize=32, fontweight='bold', color=text_color
                )
                self.dashboard_ax_pie.set_aspect("equal")

                self.dashboard_canvas_pie.draw()

            # 3. График BAR (Маршруты)
                if hasattr(self, 'dashboard_ax_bar'):
                    self.dashboard_ax_bar.clear()
                    self.dashboard_fig_bar.patch.set_facecolor(chart_bg)
                    self.dashboard_ax_bar.set_facecolor(chart_bg)
                
                # Настройка цветов осей и текста
                self.dashboard_ax_bar.tick_params(axis='x', colors=c["text_light"])
                self.dashboard_ax_bar.tick_params(axis='y', colors=c["text_light"])
                for spine in self.dashboard_ax_bar.spines.values():
                    spine.set_edgecolor(c["border"])
                self.dashboard_ax_bar.spines['top'].set_visible(False)
                self.dashboard_ax_bar.spines['right'].set_visible(False)

                sorted_routes = sorted(routes_count.items(), key=lambda x: x[1], reverse=True)[:6]
                if sorted_routes:
                    r_names = [x[0][:15] for x in sorted_routes]
                    r_vals = [x[1] for x in sorted_routes]
                    y_pos = range(len(r_names))
                    
                    self.dashboard_ax_bar.barh(y_pos, r_vals, color="#3B75F5", height=0.60)
                    self.dashboard_ax_bar.set_yticks(y_pos)
                    self.dashboard_ax_bar.set_yticklabels(r_names, color=c["text_light"])
                    self.dashboard_ax_bar.invert_yaxis()
                    self.dashboard_ax_bar.grid(axis='x', color=c["border"], alpha=0.35, linewidth=1)
                
                self.dashboard_canvas_bar.draw()

            # 4. Списки (Текст)
            if hasattr(self, 'dashboard_top_clients'):
                top_cl = sorted(clients_count.items(), key=lambda x: x[1], reverse=True)[:5]
                txt = "\n".join([f"{i+1}. {k[:25]} — {v} зак." for i, (k,v) in enumerate(top_cl)])
                self.dashboard_top_clients.config(text=txt, fg=c["accent"])
                
            if hasattr(self, 'dashboard_sum_stats'):
                avg = total_sum / total if total > 0 else 0
                txt = f"Общая: {total_sum:,.2f} €\nСредняя: {avg:,.2f} €"
                self.dashboard_sum_stats.config(text=txt)
                
            if hasattr(self, 'dashboard_print_stats'):
                pct = (printed / total * 100) if total > 0 else 0
                txt = f"Напечатано: {printed} из {total}\nПрогресс: {pct:.1f}%"
                self.dashboard_print_stats.config(text=txt)

        except Exception as e:
            print(f"[Dashboard Error] {e}")

