    def _ensure_admin_order_mail_icons(self):
        """Создаёт/загружает иконки статуса письма (серый/синий конверт)."""
        if hasattr(self, '_mail_icon_sent') and hasattr(self, '_mail_icon_unsent'):
            return

        self._mail_icon_sent = None
        self._mail_icon_unsent = None
        try:
            from PIL import Image, ImageDraw

            icons_dir = Path(__file__).parent / "_ui_icons"
            icons_dir.mkdir(parents=True, exist_ok=True)

            def _draw_mail_icon(path: Path, stroke_color: tuple):
                w, h = 20, 14
                img = Image.new("RGBA", (w, h), (0, 0, 0, 0))
                dr = ImageDraw.Draw(img)
                dr.rounded_rectangle((1, 1, w - 2, h - 2), radius=2, outline=stroke_color, width=2)
                dr.line((2, 2, w // 2, h // 2 + 1), fill=stroke_color, width=2)
                dr.line((w - 3, 2, w // 2, h // 2 + 1), fill=stroke_color, width=2)
                dr.line((2, h - 3, w // 2, h // 2 + 1), fill=stroke_color, width=2)
                dr.line((w - 3, h - 3, w // 2, h // 2 + 1), fill=stroke_color, width=2)
                img.save(path)

            sent_path = icons_dir / "mail_sent_blue.png"
            unsent_path = icons_dir / "mail_unsent_gray.png"
            if not sent_path.exists():
                _draw_mail_icon(sent_path, (37, 99, 235, 255))
            if not unsent_path.exists():
                _draw_mail_icon(unsent_path, (156, 163, 175, 255))

            self._mail_icon_sent = tk.PhotoImage(file=str(sent_path))
            self._mail_icon_unsent = tk.PhotoImage(file=str(unsent_path))
        except Exception as e:
            print(f"[UI] Mail icons fallback to text mode: {e}")

    def _admin_orders_email_link_click(self, event):
        tree = getattr(self, 'admin_orders_tree', None)
        if not tree:
            return
        region = tree.identify_region(event.x, event.y)
        if region not in ("cell", "tree"):
            return

        row_id = tree.identify_row(event.y)
        if not row_id:
            return

        if region == "cell":
            col_id = tree.identify_column(event.x)
            if not col_id:
                return
            try:
                col_idx = int(str(col_id).replace("#", "")) - 1
            except Exception:
                return

            display_cols = tree.cget("displaycolumns")
            if display_cols == "#all":
                display_cols = tuple(self.admin_orders_column_order)
            if col_idx < 0 or col_idx >= len(display_cols):
                return
            column_name = display_cols[col_idx]
            if column_name != 'email':
                return

        # Дата-группа не кликабельна
        if not tree.parent(row_id):
            return
        # Строка товара не кликабельна
        parent_id = tree.parent(row_id)
        if parent_id and tree.parent(parent_id):
            return

        order_id = self.get_order_id_from_selection(tree, [row_id])
        if not order_id or order_id not in self.orders:
            return

        order_info = self.orders[order_id]
        order_data = order_info.get('data', order_info)
        if not bool(order_data.get('customer_email_sent')):
            return

        try:
            boxes_count = int(float(order_data.get('boxes_count') or 0))
        except Exception:
            boxes_count = 0
        self.send_ws_message({
            'type': 'get_customer_shipping_doc',
            'order_id': order_id,
            'boxes_count': boxes_count
        })

    def _admin_orders_double_click(self, event):
        tree = getattr(self, 'admin_orders_tree', None)
        if not tree:
            return

        region = tree.identify_region(event.x, event.y)
        if region != "cell":
            return

        row_id = tree.identify_row(event.y)
        if not row_id:
            return

        col_id = tree.identify_column(event.x)
        if not col_id:
            return

        try:
            col_idx = int(str(col_id).replace("#", "")) - 1
        except Exception:
            return

        display_cols = tree.cget("displaycolumns")
        if display_cols == "#all":
            display_cols = tuple(self.admin_orders_column_order)
        if col_idx < 0 or col_idx >= len(display_cols):
            return

        # Открываем заказ ТОЛЬКО по колонке "№ Заказа"
        if display_cols[col_idx] != 'id':
            return

        # Группы дат и дочерние строки не открываем
        parent_id = tree.parent(row_id)
        if not parent_id:
            return
        if tree.parent(parent_id):
            return

        order_id = self.get_order_id_from_selection(tree, [row_id])
        if not order_id or order_id not in self.orders:
            return

        order_info = self.orders[order_id]
        order_data = order_info.get('data', order_info)
        self._open_admin_order_items_window(order_id, order_data)

    def _open_admin_order_items_window(self, order_id: str, order_data: dict):
        """Окно полного состава заказа (аналог старого раскрытия, но в отдельном окне)."""
        arts = order_data.get('artikel', []) or []
        kunde = str(order_data.get('kunde') or '-').strip() or '-'
        order_no = str(order_data.get('auftrag_nr') or order_id or '').strip() or str(order_id)
        delivery_date = str(order_data.get('delivery_date') or order_data.get('date') or '-')

        win = tk.Toplevel(self)
        win.title(f"Заказ {order_no}")
        win.geometry("980x620")
        win.minsize(820, 500)
        win.transient(self)
        win.grab_set()

        head = ttk.Frame(win)
        head.pack(fill=tk.X, padx=12, pady=(10, 6))
        ttk.Label(head, text=f"Заказ: {order_no}", font=("Arial", 11, "bold")).pack(anchor='w')
        ttk.Label(head, text=f"Клиент: {kunde}", font=("Arial", 10)).pack(anchor='w')
        ttk.Label(head, text=f"Дата доставки: {delivery_date}", font=("Arial", 10)).pack(anchor='w')

        table_wrap = ttk.Frame(win)
        table_wrap.pack(fill=tk.BOTH, expand=True, padx=12, pady=6)

        cols = ('pos', 'article', 'name', 'ordered', 'picked', 'status', 'comment')
        tree = ttk.Treeview(table_wrap, columns=cols, show='headings')
        tree.heading('pos', text='Pos.')
        tree.heading('article', text='Artikel')
        tree.heading('name', text='Bezeichnung')
        tree.heading('ordered', text='Bestellt')
        tree.heading('picked', text='Gesammelt')
        tree.heading('status', text='Status')
        tree.heading('comment', text='Kommentar')

        tree.column('pos', width=60, anchor='center')
        tree.column('article', width=120, anchor='center')
        tree.column('name', width=360, anchor='w')
        tree.column('ordered', width=90, anchor='center')
        tree.column('picked', width=90, anchor='center')
        tree.column('status', width=100, anchor='center')
        tree.column('comment', width=180, anchor='w')

        vs = ttk.Scrollbar(table_wrap, orient=tk.VERTICAL, command=tree.yview)
        hs = ttk.Scrollbar(table_wrap, orient=tk.HORIZONTAL, command=tree.xview)
        tree.configure(yscrollcommand=vs.set, xscrollcommand=hs.set)

        tree.grid(row=0, column=0, sticky='nsew')
        vs.grid(row=0, column=1, sticky='ns')
        hs.grid(row=1, column=0, sticky='ew')
        table_wrap.rowconfigure(0, weight=1)
        table_wrap.columnconfigure(0, weight=1)

        for i, art in enumerate(arts, 1):
            raw_nr = str(art.get('artikel_nr') or art.get('nummer') or '').strip()
            article_nr = raw_nr.replace(' ', '').replace(',', '').split('.')[0].zfill(5) if raw_nr else ''
            name = str(art.get('name') or art.get('beschreibung') or '').strip()
            comment = str(art.get('comment') or art.get('kommentar') or '').strip()
            try:
                ordered = int(float(art.get('menge', 0)))
            except Exception:
                ordered = 0
            try:
                picked = int(float(art.get('picked', 0)))
            except Exception:
                picked = 0
            is_checked = bool(art.get('checked', False))
            if is_checked:
                status = "✅ Готов"
            elif picked > 0:
                status = "🔄 В работе"
            else:
                status = "⏳ Не собрано"

            tree.insert('', tk.END, values=(
                i, article_nr, name, ordered, picked, status, comment
            ))

        footer = ttk.Frame(win)
        footer.pack(fill=tk.X, padx=12, pady=(4, 10))
        ttk.Label(footer, text=f"Позиций: {len(arts)}").pack(side=tk.LEFT)
        ttk.Button(footer, text="Закрыть", command=win.destroy).pack(side=tk.RIGHT)

