    def add_client_from_order(self):
        """Создать клиента в базе логистики на основе выбранного заказа"""
        selection = self.admin_orders_tree.selection()
        if not selection:
            messagebox.showwarning("Внимание", "Выберите заказ")
            return

        # Получаем данные заказа
        order_id = self.get_order_id_from_selection(self.admin_orders_tree, selection)
        if not order_id or order_id not in self.orders:
            return

        order_data = self.orders[order_id].get('data', self.orders[order_id])
        
        # Извлекаем данные
        kunden_nr = str(order_data.get('kunden_nr', '')).strip()
        kunde_name = order_data.get('kunde', '').strip()
        address = order_data.get('address', '')
        email = (
            order_data.get('email')
            or order_data.get('e_mail')
            or order_data.get('mail')
            or order_data.get('kunde_email')
            or order_data.get('customer_email')
            or ''
        )
        
        # Проверяем, есть ли уже такой клиент (по monolith_client_id или client_id)
        existing = next((c for c in self.logistics_clients
                         if str(c.get('monolith_client_id', '')) == kunden_nr
                         or str(c['client_id']) == kunden_nr), None)
        if existing:
            if not messagebox.askyesno("Внимание", f"Клиент {kunden_nr} уже есть в базе. Редактировать его?"):
                return
            self.client_editor_dialog(mode='edit', data=existing)
        else:
            # Создаем структуру данных для нового клиента:
            # monolith_client_id берём из заказа, client_id пользователь заполнит сам
            new_client_data = {
                'client_id': '',
                'monolith_client_id': kunden_nr,
                'client_name': kunde_name,
                'email': email,
                'address': address,
                'plz': '',
                'city': '',
                'route_id': 'free'
            }
            
            # Попытка парсинга города из адреса (простая эвристика)
            if ',' in address:
                parts = address.split(',')
                if len(parts) >= 2:
                    new_client_data['city'] = parts[-1].strip()
                    new_client_data['address'] = ",".join(parts[:-1]).strip()

            # Открываем диалог (используем уже существующий метод)
            self.client_editor_dialog(mode='add', data=new_client_data)

    def show_admin_orders_settings(self):
        """Диалог настройки видимости колонок таблицы 'Все заказы'."""
        c = self.colors
        win = tk.Toplevel(self)
        win.title("Настройки таблицы заказов")
        win.transient(self)
        win.grab_set()
        self.center_dialog(win, 560, 760)
        win.configure(bg="#F5F6F8")

        card = tk.Frame(win, bg="#F5F6F8", highlightbackground="#D1D5DB", highlightthickness=1)
        card.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        tk.Label(card, text="Настройки таблицы заказов", font=("Segoe UI", 18, "bold"),
                 bg="#F5F6F8", fg="#111827").pack(anchor='w', padx=16, pady=(14, 8))

        body = tk.Frame(card, bg="#F5F6F8")
        body.pack(fill=tk.BOTH, expand=True, padx=12)
        tk.Label(body, text="Показывать столбцы:", font=("Segoe UI", 12, "bold"),
                 bg="#F5F6F8", fg="#111827").pack(anchor='w', padx=4, pady=(2, 8))

        for i, col in enumerate(self.admin_orders_column_order):
            row = tk.Frame(body, bg="#F5F6F8")
            row.pack(fill=tk.X, pady=(0, 1))

            lbl = tk.Label(row, text=self.admin_orders_column_meta[col]['title'],
                           font=("Segoe UI", 11), bg="#F5F6F8", fg="#111827", anchor='w')
            lbl.pack(side=tk.LEFT, padx=(8, 0), pady=8)

            toggle = tk.Canvas(row, width=56, height=28, bg="#F5F6F8", highlightthickness=0, bd=0)
            toggle.pack(side=tk.RIGHT, padx=(12, 8))
            self._draw_shipping_toggle(toggle, self.admin_orders_column_vars[col].get())

            def on_toggle(_event=None, key=col, canvas=toggle):
                current = self.admin_orders_column_vars[key].get()
                self.admin_orders_column_vars[key].set(not current)
                self._draw_shipping_toggle(canvas, not current)
                self.apply_admin_orders_columns_visibility()

            row.bind("<Button-1>", on_toggle)
            lbl.bind("<Button-1>", on_toggle)
            toggle.bind("<Button-1>", on_toggle)

            if i < len(self.admin_orders_column_order) - 1:
                tk.Frame(body, bg="#E5E7EB", height=1).pack(fill=tk.X, padx=8)

        footer = tk.Frame(card, bg="#F5F6F8")
        footer.pack(fill=tk.X, padx=12, pady=(8, 12))
        tk.Button(
            footer, text="Сохранить настройки", font=("Segoe UI", 11, "bold"),
            bg="#2563EB", fg="white", activebackground="#1D4ED8", activeforeground="white",
            relief=tk.FLAT, bd=0, padx=18, pady=10,
            command=lambda w=win: self.save_admin_orders_settings(dialog=w)
        ).pack(side=tk.LEFT, padx=(4, 8), fill=tk.X, expand=True)
        tk.Button(
            footer, text="Закрыть", font=("Segoe UI", 11),
            bg="#E5EAF2", fg="#111827", activebackground="#D6DEE8", activeforeground="#111827",
            relief=tk.FLAT, bd=0, padx=18, pady=10, command=win.destroy
        ).pack(side=tk.LEFT, padx=(8, 4), fill=tk.X, expand=True)

    def request_admin_orders_settings(self):
        self.send_ws_message({'type': 'get_admin_orders_settings'})

    def save_admin_orders_settings(self, dialog=None):
        visible_columns = [
            col for col in self.admin_orders_column_order
            if self.admin_orders_column_vars[col].get()
        ]
        self.send_ws_message({
            'type': 'save_admin_orders_settings',
            'visible_columns': visible_columns
        })
        self.apply_admin_orders_columns_visibility()
        if dialog and dialog.winfo_exists():
            dialog.destroy()

    def apply_admin_orders_columns_visibility(self):
        if not hasattr(self, 'admin_orders_tree'):
            return
        display_columns = [
            col for col in self.admin_orders_column_order
            if self.admin_orders_column_vars[col].get()
        ]
        if not display_columns:
            self.admin_orders_column_vars['id'].set(True)
            display_columns = ['id']
        self.admin_orders_tree.configure(displaycolumns=display_columns)

    def admin_open_add_order_dialog(self):
        """Диалог выбора способа добавления заказа (ручной / PDF)."""
        if not hasattr(self, 'logistics_clients'):
            self.logistics_clients = []
        if not hasattr(self, 'logistics_routes'):
            self.logistics_routes = []
        # Подтягиваем свежую логистику (не блокируем UI)
        self.send_ws_message({'type': 'get_all_logistics'})

        dlg = tk.Toplevel(self)
        dlg.title("Добавить заказ")
        self.center_dialog(dlg, 460, 220)
        dlg.resizable(False, False)

        wrap = ttk.Frame(dlg, padding=16)
        wrap.pack(fill=tk.BOTH, expand=True)
        ttk.Label(wrap, text="Выберите действие:", font=("Segoe UI", 11, "bold")).pack(anchor='w', pady=(0, 12))

        ttk.Button(
            wrap,
            text="1. Внести заказ вручную",
            command=lambda: (dlg.destroy(), self.admin_open_manual_order_dialog())
        ).pack(fill=tk.X, pady=4)

        ttk.Button(
            wrap,
            text="2. Загрузить заказ из PDF",
            command=lambda: (dlg.destroy(), self.admin_import_order_from_pdf())
        ).pack(fill=tk.X, pady=4)

    def _admin_find_client(self, query: str):
        q = (query or '').strip().lower()
        if not q:
            return None
        for c in getattr(self, 'logistics_clients', []):
            cid = str(c.get('client_id', '')).strip().lower()
            name = str(c.get('client_name', '')).strip().lower()
            if q == cid or q == name:
                return c
        return None

    def admin_open_manual_order_dialog(self):
        """Ручное создание заказа администратором."""
        if not hasattr(self, 'all_recipes_data') or not self.all_recipes_data:
            self.send_ws_message({'type': 'get_recipes'})

        recipe_index = {}
        for r in (getattr(self, 'all_recipes_data', []) or []):
            raw_art = str(r.get('article_nr', '')).strip()
            if not raw_art:
                continue
            art = raw_art.zfill(5) if raw_art.isdigit() else raw_art
            name = str(r.get('name', '')).strip() or "Без названия"
            recipe_index[art] = name
        article_options_all = [f"{a} - {n}" for a, n in sorted(recipe_index.items(), key=lambda x: str(x[0]))]

        def _norm_art(value: str) -> str:
            raw = str(value or '').strip()
            if ' - ' in raw:
                raw = raw.split(' - ', 1)[0]
            raw = raw.replace(' ', '').replace(',', '')
            if '.' in raw and raw.replace('.', '').isdigit():
                raw = raw.split('.', 1)[0]
            return raw.zfill(5) if raw.isdigit() else raw

        dlg = tk.Toplevel(self)
        dlg.title("Ручной ввод заказа")
        self.center_dialog(dlg, 760, 620)

        wrap = ttk.Frame(dlg, padding=12)
        wrap.pack(fill=tk.BOTH, expand=True)

        top = ttk.Frame(wrap)
        top.pack(fill=tk.X)

        ttk.Label(top, text="Тип ID").grid(row=0, column=0, sticky='w')
        prefix_var = tk.StringVar(value="AB")
        ttk.Combobox(top, width=10, state='readonly', textvariable=prefix_var, values=["AB", "MO"]).grid(row=0, column=1, sticky='w', padx=(6, 12))

        ttk.Label(top, text="Номер заказа").grid(row=0, column=2, sticky='w')
        order_nr_var = tk.StringVar()
        order_nr_entry = ttk.Entry(top, textvariable=order_nr_var, width=18)
        order_nr_entry.grid(row=0, column=3, sticky='w', padx=(6, 12))

        ttk.Label(top, text="Дата отгрузки").grid(row=0, column=4, sticky='w')
        delivery_entry = DateEntry(top, width=12, date_pattern='yyyy-mm-dd')
        delivery_entry.set_date(datetime.now())
        delivery_entry.grid(row=0, column=5, sticky='w', padx=(6, 0))

        client_frame = ttk.LabelFrame(wrap, text="Клиент")
        client_frame.pack(fill=tk.X, pady=(12, 10))

        ttk.Label(client_frame, text="ID / имя клиента").grid(row=0, column=0, sticky='w', padx=8, pady=6)
        customer_query_var = tk.StringVar()
        customer_entry = ttk.Entry(client_frame, textvariable=customer_query_var, width=36)
        customer_entry.grid(row=0, column=1, sticky='w', padx=6, pady=6)

        customer_name_var = tk.StringVar()
        customer_addr_var = tk.StringVar()
        customer_route_var = tk.StringVar(value='free')

        ttk.Label(client_frame, text="Клиент").grid(row=1, column=0, sticky='w', padx=8)
        ttk.Entry(client_frame, textvariable=customer_name_var, width=50).grid(row=1, column=1, sticky='w', padx=6, pady=3)
        ttk.Label(client_frame, text="Адрес").grid(row=2, column=0, sticky='w', padx=8)
        ttk.Entry(client_frame, textvariable=customer_addr_var, width=50).grid(row=2, column=1, sticky='w', padx=6, pady=3)
        ttk.Label(client_frame, text="Маршрут").grid(row=3, column=0, sticky='w', padx=8, pady=(0, 8))
        ttk.Entry(client_frame, textvariable=customer_route_var, width=20).grid(row=3, column=1, sticky='w', padx=6, pady=(0, 8))

        def _autofill_client(*_args):
            found = self._admin_find_client(customer_query_var.get())
            if not found:
                return
            customer_query_var.set(str(found.get('client_id', '')).strip())
            customer_name_var.set(str(found.get('client_name', '')).strip())
            parts = [str(found.get('address', '')).strip(), str(found.get('plz', '')).strip(), str(found.get('city', '')).strip()]
            customer_addr_var.set(", ".join([p for p in parts if p]))
            customer_route_var.set(str(found.get('route_id', '')).strip() or 'free')

        customer_entry.bind('<FocusOut>', _autofill_client)
        customer_entry.bind('<Return>', _autofill_client)

        pos_frame = ttk.LabelFrame(wrap, text="Позиции заказа")
        pos_frame.pack(fill=tk.BOTH, expand=True)

        cols = ('article', 'name', 'qty')
        pos_tree = ttk.Treeview(pos_frame, columns=cols, show='headings', height=10)
        pos_tree.heading('article', text='Артикль')
        pos_tree.heading('name', text='Название')
        pos_tree.heading('qty', text='Количество')
        pos_tree.column('article', width=120, anchor='center')
        pos_tree.column('name', width=420, anchor='w')
        pos_tree.column('qty', width=120, anchor='center')
        pos_tree.pack(fill=tk.BOTH, expand=True, padx=8, pady=(8, 6))

        entry_row = ttk.Frame(pos_frame)
        entry_row.pack(fill=tk.X, padx=8, pady=(0, 8))
        ttk.Label(entry_row, text="Артикль").pack(side=tk.LEFT)
        article_var = tk.StringVar()
        article_entry = ttk.Combobox(entry_row, textvariable=article_var, width=34, values=article_options_all)
        article_entry.pack(side=tk.LEFT, padx=(6, 10))
        ttk.Label(entry_row, text="Кол-во").pack(side=tk.LEFT)
        qty_var = tk.StringVar()
        qty_entry = ttk.Entry(entry_row, textvariable=qty_var, width=10)
        qty_entry.pack(side=tk.LEFT, padx=(6, 10))
        article_status_var = tk.StringVar(value="Введите артикул...")
        article_status_lbl = tk.Label(entry_row, textvariable=article_status_var, fg="#666666", bg=self.colors.get("bg_card", "#ffffff"))
        article_status_lbl.pack(side=tk.LEFT, padx=(4, 0))

        def _update_article_status(*_args):
            typed = article_var.get()
            art = _norm_art(typed)
            typed_l = str(typed or '').strip().lower()
            if typed_l:
                filtered = [opt for opt in article_options_all if opt.lower().startswith(typed_l)]
                if len(filtered) < 15:
                    extra = [opt for opt in article_options_all if typed_l in opt.lower() and opt not in filtered]
                    filtered.extend(extra[:15 - len(filtered)])
                article_entry.configure(values=(filtered[:25] or article_options_all[:25]))
            else:
                article_entry.configure(values=article_options_all[:25])
            if not art:
                article_status_var.set("Введите артикул...")
                article_status_lbl.configure(fg="#666666")
                return
            if art in recipe_index:
                article_status_var.set(f"Найдено: {art} - {recipe_index[art]}")
                article_status_lbl.configure(fg="#0a7d35")
                return
            prefix_matches = [f"{a} - {n}" for a, n in recipe_index.items() if str(a).startswith(art)]
            if prefix_matches:
                preview = "; ".join(prefix_matches[:2])
                more = "" if len(prefix_matches) <= 2 else f" (+{len(prefix_matches)-2})"
                article_status_var.set(f"Похожие: {preview}{more}")
                article_status_lbl.configure(fg="#a36b00")
            else:
                article_status_var.set("Артикул не найден в рецептах")
                article_status_lbl.configure(fg="#b00020")

        def _add_position(_event=None):
            art = _norm_art(article_var.get())
            raw_qty = (qty_var.get() or '').strip().replace(',', '.')
            if not art:
                article_entry.focus_set()
                return
            if art not in recipe_index:
                messagebox.showwarning("Позиция", f"Артикул {art} не найден в базе рецептов.\nВыберите существующий артикул.")
                article_entry.focus_set()
                article_entry.selection_range(0, tk.END)
                return
            try:
                q = float(raw_qty)
            except Exception:
                messagebox.showwarning("Позиция", "Количество должно быть числом.")
                qty_entry.focus_set()
                return
            if q <= 0:
                messagebox.showwarning("Позиция", "Количество должно быть больше 0.")
                qty_entry.focus_set()
                return
            qty_text = str(int(q)) if float(q).is_integer() else str(q)
            name = recipe_index.get(art, '')
            # Если артикул уже есть в списке, увеличиваем количество
            for iid in pos_tree.get_children():
                vals = pos_tree.item(iid, 'values')
                if vals and str(vals[0]).strip() == art:
                    try:
                        old_q = float(str(vals[2]).replace(',', '.'))
                    except Exception:
                        old_q = 0.0
                    new_q = old_q + q
                    new_q_text = str(int(new_q)) if float(new_q).is_integer() else str(new_q)
                    pos_tree.item(iid, values=(art, name, new_q_text))
                    article_var.set('')
                    qty_var.set('')
                    _update_article_status()
                    article_entry.focus_set()
                    return

            pos_tree.insert('', tk.END, values=(art, name, qty_text))
            article_var.set('')
            qty_var.set('')
            _update_article_status()
            article_entry.focus_set()

        def _remove_position():
            for item in pos_tree.selection():
                pos_tree.delete(item)

        article_entry.bind('<Return>', lambda _e: qty_entry.focus_set())
        article_entry.bind('<Down>', lambda _e: article_entry.event_generate('<Button-1>'))
        qty_entry.bind('<Return>', _add_position)
        article_var.trace_add('write', _update_article_status)
        _update_article_status()
        ttk.Button(entry_row, text="Добавить", command=_add_position).pack(side=tk.LEFT, padx=4)
        ttk.Button(entry_row, text="Удалить выбранное", command=_remove_position).pack(side=tk.LEFT, padx=4)

        btns = ttk.Frame(wrap)
        btns.pack(fill=tk.X, pady=(10, 0))

        def _submit_manual_order():
            order_nr = (order_nr_var.get() or '').strip()
            if not order_nr:
                messagebox.showwarning("Заказ", "Укажите номер заказа.")
                return
            artikel = []
            for item in pos_tree.get_children():
                vals = pos_tree.item(item, 'values')
                if not vals or len(vals) < 3:
                    continue
                art = str(vals[0]).strip()
                name = str(vals[1]).strip()
                try:
                    qty = float(str(vals[2]).replace(',', '.'))
                except Exception:
                    continue
                if art and qty > 0:
                    artikel.append({'artikel_nr': art, 'nummer': art, 'name': name, 'beschreibung': name, 'menge': qty})
            if not artikel:
                messagebox.showwarning("Заказ", "Добавьте хотя бы одну позицию.")
                return

            self.send_ws_message({
                'type': 'create_manual_order',
                'order': {
                    'source_prefix': (prefix_var.get() or 'AB').strip().upper(),
                    'order_number': order_nr,
                    'kunden_nr': (customer_query_var.get() or '').strip(),
                    'kunde': (customer_name_var.get() or '').strip(),
                    'address': (customer_addr_var.get() or '').strip(),
                    'route_id': (customer_route_var.get() or '').strip(),
                    'delivery_date': delivery_entry.get_date().strftime('%Y-%m-%d'),
                    'order_date': datetime.now().strftime('%Y-%m-%d'),
                    'artikel': artikel
                }
            })
            dlg.destroy()

        ttk.Button(btns, text="Готово", command=_submit_manual_order).pack(side=tk.RIGHT)
        ttk.Button(btns, text="Отмена", command=dlg.destroy).pack(side=tk.RIGHT, padx=(0, 8))

        order_nr_entry.focus_set()

    def _parse_order_pdf_text(self, text: str) -> dict:
        """Эвристический парсер текста заказа из PDF."""
        import re

        src = (text or '').replace('\r', '\n')
        lines = [ln.strip() for ln in src.split('\n') if ln and ln.strip()]
        result = {
            'order_number': '',
            'kunden_nr': '',
            'kunde': '',
            'address': '',
            'artikel': []
        }

        patterns_order = [
            r'Auftrags[- ]?Nr\.?\s*[:#]?\s*([A-Za-z0-9\-\/]+)',
            r'Auftragsbest[äa]tigung(?:s?-?Nr\.?)?\s*[:#]?\s*([A-Za-z0-9\-\/]+)',
            r'Auftrag(?:s?-?Nr\.?)?\s*[:#]?\s*([A-Za-z0-9\-\/]+)',
            r'Bestell(?:ung)?(?:-?Nr\.?)?\s*[:#]?\s*([A-Za-z0-9\-\/]+)',
        ]
        for pat in patterns_order:
            m = re.search(pat, src, flags=re.IGNORECASE)
            if m:
                result['order_number'] = m.group(1).strip()
                break

        m_kn = re.search(r'Kunden[- ]?Nr\.?\s*:?\s*([A-Za-z0-9\-]+)', src, flags=re.IGNORECASE)
        if m_kn:
            result['kunden_nr'] = m_kn.group(1).strip()

        customer_block = []
        for ln in lines:
            if ln.startswith("Datum:"):
                break
            customer_block.append(ln)
        if customer_block:
            filtered = [x for x in customer_block if not x.lower().startswith("monolith bakery")]
            if filtered:
                result['kunde'] = filtered[0]
                if len(filtered) >= 3:
                    result['address'] = f"{filtered[1]}, {filtered[2]}"

        for i, ln in enumerate(lines):
            if re.match(r'^(Kunde|Kundenname)\s*[:]', ln, flags=re.IGNORECASE):
                result['kunde'] = ln.split(':', 1)[1].strip()
                if i + 1 < len(lines) and re.search(r'\d{4,5}\s+\w+', lines[i + 1]):
                    result['address'] = lines[i + 1]
                break

        items = {}
        current_art = None
        p_ab_line = re.compile(
            r'^\s*(\d+)\s+(\d+(?:[.,]\d+)?)\s*Stk\.?\s+(\d{4,8})\s+(.+?)\s+\d+%\s+[\d.,]+\s*€\s+[\d.,]+\s*€\s*$',
            re.IGNORECASE
        )
        p_simple = re.compile(
            r'^\s*(\d+)\s+(\d+(?:[.,]\d+)?)\s*Stk\.?\s+(\d{4,8})\s+(.+)$',
            re.IGNORECASE
        )

        def _clean_item_name(raw_name: str) -> str:
            """Убирает из конца названия хвосты с НДС/ценой/суммой."""
            name = str(raw_name or '').strip()
            if not name:
                return ''

            # Частый формат: "... 7% 3,86 € 19,30 €"
            name = re.sub(
                r'\s+\d{1,2}\s*%\s+\d+(?:[.,]\d+)?\s*€\s+\d+(?:[.,]\d+)?\s*€\s*$',
                '',
                name,
                flags=re.IGNORECASE
            )
            # Формат без процента: "... 3,86 € 19,30 €"
            name = re.sub(
                r'\s+\d+(?:[.,]\d+)?\s*€\s+\d+(?:[.,]\d+)?\s*€\s*$',
                '',
                name,
                flags=re.IGNORECASE
            )
            # Подстраховка для вариаций, где символ евро не распознан.
            name = re.sub(
                r'\s+\d+(?:[.,]\d+)?\s+\d+(?:[.,]\d+)?\s*$',
                '',
                name,
                flags=re.IGNORECASE
            )
            return re.sub(r'\s+', ' ', name).strip()

        for ln in lines:
            m = p_ab_line.match(ln) or p_simple.match(ln)
            if m:
                qty = float(m.group(2).replace(',', '.'))
                art = m.group(3).strip()
                name = _clean_item_name(m.group(4))
                if qty <= 0:
                    current_art = None
                    continue
                if art not in items:
                    items[art] = {'artikel_nr': art, 'nummer': art, 'name': name, 'beschreibung': name, 'menge': 0.0}
                else:
                    if name:
                        items[art]['name'] = name
                        items[art]['beschreibung'] = name
                items[art]['menge'] += qty
                current_art = art
                continue

            if current_art:
                is_service_line = (
                    ln.startswith("Summe") or
                    ln.startswith("Zu zahlender Betrag") or
                    ln.startswith("Mehrwertsteuer") or
                    ln.startswith("MwSt") or
                    ln.startswith("Nettobetrag") or
                    ln.startswith("Bruttobetrag") or
                    ln.startswith("Sparkasse") or
                    ln.startswith("IBAN") or
                    ln.startswith("BIC") or
                    ln.startswith("VR Genobank") or
                    ln.startswith("Amtsgericht") or
                    ln.startswith("CEO:") or
                    ln.startswith("Seite") or
                    ln.startswith("Auftrags-Nr.:") or
                    ln.startswith("Pos. Anzahl Einheit") or
                    ln.startswith("Die Lieferung erfolgt") or
                    ln.startswith("Wir freuen uns") or
                    "netto" in ln.lower() or
                    "brutto" in ln.lower()
                )
                if not is_service_line:
                    add_part = _clean_item_name(ln)
                    if not add_part:
                        continue
                    new_name = (items[current_art].get('name', '') + " " + add_part).strip()
                    items[current_art]['name'] = new_name
                    items[current_art]['beschreibung'] = new_name
                else:
                    # Дошли до сервисного блока внизу документа - не продолжаем
                    # "наращивать" последнее название товара.
                    current_art = None

        result['artikel'] = list(items.values())
        return result

    def admin_import_order_from_pdf(self):
        """Импорт заказа из PDF: извлечь данные и отправить на сервер."""
        file_path = filedialog.askopenfilename(
            title="Выберите PDF заказа",
            filetypes=[("PDF", "*.pdf"), ("All files", "*.*")]
        )
        if not file_path:
            return

        try:
            import pdfplumber
        except Exception:
            messagebox.showerror("PDF", "Не установлен pdfplumber. Установите: pip install pdfplumber")
            return

        try:
            text_parts = []
            with pdfplumber.open(file_path) as pdf:
                for p in pdf.pages:
                    text_parts.append(p.extract_text() or "")
            parsed = self._parse_order_pdf_text("\n".join(text_parts))
            if not parsed.get('order_number'):
                messagebox.showwarning("PDF", "Не удалось определить номер заказа в PDF.")
                return
            if not parsed.get('artikel'):
                messagebox.showwarning("PDF", "Не удалось распознать позиции товара в PDF.")
                return

            self.send_ws_message({
                'type': 'import_order_pdf',
                'file_name': Path(file_path).name,
                'order': {
                    'source_prefix': 'AB',
                    'order_number': parsed.get('order_number', ''),
                    'kunden_nr': parsed.get('kunden_nr', ''),
                    'kunde': parsed.get('kunde', ''),
                    'address': parsed.get('address', ''),
                    'order_date': datetime.now().strftime('%Y-%m-%d'),
                    'artikel': parsed.get('artikel', [])
                }
            })
        except Exception as exc:
            messagebox.showerror("PDF", f"Ошибка импорта PDF:\n{exc}")

