        toolbar.pack(fill=tk.X, pady=(0, 8))

        tk.Label(toolbar, text="Поиск:", bg=c["bg_card"], fg=c["text_light"],
                 font=("Segoe UI", 10)).pack(side=tk.LEFT, padx=(0, 5))
