        self.article_regions_search_var.trace_add("write", lambda *_: self._apply_article_regions_filter())
        ttk.Entry(toolbar, textvariable=self.article_regions_search_var, width=35).pack(side=tk.LEFT, padx=(0, 8))

        ttk.Button(toolbar, text="🔄 Обновить", command=self.refresh_article_regions_view).pack(side=tk.LEFT)
