    def _normalize_article_key(self, value):
        """Приводит артикул к одному формату для сравнения."""
        art = str(value or "").strip()
        if art.isdigit() and len(art) < 5:
            return art.zfill(5)
        return art

    def _parse_active_regions(self, raw_value):
        """Парсит active_regions из JSON-строки/списка."""
        try:
            if isinstance(raw_value, list):
                return [str(x).strip() for x in raw_value if str(x).strip()]
            if isinstance(raw_value, str) and raw_value.strip():
                parsed = json.loads(raw_value)
                if isinstance(parsed, list):
                    return [str(x).strip() for x in parsed if str(x).strip()]
        except Exception:
            pass
        return []

    def _get_cached_regions_for_article(self, article_nr):
        """Возвращает активные регионы для артикула из кэша остатков."""
        target = self._normalize_article_key(article_nr)
        regions_found = set()

        for cache in (getattr(self, '_cs_actual_cache', None), getattr(self, '_cs_full_cache', None)):
            if not cache:
                continue
            for row in cache.get("items", []) or []:
                row_art = self._normalize_article_key(row.get("Артикул", ""))
                if row_art != target:
                    continue
                for region in self.KNOWN_REGIONS:
                    val = row.get(region, 0) or 0
                    try:
                        if float(val) > 0:
                            regions_found.add(region)
                    except Exception:
                        continue
                if regions_found:
                    return sorted(regions_found, key=lambda x: self.KNOWN_REGIONS.index(x))
        return []

    def _load_article_regions_cache_async(self):
        """Фоновая загрузка кэша регионов без блокировки UI."""
        if getattr(self, '_article_regions_cache_loading', False):
            return
        self._article_regions_cache_loading = True

        def _worker():
            try:
                actual_data, _ = self._cs_fetch_and_transform(self.ACTUAL_STOCK_URL)
                full_data, _ = self._cs_fetch_and_transform(self.FULL_STOCK_URL)

                def _apply():
                    try:
                        if actual_data:
                            self._cs_actual_cache = actual_data
                            self._cs_actual_filtered = actual_data.get("items", [])[:]
                        if full_data:
                            self._cs_full_cache = full_data
                            self._cs_full_filtered = full_data.get("items", [])[:]
                    finally:
                        self._article_regions_cache_loading = False
                        if hasattr(self, 'article_regions_tree'):
                            self.refresh_article_regions_view()

                self.after(0, _apply)
            except Exception:
                self.after(0, lambda: setattr(self, '_article_regions_cache_loading', False))

        threading.Thread(target=_worker, daemon=True).start()

    def _get_active_regions_for_article(self, article_nr):
        """Получает регионы только из кэша (без сетевых вызовов в UI-потоке)."""
        from_cache = self._get_cached_regions_for_article(article_nr)
        if from_cache:
            return from_cache
        self._load_article_regions_cache_async()
        return list(self.KNOWN_REGIONS)

    def refresh_article_regions_view(self):
        """Обновляет таблицу регионов активности артикулов."""
        if not getattr(self, 'all_recipes_data', None):
            self.send_ws_message({'type': 'get_recipes'})
            self.after(600, self.refresh_article_regions_view)
            return

        if not getattr(self, '_cs_actual_cache', None) and not getattr(self, '_cs_full_cache', None):
            self._load_article_regions_cache_async()

        rows = []
        recipes = sorted(
            list(getattr(self, 'all_recipes_data', []) or []),
            key=lambda r: self._normalize_article_key(r.get('article_nr', ''))
        )
        for recipe in recipes:
            article_nr = self._normalize_article_key(recipe.get('article_nr', ''))
            name = str(recipe.get('name', '') or '')
            active_regions = self._parse_active_regions(recipe.get('active_regions'))
            if not active_regions:
                active_regions = self._get_active_regions_for_article(article_nr)
            if not active_regions:
                active_regions = list(self.KNOWN_REGIONS)
            rows.append({
                'article_nr': article_nr,
                'name': name,
                'regions': active_regions
            })

        self.article_regions_rows = rows
        self._apply_article_regions_filter()

    def _apply_article_regions_filter(self):
        """Фильтр таблицы регионов по артикулу/названию/региону."""
        if not hasattr(self, 'article_regions_tree'):
            return

        search = str(self.article_regions_search_var.get() or '').strip().lower() if hasattr(self, 'article_regions_search_var') else ''
        self.article_regions_tree.delete(*self.article_regions_tree.get_children())
        for row in getattr(self, 'article_regions_rows', []):
            regions_text = ", ".join(row['regions'])
            if search:
                hay = f"{row['article_nr']} {row['name']} {regions_text}".lower()
                if search not in hay:
                    continue
            self.article_regions_tree.insert('', tk.END, values=(row['article_nr'], row['name'], regions_text))

