    def on_dough_select(self, event):
        """Клик по компоненту производства"""
        sel = self.dough_tree.selection()
        if not sel: return
        item = self.dough_tree.item(sel[0])['values']
        self.dough_id_var.set(item[0])
        self.dough_name_var.set(item[1])
        self.dough_batch_var.set(item[2])
        if len(item) > 3:
            self.dough_unit_var.set(item[3] if item[3] else "лист")
        else:
            self.dough_unit_var.set("лист")
        if len(item) > 4:
            self.dough_workshop_var.set(item[4])
        else:
            self.dough_workshop_var.set("Основной цех")

    def save_current_dough(self):
        """Сохранить компонент производства"""
        did = self.dough_id_var.get()
        if not did: return
        unit = self.dough_unit_var.get() if hasattr(self, 'dough_unit_var') else "лист"
        workshop = self.dough_workshop_var.get() if hasattr(self, 'dough_workshop_var') else "Основной цех"
        self.admin_save_dough_type(did, self.dough_name_var.get(), self.dough_batch_var.get(), unit, workshop)
        self.after(200, self.admin_request_recipes) # Обновить

    def delete_current_dough(self):
        """Удалить выбранный компонент"""
        sel = self.dough_tree.selection()
        if not sel:
            messagebox.showwarning("Удаление", "Выберите компонент для удаления")
            return

        # Получить данные из таблицы
        values = self.dough_tree.item(sel[0])['values']
        dough_id = values[0]
        dough_name = values[1]

        # Подтверждение
        if not messagebox.askyesno("Удаление", f"Удалить компонент '{dough_name}' (ID: {dough_id})?\n\nВнимание: Удаление невозможно, если этот компонент используется в рецептах."):
            return

        # Отправить запрос на удаление
        self.send_ws_message({
            'type': 'delete_dough_type',
            'dough_id': dough_id
        })

        # Обновить список
        self.after(200, lambda: self.send_ws_message({'type': 'get_dough_list'}))

    def add_component_dialog(self):
        """Диалог добавления нового компонента"""
        self.component_editor_dialog(mode='add')

    def edit_component_dialog(self):
        """Диалог редактирования компонента"""
        sel = self.dough_tree.selection()
        if not sel:
            messagebox.showwarning("Редактирование", "Выберите компонент для редактирования")
            return
        self.component_editor_dialog(mode='edit')

    def component_editor_dialog(self, mode='add'):
        """Универсальный диалог для добавления/редактирования компонента (ИСПРАВЛЕНО)"""
        dialog = tk.Toplevel(self)
        dialog.title("Добавить компонент" if mode == 'add' else "Редактировать компонент")
        dialog.transient(self)
        dialog.grab_set()

        self.center_dialog(dialog, 650, 700)

        main_frame = ttk.Frame(dialog, padding=20)
        main_frame.pack(fill=tk.BOTH, expand=True)

        current_data = None
        if mode == 'edit':
            sel = self.dough_tree.selection()
            if sel:
                values = self.dough_tree.item(sel[0])['values']
                # Собираем данные из строки таблицы
                current_data = {
                    'dough_id': values[0],
                    'name': values[1],
                    'batch_size': float(values[2]) if values[2] else 1.0,
                    'unit': values[3] if len(values) > 3 else 'гр',
                    'resource_name': values[4] if len(values) > 4 else '',
                    'production_time_min': float(values[5]) if len(values) > 5 and values[5] else 0.0
                }

        # === ПОЛЕ 1: ID ===
        id_frame = ttk.Frame(main_frame); id_frame.pack(fill=tk.X, pady=5)
        ttk.Label(id_frame, text="ID компонента:", width=20).pack(side=tk.LEFT)
        id_var = tk.StringVar(value=current_data['dough_id'] if current_data else '')
        id_entry = ttk.Entry(id_frame, textvariable=id_var, width=20)
        id_entry.pack(side=tk.LEFT, padx=5)
        if mode == 'edit': id_entry.config(state='readonly')

        # === ПОЛЕ 2: Название ===
        name_frame = ttk.Frame(main_frame); name_frame.pack(fill=tk.X, pady=5)
        ttk.Label(name_frame, text="Название:", width=20).pack(side=tk.LEFT)
        name_var = tk.StringVar(value=current_data['name'] if current_data else '')
        name_entry = ttk.Entry(name_frame, textvariable=name_var, width=40)
        name_entry.pack(side=tk.LEFT, padx=5)

        # === ПОЛЕ 3: Партия ===
        batch_frame = ttk.Frame(main_frame); batch_frame.pack(fill=tk.X, pady=5)
        ttk.Label(batch_frame, text="Партия:", width=20).pack(side=tk.LEFT)
        batch_var = tk.DoubleVar(value=current_data['batch_size'] if current_data else 10.0)
        batch_spin = ttk.Spinbox(batch_frame, from_=0.1, to=100000, increment=1, textvariable=batch_var, width=15)
        batch_spin.pack(side=tk.LEFT, padx=5)
        self.setup_comma_to_dot(batch_spin)

        # === ПОЛЕ 4: Единица ===
        unit_frame = ttk.Frame(main_frame); unit_frame.pack(fill=tk.X, pady=5)
        ttk.Label(unit_frame, text="Единица:", width=20).pack(side=tk.LEFT)
        unit_var = tk.StringVar(value=current_data['unit'] if current_data else 'лист')
        unit_combo = ttk.Combobox(unit_frame, textvariable=unit_var, values=['гр', 'кг', 'л', 'мл', 'шт', 'лист'], width=15)
        unit_combo.pack(side=tk.LEFT, padx=5)

        # === ПОЛЕ 5: Ресурс ===
        res_frame = ttk.Frame(main_frame); res_frame.pack(fill=tk.X, pady=5)
        ttk.Label(res_frame, text="Ресурс:", width=20).pack(side=tk.LEFT)
        
        # Загружаем ресурсы из кэша
        res_list = []
        res_map = {}
        if hasattr(self, 'all_resources_cache'):
            for r in self.all_resources_cache:
                res_list.append(r['resource_name'])
                res_map[r['resource_name']] = r['resource_id']
        
        res_var = tk.StringVar(value=current_data['resource_name'] if current_data else '')
        if not res_var.get() and res_list: res_var.set(res_list[0])
        
        res_combo = ttk.Combobox(res_frame, textvariable=res_var, values=res_list, width=30)
        res_combo.pack(side=tk.LEFT, padx=5)

        # === ПОЛЕ 6: Время ===
        time_frame = ttk.Frame(main_frame); time_frame.pack(fill=tk.X, pady=5)
        ttk.Label(time_frame, text="Время (мин):", width=20).pack(side=tk.LEFT)
        time_var = tk.DoubleVar(value=current_data.get('production_time_min', 60.0) if current_data else 60.0)
        time_spin = ttk.Spinbox(time_frame, from_=0, to=999, increment=5, textvariable=time_var, width=15)
        time_spin.pack(side=tk.LEFT, padx=5)

        # === СОСТАВ (BOM) ===
        comp_frame = ttk.LabelFrame(main_frame, text="Состав (вложенные компоненты)", padding=10)
        comp_frame.pack(fill=tk.BOTH, expand=True, pady=10)
        
        comp_tree = ttk.Treeview(comp_frame, columns=('ID', 'Name', 'Qty', 'Unit'), show='headings', height=5)
        comp_tree.heading('ID', text='ID'); comp_tree.column('ID', width=80)
        comp_tree.heading('Name', text='Название'); comp_tree.column('Name', width=200)
        comp_tree.heading('Qty', text='Кол-во'); comp_tree.column('Qty', width=80)
        comp_tree.heading('Unit', text='Ед.'); comp_tree.column('Unit', width=60)
        comp_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        
        # Скроллбар для состава
        comp_scroll = ttk.Scrollbar(comp_frame, orient="vertical", command=comp_tree.yview)
        comp_tree.configure(yscrollcommand=comp_scroll.set)
        comp_scroll.pack(side=tk.RIGHT, fill=tk.Y)

        # Загрузка состава с сервера
        if mode == 'edit' and current_data:
            self.send_ws_message({'type': 'get_dough_composition', 'dough_id': current_data['dough_id']})
            def load_comp():
                if hasattr(self, 'dough_composition_cache') and current_data['dough_id'] in self.dough_composition_cache:
                    comp_tree.delete(*comp_tree.get_children())
                    for c in self.dough_composition_cache[current_data['dough_id']]:
                        comp_tree.insert('', tk.END, values=(c['child_dough_id'], c['child_name'], c['quantity'], c['unit']))
                else:
                    dialog.after(100, load_comp)
            dialog.after(50, load_comp)

        # --- ФУНКЦИИ УПРАВЛЕНИЯ СОСТАВОМ ---
        def add_composition_component():
            add_win = tk.Toplevel(dialog)
            add_win.title("Добавить в состав")
            self.center_dialog(add_win, 400, 200)
            
            f = ttk.Frame(add_win, padding=10); f.pack(fill=tk.BOTH, expand=True)
            
            # Список доступных компонентов (кроме самого себя)
            avail_comps = []
            if hasattr(self, 'all_dough_data'):
                self_id = id_var.get()
                avail_comps = [f"{d['dough_id']} | {d['name']}" for d in self.all_dough_data if d['dough_id'] != self_id]
            
            ttk.Label(f, text="Компонент:").pack(anchor='w')
            c_var = tk.StringVar()
            c_combo = ttk.Combobox(f, textvariable=c_var, values=avail_comps, width=40)
            c_combo.pack(fill=tk.X, pady=5)
            
            ttk.Label(f, text="Количество:").pack(anchor='w')
            q_var = tk.DoubleVar(value=1.0)
            q_spin = ttk.Spinbox(f, from_=0.001, to=1000, textvariable=q_var)
            q_spin.pack(fill=tk.X, pady=5)
            
            def confirm_add():
                val = c_var.get()
                if not val: return
                cid = val.split(' | ')[0]
                cname = val.split(' | ')[1] if ' | ' in val else val
                # Ищем единицу измерения выбранного компонента
                cunit = 'кг'
                if hasattr(self, 'all_dough_data'):
                     found = next((d for d in self.all_dough_data if d['dough_id'] == cid), None)
                     if found: cunit = found.get('unit', 'кг')

                comp_tree.insert('', tk.END, values=(cid, cname, q_var.get(), cunit))
                add_win.destroy()
                
            ttk.Button(f, text="Добавить", command=confirm_add).pack(pady=10)

        def remove_composition_component():
            sel = comp_tree.selection()
            if sel: comp_tree.delete(sel[0])

        # --- КНОПКИ УПРАВЛЕНИЯ СОСТАВОМ (ВОТ ЭТОГО НЕ ХВАТАЛО) ---
        comp_buttons = ttk.Frame(main_frame)  # <--- Создаем фрейм
        comp_buttons.pack(fill=tk.X, pady=5)  # <--- Размещаем его

        ttk.Button(comp_buttons, text="➕ Добавить компонент", command=add_composition_component).pack(side=tk.LEFT, padx=5)
        ttk.Button(comp_buttons, text="➖ Удалить", command=remove_composition_component).pack(side=tk.LEFT, padx=5)

        # === ГЛАВНЫЕ КНОПКИ СОХРАНЕНИЯ ===
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=20)

        def save():
            did = id_var.get().strip()
            if not did: return
            
            comps = []
            for i in comp_tree.get_children():
                vals = comp_tree.item(i)['values']
                comps.append({'child_dough_id': str(vals[0]), 'child_name': str(vals[1]), 'quantity': float(vals[2]), 'unit': str(vals[3])})

            self.send_ws_message({
                'type': 'save_dough_type',
                'dough_id': did,
                'name': name_var.get(),
                'batch_size': batch_var.get(),
                'unit': unit_var.get(),
                'workshop': 'Основной цех',
                'resource_id': res_map.get(res_var.get(), 1),
                'production_time_min': time_var.get(),
                'composition': comps
            })
            dialog.destroy()

        ttk.Button(btn_frame, text="💾 Сохранить", command=save, style="Accent.TButton").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Отмена", command=dialog.destroy).pack(side=tk.LEFT, padx=5)

        # Фокус
        if mode == 'add': id_entry.focus()
        else: name_entry.focus()

    def manage_categories_dialog(self, category_combo=None):
        """Диалог управления категориями тортов (ИСПРАВЛЕННЫЙ И ПОЛНЫЙ)"""
        dialog = tk.Toplevel(self)
        dialog.title("Управление категориями")
        dialog.transient(self)
        dialog.grab_set()

        self.center_dialog(dialog, 500, 450)

        main_frame = ttk.Frame(dialog, padding=15)
        main_frame.pack(fill=tk.BOTH, expand=True)

        # Инструкция
        ttk.Label(main_frame, text="Категории тортов", font=("Arial", 11, "bold")).pack(pady=(0, 10))
        ttk.Label(main_frame, text="Удаляйте старые или добавляйте новые категории.", font=("Arial", 8), foreground="gray").pack()
        
        # Список категорий
        list_frame = ttk.Frame(main_frame)
        list_frame.pack(fill=tk.BOTH, expand=True, pady=5)

        cat_listbox = tk.Listbox(list_frame, height=10, selectmode=tk.SINGLE)
        cat_listbox.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        scrollbar = ttk.Scrollbar(list_frame, orient=tk.VERTICAL, command=cat_listbox.yview)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        cat_listbox.configure(yscrollcommand=scrollbar.set)

        # --- ЗАГРУЗКА И ОЧИСТКА ---
        # Загружаем из кэша или создаем дефолтный
        if not hasattr(self, 'cached_categories') or not self.cached_categories:
             self.cached_categories = ['Biskuit', 'Medowik', 'Kleingebäck', 'Dekoration', 'Sonstiges']
        
        # Очищаем список от "None", пустых строк и дубликатов
        clean_list = []
        seen = set()
        for c in self.cached_categories:
            s_val = str(c).strip()
            if s_val and s_val.lower() != 'none' and s_val not in seen:
                clean_list.append(s_val)
                seen.add(s_val)
        
        self.cached_categories = sorted(clean_list)

        # Заполняем Listbox
        for cat in self.cached_categories:
            cat_listbox.insert(tk.END, cat)

        # Поле ввода новой категории
        input_frame = ttk.Frame(main_frame)
        input_frame.pack(fill=tk.X, pady=10)

        ttk.Label(input_frame, text="Новая категория:").pack(side=tk.LEFT, padx=(0, 5))
        new_cat_var = tk.StringVar()
        new_cat_entry = ttk.Entry(input_frame, textvariable=new_cat_var, width=25)
        new_cat_entry.pack(side=tk.LEFT, padx=5)

        # --- ФУНКЦИЯ ДОБАВЛЕНИЯ ---
        def add_category():
            cat = new_cat_var.get().strip()
            if not cat:
                messagebox.showwarning("Ошибка", "Введите название категории")
                return

            # Проверка на дубликаты (без учета регистра)
            for c in self.cached_categories:
                if c.lower() == cat.lower():
                    messagebox.showwarning("Ошибка", "Такая категория уже есть")
                    return

            # 1. Добавляем в локальный список
            self.cached_categories.append(cat)
            self.cached_categories.sort()
            
            # 2. Обновляем визуальный список в этом окне
            cat_listbox.delete(0, tk.END)
            for c in self.cached_categories:
                cat_listbox.insert(tk.END, c)
            
            new_cat_var.set('')

            # 3. ВАЖНО: Обновляем выпадающий список в окне рецепта
            if category_combo:
                category_combo['values'] = self.cached_categories
                # Если в поле было пусто, ставим новую категорию
                if not category_combo.get():
                    category_combo.set(cat)

            # 4. Отправляем на сервер для сохранения в БД
            if hasattr(self, 'send_ws_message'):
                self.send_ws_message({
                    'type': 'add_category',
                    'category_id': cat,   # Используем имя как ID
                    'category_name': cat,
                    'workshop_name': 'Основной цех'
                })

        # --- ФУНКЦИЯ УДАЛЕНИЯ ---
        def remove_category():
            selection = cat_listbox.curselection()
            if not selection:
                messagebox.showwarning("Ошибка", "Выберите категорию для удаления")
                return

            cat = cat_listbox.get(selection[0])
            
            # Удаляем (без лишних вопросов про стандартные)
            if messagebox.askyesno("Удаление", f"Удалить категорию '{cat}'?"):
                if cat in self.cached_categories:
                    self.cached_categories.remove(cat)
                
                cat_listbox.delete(selection[0])

                # Обновляем выпадающий список в окне рецепта
                if category_combo:
                    category_combo['values'] = self.cached_categories
                    # Если удаленная категория была выбрана, сбрасываем
                    if category_combo.get() == cat:
                        category_combo.set('')

                # Отправляем на сервер команду удаления
                if hasattr(self, 'send_ws_message'):
                    self.send_ws_message({
                        'type': 'delete_category',
                        'category_id': cat
                    })

        ttk.Button(input_frame, text="➕ Добавить", command=add_category).pack(side=tk.LEFT, padx=2)
        ttk.Button(input_frame, text="🗑️ Удалить", command=remove_category).pack(side=tk.LEFT, padx=2)

        # Кнопка закрытия
        ttk.Button(main_frame, text="✅ Готово", command=dialog.destroy).pack(pady=10)

    def on_recipe_select(self, event):
        """Клик по торту: сохраняем данные выделенного рецепта для действий."""
        sel = self.recipe_tree.selection()
        if not sel:
            return

        values = self.recipe_tree.item(sel[0], 'values')
        if not values:
            return

        art_nr = str(values[0]).strip()
        if art_nr.isdigit() and len(art_nr) < 5:
            art_nr = art_nr.zfill(5)

        self.rec_art_var.set(art_nr)
        self.rec_name_var.set(str(values[1]))

        found_recipe = None
        if hasattr(self, 'all_recipes_data'):
            for recipe in self.all_recipes_data:
                recipe_art = str(recipe.get('article_nr', '')).strip().zfill(5)
                if recipe_art == art_nr:
                    found_recipe = recipe
                    break

        self.selected_recipe_data = found_recipe or {}
        self.rec_category_var.set((found_recipe or {}).get('category') or '')
        self.rec_items_tray_var.set(float((found_recipe or {}).get('items_per_tray', 1.0)))
        self.rec_pack_var.set((found_recipe or {}).get('packaging_unit_id') or '')
        self.rec_active_var.set((found_recipe or {}).get('active', 1) == 1)

    def create_new_recipe(self):
        """Создать новый рецепт"""
        # Диалог ввода номера артикля
        dialog = tk.Toplevel(self)
        dialog.title("Создать новый рецепт")
        dialog.transient(self)
        dialog.grab_set()

        # Центрировать окно
        self.center_dialog(dialog, 500, 220)

        frame = ttk.Frame(dialog, padding=20)
        frame.pack(fill=tk.BOTH, expand=True)

        ttk.Label(frame, text="Артикул (5 цифр):").pack(anchor='w', pady=5)
        art_var = tk.StringVar()
        art_entry = ttk.Entry(frame, textvariable=art_var, width=20)
        art_entry.pack(fill=tk.X, pady=5)
        art_entry.focus()

        ttk.Label(frame, text="Название:").pack(anchor='w', pady=5)
        name_var = tk.StringVar()
        name_entry = ttk.Entry(frame, textvariable=name_var, width=40)
        name_entry.pack(fill=tk.X, pady=5)

        def create():
            art = art_var.get().strip()
            name = name_var.get().strip()

            if not art or not name:
                messagebox.showwarning("Ошибка", "Заполните артикул и название!")
                return

            # Нормализуем артикул
            if art.isdigit() and len(art) < 5:
                art = art.zfill(5)

            default_dough_id = ''
            if hasattr(self, 'all_dough_data') and self.all_dough_data:
                default_dough_id = str(self.all_dough_data[0].get('dough_id', ''))

            if not default_dough_id:
                messagebox.showwarning("Ошибка", "Нет доступных компонентов. Сначала добавьте компонент в справочник.")
                return

            self.admin_save_recipe(
                art,
                name,
                default_dough_id,
                1.0,
                '',
                'Biskuit',
                1
            )

            dialog.destroy()
            messagebox.showinfo("Готово", f"Торт {art} создан. Откройте редактирование для настройки состава.")

            self.after(500, self.admin_request_recipes)

        btn_frame = ttk.Frame(frame)
        btn_frame.pack(pady=10)
        ttk.Button(btn_frame, text="✓ Создать", command=create).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✗ Отмена", command=dialog.destroy).pack(side=tk.LEFT, padx=5)

    def save_current_recipe(self):
        """Сохранение из списка отключено: используйте окно редактирования."""
        self.open_recipe_editor_window()

    def delete_current_recipe(self):
        """Удалить выбранный рецепт"""
        selection = self.recipe_tree.selection()
        if not selection:
            messagebox.showwarning("Удаление", "Выберите рецепт для удаления")
            return

        values = self.recipe_tree.item(selection[0], 'values')
        if not values:
            messagebox.showwarning("Удаление", "Выберите рецепт для удаления")
            return

        article_nr = str(values[0]).strip()
        if not article_nr:
            messagebox.showwarning("Удаление", "Выберите рецепт для удаления")
            return

        # Нормализовать артикул
        if article_nr.isdigit() and len(article_nr) < 5:
            article_nr = article_nr.zfill(5)

        recipe_name = str(values[1]) if len(values) > 1 else ''
        if not messagebox.askyesno("Удаление", f"Удалить рецепт '{recipe_name}' (арт. {article_nr})?"):
            return

        # Отправить запрос на удаление
        self.send_ws_message({
            'type': 'delete_recipe',
            'article_nr': article_nr
        })

    def open_recipe_editor_window(self, event=None):
        """Открыть расширенное окно редактирования артикля"""
        selection = self.recipe_tree.selection()
        if not selection:
            return

        # Получить данные выбранного рецепта
        item = self.recipe_tree.item(selection[0])
        values = item['values']
        if not values:
            return

        article_nr = str(values[0]).strip()
        # Нормализовать артикул с ведущими нулями
        if article_nr.isdigit() and len(article_nr) < 5:
            article_nr = article_nr.zfill(5)

        # Создать окно редактирования
        editor_win = tk.Toplevel(self)
        editor_win.title(f"Редактирование артикля {article_nr}")
        editor_win.transient(self)
        editor_win.grab_set()

        # Получить размер экрана и установить разумный размер окна
        screen_height = self.winfo_screenheight()
        screen_width = self.winfo_screenwidth()

        # Использовать 90% высоты экрана, но не более 1000px
        window_height = min(int(screen_height * 0.9), 1000)
        window_width = min(int(screen_width * 0.5), 900)

        # Центрировать окно
        self.center_dialog(editor_win, window_width, window_height)

        # Разрешить изменение размера
        editor_win.resizable(True, True)

        # Создаём Canvas с прокруткой для содержимого
        canvas = tk.Canvas(editor_win, highlightthickness=0)
        scrollbar = ttk.Scrollbar(editor_win, orient="vertical", command=canvas.yview)
        scrollable_frame = ttk.Frame(canvas, padding=10)

        scrollable_frame.bind(
            "<Configure>",
            lambda _: canvas.configure(scrollregion=canvas.bbox("all"))
        )

        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)

        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")

        # Привязать прокрутку колесиком мыши (только для этого окна)
        def _on_mousewheel(event):
            try:
                # Проверяем что canvas еще существует
                if canvas.winfo_exists():
                    canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
            except Exception:
                pass  # Игнорируем ошибки если canvas уже удален

        def _bind_mousewheel(_):
            try:
                if canvas.winfo_exists():
                    canvas.bind_all("<MouseWheel>", _on_mousewheel)
            except Exception:
                pass

        def _unbind_mousewheel(_):
            try:
                canvas.unbind_all("<MouseWheel>")
            except Exception:
                pass

        canvas.bind("<Enter>", _bind_mousewheel)
        canvas.bind("<Leave>", _unbind_mousewheel)

        # Используем scrollable_frame вместо main_frame
        main_frame = scrollable_frame

        # === ЗАГРУЗИТЬ ДАННЫЕ РЕЦЕПТА (СНАЧАЛА!) ===
        current_recipe = None
        if hasattr(self, 'all_recipes_data'):
            for r in self.all_recipes_data:
                r_art = str(r['article_nr']).strip().zfill(5)
                if r_art == article_nr:
                    current_recipe = r
                    break

        # === СЕКЦИЯ 1: Основная информация ===
        info_frame = ttk.LabelFrame(main_frame, text="📋 Основная информация", padding=10)
        info_frame.pack(fill=tk.X, pady=5)

        # Номер артикля
        ttk.Label(info_frame, text="Номер артикля:").grid(row=0, column=0, sticky='w', pady=5)
        art_nr_var = tk.StringVar(value=article_nr)
        ttk.Entry(info_frame, textvariable=art_nr_var, state='readonly', width=20).grid(row=0, column=1, sticky='we', padx=5)

        # Название
        ttk.Label(info_frame, text="Название:").grid(row=1, column=0, sticky='w', pady=5)
        name_var = tk.StringVar(value=current_recipe.get('name', '') if current_recipe else '')
        ttk.Entry(info_frame, textvariable=name_var, width=40).grid(row=1, column=1, sticky='we', padx=5)

        # Категория
        ttk.Label(info_frame, text="Категория:").grid(row=2, column=0, sticky='w', pady=5)
        current_cat = current_recipe.get('category', '') if current_recipe else ''
        category_var = tk.StringVar(value=current_cat)

        # Получить список категорий из базы
        if hasattr(self, 'cached_categories') and self.cached_categories:
            cats = list(self.cached_categories)
        else:
            cats = []

        # Добавить текущую категорию в список, если её там нет (для совместимости)
        if current_cat and current_cat not in cats:
            cats.insert(0, current_cat)

        cat_frame = ttk.Frame(info_frame)
        cat_frame.grid(row=2, column=1, sticky='we', padx=5)

        category_combo = ttk.Combobox(cat_frame, textvariable=category_var, values=cats, width=25)
        category_combo.pack(side=tk.LEFT, fill=tk.X, expand=True)

        # Кнопка управления категориями
        ttk.Button(cat_frame, text="⚙️", width=3, command=lambda: self.manage_categories_dialog(category_combo)).pack(side=tk.LEFT, padx=(2, 0))

        # Активность артикула (производится или нет)
        active_var = tk.BooleanVar(value=True)  # По умолчанию активен
        if current_recipe:
            active_var.set(current_recipe.get('active', 1) == 1)
        ttk.Checkbutton(info_frame, text="✓ Активен (производится)", variable=active_var).grid(row=3, column=0, columnspan=2, sticky='w', pady=5)
        freeze_var = tk.BooleanVar(value=False)
        if current_recipe:
            freeze_var.set(str(current_recipe.get('freeze_mode', '') or '').strip().lower() == 'tiefkuhle')
        ttk.Checkbutton(info_frame, text="✓ Заморозка (Tiefkuhle)", variable=freeze_var).grid(row=4, column=0, columnspan=2, sticky='w', pady=2)

        info_frame.columnconfigure(1, weight=1)

        # === СЕКЦИЯ: Регионы активности артикула ===
        regions_frame = ttk.LabelFrame(main_frame, text="🌍 Активные регионы поставки", padding=10)
        regions_frame.pack(fill=tk.X, pady=5)

        saved_regions = self._parse_active_regions(current_recipe.get('active_regions') if current_recipe else None)
        if not saved_regions:
            saved_regions = self._get_active_regions_for_article(article_nr)
        if not saved_regions:
            saved_regions = list(self.KNOWN_REGIONS)

        region_vars = {}
        for idx, region in enumerate(self.KNOWN_REGIONS):
            region_vars[region] = tk.BooleanVar(value=(region in saved_regions))
            ttk.Checkbutton(regions_frame, text=region, variable=region_vars[region]).grid(
                row=idx // 3, column=idx % 3, sticky='w', padx=6, pady=2
            )

        all_regions_var = tk.BooleanVar(value=all(v.get() for v in region_vars.values()))

        def _toggle_all_regions():
            val = all_regions_var.get()
            for rv in region_vars.values():
                rv.set(val)

        ttk.Checkbutton(
            regions_frame,
            text="Все регионы",
            variable=all_regions_var,
            command=_toggle_all_regions
        ).grid(row=2, column=0, columnspan=3, sticky='w', padx=6, pady=(6, 2))

        # === СЕКЦИЯ 2: Производственные параметры ===
        production_frame = ttk.LabelFrame(main_frame, text="⚙️ Производственные параметры", padding=10)
        production_frame.pack(fill=tk.X, pady=5)

        # Штук на листе
        ttk.Label(production_frame, text="Штук на листе/противне:").grid(row=0, column=0, sticky='w', pady=5)
        items_per_tray_var = tk.DoubleVar(value=1.0)
        if current_recipe:
            items_per_tray_var.set(float(current_recipe.get('items_per_tray', 1.0)))
        items_per_tray_spin = ttk.Spinbox(production_frame, from_=0.1, to=1000, increment=0.5, textvariable=items_per_tray_var, width=15)
        items_per_tray_spin.grid(row=0, column=1, sticky='w', padx=5)
        self.setup_comma_to_dot(items_per_tray_spin)

        # Минимальная партия
        ttk.Label(production_frame, text="Минимальная партия (шт):").grid(row=1, column=0, sticky='w', pady=5)
        min_batch_size_var = tk.IntVar(value=1)
        if current_recipe:
            min_batch_size_var.set(int(current_recipe.get('min_batch_size', 1)))
        min_batch_size_spin = ttk.Spinbox(production_frame, from_=1, to=1000, increment=1, textvariable=min_batch_size_var, width=15)
        min_batch_size_spin.grid(row=1, column=1, sticky='w', padx=5)

        # Подсказка для минимальной партии
