    def _sales_create_report_tree(self, parent, columns, headers):
        wrap = ttk.Frame(parent)
        wrap.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)
        tree = ttk.Treeview(wrap, columns=columns, show='headings')
        for col, title in zip(columns, headers):
            tree.heading(col, text=title, command=lambda c=col, t=tree: self._sales_tree_sort_column(t, c))
            tree.column(col, width=140, anchor='e' if col in ('sum',) else 'center')
        if 'name' in columns or 'client' in columns or 'category' in columns:
            for txt_col in ('name', 'client', 'category'):
                if txt_col in columns:
                    tree.column(txt_col, width=260, anchor='w')
        scroll = ttk.Scrollbar(wrap, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscrollcommand=scroll.set)
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)
        return tree

    def _sales_sort_value(self, raw):
        s = str(raw or '').strip()
        if not s:
            return (2, '')
        # Date YYYY-MM-DD
        try:
            return (0, datetime.strptime(s, '%Y-%m-%d'))
        except Exception:
            pass
        # Number
        cleaned = s.replace('€', '').replace(' ', '').replace(',', '.')
        cleaned = ''.join(ch for ch in cleaned if ch.isdigit() or ch in '.-')
        try:
            return (0, float(cleaned))
        except Exception:
            pass
        return (1, s.lower())

    def _tree_sort_value(self, raw):
        """Универсальный ключ сортировки для Treeview (числа/даты/текст)."""
        s = str(raw or '').strip()
        if not s or s in ('—', '-', 'None'):
            return (3, '')
        for fmt in ('%Y-%m-%d', '%d.%m.%Y', '%d.%m.%y'):
            try:
                return (0, datetime.strptime(s, fmt))
            except Exception:
                pass
        cleaned = s.replace('\xa0', ' ').replace('€', '').replace('%', '').replace(' ', '').replace(',', '.')
        cleaned = ''.join(ch for ch in cleaned if ch.isdigit() or ch in '.-')
        if cleaned not in ('', '-', '.'):
            try:
                return (1, float(cleaned))
            except Exception:
                pass
        return (2, s.lower())

    def _enable_treeview_sorting(self, tree, columns=None):
        """Включить сортировку по клику на заголовок колонок таблицы."""
        if not tree or not tree.winfo_exists():
            return
        target_columns = list(columns or tree['columns'] or [])
        if not target_columns:
            return
        titles = getattr(tree, '_heading_titles', {})
        for col in target_columns:
            current_title = str(tree.heading(col, 'text') or '').strip().rstrip(' ▲▼')
            titles[col] = current_title
            tree.heading(col, text=current_title, command=lambda c=col, t=tree: self._treeview_sort_column(t, c))
        tree._heading_titles = titles
        if not hasattr(tree, '_sort_state'):
            tree._sort_state = {'column': None, 'desc': False}

    def _treeview_sort_column(self, tree, col):
        if not tree or not tree.winfo_exists():
            return
        items = list(tree.get_children(''))
        if not items:
            return
        state = getattr(tree, '_sort_state', {'column': None, 'desc': False})
        prev_col = state.get('column')
        prev_desc = bool(state.get('desc', False))
        desc = (not prev_desc) if prev_col == col else False

        try:
            idx = tree['columns'].index(col)
        except Exception:
            return

        decorated = []
        for iid in items:
            vals = tree.item(iid, 'values') or []
            raw = vals[idx] if idx < len(vals) else ''
            decorated.append((self._tree_sort_value(raw), iid))
        decorated.sort(key=lambda x: x[0], reverse=desc)
        for pos, (_, iid) in enumerate(decorated):
            tree.move(iid, '', pos)

        tree._sort_state = {'column': col, 'desc': desc}
        titles = getattr(tree, '_heading_titles', {})
        for c in tree['columns']:
            base = str(titles.get(c) or tree.heading(c, 'text') or '').strip().rstrip(' ▲▼')
            if c == col:
                arrow = '▼' if desc else '▲'
                tree.heading(c, text=f"{base} {arrow}")
            else:
                tree.heading(c, text=base)

    def _sales_tree_sort_column(self, tree, col):
        self._treeview_sort_column(tree, col)

    def _sales_set_period(self, key):
        self.sales_period_key.set(key)
        self.sales_refresh_dashboard()

    def _sales_reset_report_filters(self):
        self.sales_filter_from.set_date(datetime.now() - timedelta(days=30))
        self.sales_filter_to.set_date(datetime.now())
        self.sales_client_q.set('')
        self.sales_article_q.set('')
        self.sales_category_q.set('')
        self.sales_refresh_reports()

    def _sales_clear_filter_field(self, field_key):
        if field_key == 'client' and hasattr(self, 'sales_client_q'):
            self.sales_client_q.set('')
        elif field_key == 'article' and hasattr(self, 'sales_article_q'):
            self.sales_article_q.set('')
        elif field_key == 'category' and hasattr(self, 'sales_category_q'):
            self.sales_category_q.set('')
        self.sales_refresh_reports()

    def _sales_typeahead(self, field_key):
        combo_map = {
            'client': ('sales_client_combo', 'sales_client_q'),
            'article': ('sales_article_combo', 'sales_article_q'),
            'category': ('sales_category_combo', 'sales_category_q')
        }
        combo_attr, var_attr = combo_map.get(field_key, (None, None))
        if not combo_attr or not hasattr(self, combo_attr) or not hasattr(self, var_attr):
            return
        combo = getattr(self, combo_attr)
        query = str(getattr(self, var_attr).get() or '').strip().lower()
        base = list((getattr(self, 'sales_filter_values', {}) or {}).get(field_key, []))
        vals = [v for v in base if query in str(v).lower()] if query else base
        combo.configure(values=vals[:300])

    def _sales_update_filter_values(self, rows, order_rows):
        clients = sorted({str(o.get('client', '')).strip() for o in order_rows if str(o.get('client', '')).strip()})
        articles = sorted({str(r.get('article', '')).strip() for r in rows if str(r.get('article', '')).strip()})
        categories = sorted({str(r.get('category', '')).strip() for r in rows if str(r.get('category', '')).strip()})
        self.sales_filter_values = {'client': clients, 'article': articles, 'category': categories}
        if hasattr(self, 'sales_client_combo'):
            self.sales_client_combo.configure(values=clients)
        if hasattr(self, 'sales_article_combo'):
            self.sales_article_combo.configure(values=articles)
        if hasattr(self, 'sales_category_combo'):
            self.sales_category_combo.configure(values=categories)

    def _sales_to_float(self, raw):
        if raw is None:
            return 0.0
        if isinstance(raw, (int, float)):
            return float(raw)
        s = str(raw).strip().replace('€', '').replace(' ', '').replace(',', '.')
        cleaned = ''.join(ch for ch in s if ch.isdigit() or ch in '.-')
        try:
            return float(cleaned) if cleaned not in ('', '-', '.', '-.') else 0.0
        except Exception:
            return 0.0

    def _sales_parse_date(self, s):
        try:
            return datetime.strptime(str(s), '%Y-%m-%d').date()
        except Exception:
            return None

    def _sales_order_is_done(self, data):
        return bool(data.get('printed')) or str(data.get('status', '')).lower() == 'completed'

    def _sales_period_bounds(self):
        today = datetime.now().date()
        key = self.sales_period_key.get() if hasattr(self, 'sales_period_key') else 'today'
        if key == '5days':
            return today - timedelta(days=4), today
        if key == 'week':
            return today - timedelta(days=6), today
        if key == 'month':
            return today.replace(day=1), today
        return today, today

    def _sales_recipe_categories(self):
        rec_map = {}
        for r in getattr(self, 'all_recipes_data', []) or []:
            art = str(r.get('article_nr', '')).strip()
            if art.isdigit():
                art = art.zfill(5)
            rec_map[art] = {
                'category': str(r.get('category', '') or ''),
                'unit_price': self._sales_to_float(r.get('unit_price'))
            }
        return rec_map

    def _normalize_article_nr(self, value):
        raw = str(value or '').strip().replace(' ', '').replace(',', '')
        if '.' in raw and raw.replace('.', '').isdigit():
            raw = raw.split('.', 1)[0]
        return raw.zfill(5) if raw.isdigit() else raw

    def _is_recipe_active(self, recipe_row):
        v = recipe_row.get('active', 1)
        if isinstance(v, bool):
            return v
        s = str(v).strip().lower()
        if s in ('0', 'false', 'off', 'inactive', 'no'):
            return False
        return True

    def _is_article_active_for_plans(self, article_nr) -> bool:
        """
        True: артикул можно показывать в планах.
        False: артикул явно неактивен в карточке товара.
        """
        norm = self._normalize_article_nr(article_nr)
        recipes = list(getattr(self, 'all_recipes_data', []) or [])
        if not recipes:
            # Если справочник еще не загружен, не скрываем позиции "вслепую".
            return True
        for r in recipes:
            r_art = self._normalize_article_nr(r.get('article_nr', ''))
            if r_art == norm:
                return self._is_recipe_active(r)
        # Если артикула нет в справочнике рецептов - не режем данные.
        return True

    def _filter_inactive_articles_for_plans(self, rows):
        return [r for r in (rows or []) if self._is_article_active_for_plans(r.get('article_nr', ''))]

    def _sales_collect(self, date_from=None, date_to=None, client_q='', article_q='', category_q=''):
        rec_cat = self._sales_recipe_categories()
        rows = []
        order_rows = []
        for oid, info in (getattr(self, 'orders', {}) or {}).items():
            data = info.get('data', info)
            if not isinstance(data, dict) or not self._sales_order_is_done(data):
                continue
            dd = self._sales_parse_date(data.get('delivery_date'))
            if not dd:
                continue
            if date_from and dd < date_from:
                continue
            if date_to and dd > date_to:
                continue

            client = str(data.get('kunde', '') or '')
            order_total = self._sales_to_float(data.get('total_value')) or self._sales_to_float(data.get('summe')) or self._sales_to_float(data.get('total'))
            order_sum_from_items = 0.0

            for art in data.get('artikel', []) or []:
                art_nr_raw = str(art.get('artikel_nr') or art.get('nummer') or '').strip()
                art_nr = art_nr_raw.zfill(5) if art_nr_raw.isdigit() else art_nr_raw
                art_name = str(art.get('name') or art.get('beschreibung') or '')
                qty = self._sales_to_float(art.get('menge'))
                rec_info = rec_cat.get(art_nr, {}) if isinstance(rec_cat.get(art_nr, {}), dict) else {}
                price = (
                    self._sales_to_float(art.get('unit_price'))
                    or self._sales_to_float(art.get('preis'))
                    or self._sales_to_float(art.get('price'))
                    or self._sales_to_float(art.get('einzelpreis'))
                    or self._sales_to_float(rec_info.get('unit_price'))
                )
                amount = qty * price if price > 0 else 0.0
                order_sum_from_items += amount
                category = rec_info.get('category', '') if isinstance(rec_info, dict) else ''
                rows.append({
                    'order_id': oid,
                    'date': dd,
                    'client': client,
                    'article': art_nr,
                    'name': art_name,
                    'category': category,
                    'qty': qty,
                    'sum': amount
                })
            if order_total <= 0 and order_sum_from_items > 0:
                order_total = order_sum_from_items
            order_rows.append({'order_id': oid, 'date': dd, 'client': client, 'sum': order_total})

        cq = client_q.strip().lower()
        aq = article_q.strip().lower()
        gq = category_q.strip().lower()
        if cq or aq or gq:
            filtered_rows = []
            allowed_orders = set()
            for r in rows:
                if cq and cq not in r['client'].lower():
                    continue
                if aq and aq not in str(r['article']).lower() and aq not in r['name'].lower():
                    continue
                if gq and gq not in r['category'].lower():
                    continue
                filtered_rows.append(r)
                allowed_orders.add(r['order_id'])
            rows = filtered_rows
            order_rows = [o for o in order_rows if o['order_id'] in allowed_orders]
        return rows, order_rows

    def sales_refresh_all(self):
        self.sales_refresh_dashboard()
        self.sales_refresh_reports()

    def sales_refresh_dashboard(self):
        if not hasattr(self, 'sales_figure'):
            return
        d_from, d_to = self._sales_period_bounds()
        rows, order_rows = self._sales_collect(d_from, d_to)
        month_start = datetime.now().date().replace(day=1)
        _, month_orders = self._sales_collect(month_start, datetime.now().date())

        sales_cnt = len({o['order_id'] for o in order_rows})
        sales_sum = sum(o['sum'] for o in order_rows)
        month_cnt = len({o['order_id'] for o in month_orders})
        month_sum = sum(o['sum'] for o in month_orders)

        waiting_orders = []
        for oid, info in (getattr(self, 'orders', {}) or {}).items():
            data = info.get('data', info)
            if not isinstance(data, dict):
                continue
            dd = self._sales_parse_date(data.get('delivery_date'))
            if not dd or not (d_from <= dd <= d_to):
                continue
            if not self._sales_order_is_done(data):
                waiting_orders.append(data)
        waiting_sum = sum(self._sales_to_float(o.get('total_value')) for o in waiting_orders)

        all_sales_orders = []
        for oid, info in (getattr(self, 'orders', {}) or {}).items():
            data = info.get('data', info)
            if isinstance(data, dict) and self._sales_order_is_done(data):
                dd = self._sales_parse_date(data.get('delivery_date'))
                if dd:
                    all_sales_orders.append((dd, str(data.get('kunde', '') or '')))
        first_sale_by_client = {}
        for dd, cl in sorted(all_sales_orders, key=lambda x: x[0]):
            if cl and cl not in first_sale_by_client:
                first_sale_by_client[cl] = dd
        new_clients = sum(1 for cl, fd in first_sale_by_client.items() if d_from <= fd <= d_to)

        def _set_kpi(key, v, s):
            if key in self.sales_kpi_widgets:
                self.sales_kpi_widgets[key][0].config(text=v)
                self.sales_kpi_widgets[key][1].config(text=s)
        _set_kpi('sales_today', str(sales_cnt), f"На сумму: {sales_sum:,.0f} €".replace(',', ' '))
        _set_kpi('sales_month', str(month_cnt), f"На сумму: {month_sum:,.0f} €".replace(',', ' '))
        _set_kpi('awaiting', str(len(waiting_orders)), f"На сумму: {waiting_sum:,.0f} €".replace(',', ' '))
        _set_kpi('new_clients', str(new_clients), "За период")

        # График: строим полный диапазон дней, включая нулевые дни.
        by_day = {}
        day_iter = d_from
        while day_iter <= d_to:
            by_day[day_iter] = {'sum': 0.0, 'count': 0}
            day_iter += timedelta(days=1)
        for o in order_rows:
            od = o['date']
            if od in by_day:
                by_day[od]['sum'] += o['sum']
                by_day[od]['count'] += 1
        x_dates = sorted(by_day.keys())
        x = [d.strftime('%d.%m') for d in x_dates]
        y_sum = [by_day[d]['sum'] for d in x_dates]
        y_cnt = [by_day[d]['count'] for d in x_dates]

        self.sales_figure.clear()
        ax = self.sales_figure.add_subplot(111)
        ax2 = ax.twinx()
        line1 = ax.plot(x, y_sum, color='#2563EB', marker='o', label='Выручка')
        line2 = ax2.plot(x, y_cnt, color='#22C55E', marker='o', label='Кол-во продаж')
        ax.grid(alpha=0.25)
        # Единая легенда из двух осей
        lines = line1 + line2
        labels = [ln.get_label() for ln in lines]
        ax.legend(lines, labels, loc='upper right')
        ax.set_ylabel('€')
        ax2.set_ylabel('шт')
        ax.tick_params(axis='x', labelrotation=0)
        self.sales_canvas.draw()

        # Топы
        prod = {}
        for r in rows:
            k = (r['article'], r['name'])
            if k not in prod:
                prod[k] = {'qty': 0.0, 'sum': 0.0}
            prod[k]['qty'] += r['qty']
            prod[k]['sum'] += r['sum']
        top_prod = sorted(prod.items(), key=lambda x: (x[1]['sum'], x[1]['qty']), reverse=True)[:10]

        clients = {}
        for o in order_rows:
            cl = o['client']
            if cl not in clients:
                clients[cl] = {'orders': 0, 'sum': 0.0}
            clients[cl]['orders'] += 1
            clients[cl]['sum'] += o['sum']
        top_clients = sorted(clients.items(), key=lambda x: x[1]['sum'], reverse=True)[:10]

        cats = {}
        for r in rows:
            cat = r['category'] or 'Без категории'
            if cat not in cats:
                cats[cat] = {'qty': 0.0, 'sum': 0.0}
            cats[cat]['qty'] += r['qty']
            cats[cat]['sum'] += r['sum']
        top_cats = sorted(cats.items(), key=lambda x: x[1]['sum'], reverse=True)[:10]

        for tree in (self.sales_top_products_tree, self.sales_top_clients_tree, self.sales_top_categories_tree):
            tree.delete(*tree.get_children())
        for (art, name), v in top_prod:
            title = f"{art} {name}".strip()
            self.sales_top_products_tree.insert('', tk.END, values=(title, int(v['qty']), f"{v['sum']:.0f}"))
        for cl, v in top_clients:
            self.sales_top_clients_tree.insert('', tk.END, values=(cl, v['orders'], f"{v['sum']:.0f}"))
        for cat, v in top_cats:
            self.sales_top_categories_tree.insert('', tk.END, values=(cat, int(v['qty']), f"{v['sum']:.0f}"))

    def sales_refresh_reports(self):
        if not hasattr(self, 'sales_by_client_tree'):
            return
        try:
            d_from = self.sales_filter_from.get_date()
            d_to = self.sales_filter_to.get_date()
        except Exception:
            d_from = datetime.now().date() - timedelta(days=30)
            d_to = datetime.now().date()
        rows_all, order_rows_all = self._sales_collect(d_from, d_to)
        self._sales_update_filter_values(rows_all, order_rows_all)
        rows, order_rows = self._sales_collect(
            d_from, d_to,
            client_q=self.sales_client_q.get() if hasattr(self, 'sales_client_q') else '',
            article_q=self.sales_article_q.get() if hasattr(self, 'sales_article_q') else '',
            category_q=self.sales_category_q.get() if hasattr(self, 'sales_category_q') else ''
        )

        for tree in (self.sales_by_client_tree, self.sales_by_article_tree, self.sales_by_category_tree, self.sales_by_period_tree):
            tree.delete(*tree.get_children())

        # По клиенту
        by_client = {}
        for o in order_rows:
            k = o['client']
            if k not in by_client:
                by_client[k] = {'orders': set(), 'qty': 0.0, 'sum': 0.0}
            by_client[k]['orders'].add(o['order_id'])
            by_client[k]['sum'] += o['sum']
        qty_by_order = {}
        for r in rows:
            qty_by_order.setdefault(r['order_id'], 0.0)
            qty_by_order[r['order_id']] += r['qty']
        for o in order_rows:
            by_client[o['client']]['qty'] += qty_by_order.get(o['order_id'], 0.0)
        for cl, v in sorted(by_client.items(), key=lambda x: x[1]['sum'], reverse=True):
            self.sales_by_client_tree.insert('', tk.END, values=(cl, len(v['orders']), int(v['qty']), f"{v['sum']:.2f}"))

        # По артиклю
        by_article = {}
        for r in rows:
            k = (r['article'], r['name'])
            if k not in by_article:
                by_article[k] = {'qty': 0.0, 'sum': 0.0}
            by_article[k]['qty'] += r['qty']
            by_article[k]['sum'] += r['sum']
        for (art, name), v in sorted(by_article.items(), key=lambda x: x[1]['sum'], reverse=True):
            self.sales_by_article_tree.insert('', tk.END, values=(art, name, int(v['qty']), f"{v['sum']:.2f}"))

        # По категории
        by_cat = {}
        order_ids_by_cat = {}
        for r in rows:
            cat = r['category'] or 'Без категории'
            by_cat.setdefault(cat, {'qty': 0.0, 'sum': 0.0})
            order_ids_by_cat.setdefault(cat, set())
            by_cat[cat]['qty'] += r['qty']
            by_cat[cat]['sum'] += r['sum']
            order_ids_by_cat[cat].add(r['order_id'])
        for cat, v in sorted(by_cat.items(), key=lambda x: x[1]['sum'], reverse=True):
            self.sales_by_category_tree.insert('', tk.END, values=(cat, len(order_ids_by_cat[cat]), int(v['qty']), f"{v['sum']:.2f}"))

        # За период (по дням)
        by_day = {}
        day_orders = {}
        for o in order_rows:
            day = o['date'].strftime('%Y-%m-%d')
            by_day.setdefault(day, {'qty': 0.0, 'sum': 0.0})
            day_orders.setdefault(day, set()).add(o['order_id'])
            by_day[day]['sum'] += o['sum']
        qty_by_day = {}
        for r in rows:
            day = r['date'].strftime('%Y-%m-%d')
            qty_by_day[day] = qty_by_day.get(day, 0.0) + r['qty']
        for day in sorted(by_day.keys(), reverse=True):
            self.sales_by_period_tree.insert(
                '', tk.END,
                values=(day, len(day_orders[day]), int(qty_by_day.get(day, 0.0)), f"{by_day[day]['sum']:.2f}")
            )

    def create_admin_log_tab(self, parent):
        """Вкладка журнала"""
        c = self.colors

        # Панель инструментов (современный стиль)
        toolbar = tk.Frame(parent, bg=c["bg_card"], padx=10, pady=8)
        toolbar.pack(fill=tk.X, padx=0, pady=(0, 10))

        ToolbarButton(toolbar, text="Обновить", icon="🔄", style='primary',
                     command=self.admin_refresh_log, bg_color=c["bg_card"]).pack(side=tk.LEFT, padx=3)
        ToolbarButton(toolbar, text="Очистить", icon="🗑️", style='danger',
                     command=self.admin_clear_log, bg_color=c["bg_card"]).pack(side=tk.LEFT, padx=3)

        # Область журнала
        self.admin_log_text = scrolledtext.ScrolledText(parent, font=("Courier New", 9), height=25)
        self.admin_log_text.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)

