    def _create_zutaten_allergens_tab(self, parent):
        """Вкладка управления аллергенами — список на всю ширину, редактор в popup"""
        c = self.colors

        # Toolbar
        toolbar = tk.Frame(parent, bg=c["bg_card"])
        toolbar.pack(fill=tk.X, padx=5, pady=5)
        ttk.Button(toolbar, text="🔄 Обновить", command=self._zutaten_request_data).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="+ Новый", command=lambda: self._open_allergen_editor(None)).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="✏️ Редактировать", command=self._allergen_edit_selected).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="🗑 Удалить", command=self._allergen_delete_selected).pack(side=tk.LEFT, padx=2)

        # Treeview на всю ширину
        tree_frame = tk.Frame(parent, bg=c["bg_card"])
        tree_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=(0, 5))

        cols = ('code', 'name_de', 'name_nl', 'name_fr', 'description')
        self.allergen_tree = ttk.Treeview(tree_frame, columns=cols, show='headings', height=20)

        self.allergen_tree.heading('code', text='Код')
        self.allergen_tree.heading('name_de', text='DE')
        self.allergen_tree.heading('name_nl', text='NL')
        self.allergen_tree.heading('name_fr', text='FR')
        self.allergen_tree.heading('description', text='Описание')

        self.allergen_tree.column('code', width=100, anchor='center')
        self.allergen_tree.column('name_de', width=220)
        self.allergen_tree.column('name_nl', width=220)
        self.allergen_tree.column('name_fr', width=220)
        self.allergen_tree.column('description', width=250)

        scroll = ttk.Scrollbar(tree_frame, orient=tk.VERTICAL, command=self.allergen_tree.yview)
        self.allergen_tree.configure(yscrollcommand=scroll.set)
        self.allergen_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)

        self.allergen_tree.bind('<Double-1>', lambda e: self._allergen_edit_selected())
        self.allergen_tree.bind('<Return>', lambda e: self._allergen_edit_selected())
        self.allergen_tree.bind('<Delete>', lambda e: self._allergen_delete_selected())

        self._allergen_current_id = None

    def _allergen_refresh_tree(self):
        """Обновить список аллергенов в дереве"""
        if not hasattr(self, 'allergen_tree'):
            return
        self.allergen_tree.delete(*self.allergen_tree.get_children())
        for a in getattr(self, 'zutaten_allergens', []):
            self.allergen_tree.insert('', tk.END, iid=str(a.get('allergen_id', '')),
                values=(
                    a.get('allergen_code', ''),
                    a.get('name_de', ''),
                    a.get('name_nl', ''),
                    a.get('name_fr', ''),
                    a.get('description_de', ''),
                ))

    def _allergen_edit_selected(self):
        """Открыть popup редактора для выбранного аллергена"""
        sel = self.allergen_tree.selection()
        if not sel:
            return
        aid = sel[0]
        allergen = None
        for a in self.zutaten_allergens:
            if str(a.get('allergen_id')) == aid:
                allergen = a
                break
        if allergen:
            self._open_allergen_editor(allergen)

    def _allergen_delete_selected(self):
        """Удалить выбранный аллерген."""
        sel = self.allergen_tree.selection()
        if not sel:
            return

        aid = sel[0]
        allergen = None
        for a in self.zutaten_allergens:
            if str(a.get('allergen_id')) == str(aid):
                allergen = a
                break

        if not allergen:
            messagebox.showerror("Ошибка", "Не удалось определить выбранный аллерген")
            return

        code = allergen.get('allergen_code', '')
        name = allergen.get('name_de', '')
        if not messagebox.askyesno("Подтверждение", f"Удалить аллерген {code} - {name}?"):
            return

        self.send_ws_message({'type': 'delete_allergen', 'allergen_id': allergen.get('allergen_id')})

    def _open_allergen_editor(self, allergen=None):
        """Popup окно редактора аллергена"""
        win = tk.Toplevel(self)
        win.title("✏️ Редактор аллергена" if allergen else "➕ Новый аллерген")
        win.transient(self)
        win.grab_set()
        self.center_dialog(win, 450, 380)
        win.resizable(False, False)

        c = self.colors
        main = tk.Frame(win, bg=c["bg_card"], padx=20, pady=15)
        main.pack(fill=tk.BOTH, expand=True)

        # Форма
        fields = [
            ("Код:", "code"),
            ("Название (DE):", "name_de"),
            ("Название (NL):", "name_nl"),
            ("Название (FR):", "name_fr"),
            ("Описание:", "description_de"),
            ("Порядок:", "sort_order"),
        ]

        vars_dict = {}
        for i, (label, key) in enumerate(fields):
            tk.Label(main, text=label, bg=c["bg_card"], fg=c["text_main"],
                     font=("Segoe UI", 10)).grid(row=i, column=0, sticky='e', pady=4, padx=(0, 10))
            var = tk.StringVar()
            if allergen:
                val = allergen.get(key if key != 'code' else 'allergen_code', '')
                var.set(str(val) if val else '')
            vars_dict[key] = var
            ttk.Entry(main, textvariable=var, width=35).grid(row=i, column=1, sticky='we', pady=4)

        main.columnconfigure(1, weight=1)

        allergen_id = allergen.get('allergen_id') if allergen else None

        # Кнопки
        btn_frame = tk.Frame(main, bg=c["bg_card"])
        btn_frame.grid(row=len(fields), column=0, columnspan=2, pady=(15, 0))

        def do_save():
            code = vars_dict['code'].get().strip()
            name_de = vars_dict['name_de'].get().strip()
            if not code or not name_de:
                messagebox.showerror("Ошибка", "Код и название (DE) обязательны!", parent=win)
                return
            try:
                sort_order = int(vars_dict['sort_order'].get().strip() or '0')
            except ValueError:
                sort_order = 0
            data = {
                'type': 'save_allergen',
                'allergen_code': code,
                'name_de': name_de,
                'name_nl': vars_dict['name_nl'].get().strip(),
                'name_fr': vars_dict['name_fr'].get().strip(),
                'description_de': vars_dict['description_de'].get().strip(),
                'sort_order': sort_order,
            }
            if allergen_id:
                data['allergen_id'] = allergen_id
            self.send_ws_message(data)
            win.destroy()

        def do_delete():
            if not allergen_id:
                return
            if not messagebox.askyesno("Подтверждение", "Удалить этот аллерген?", parent=win):
                return
            self.send_ws_message({'type': 'delete_allergen', 'allergen_id': allergen_id})
            win.destroy()

        ttk.Button(btn_frame, text="💾 Сохранить", command=do_save).pack(side=tk.LEFT, padx=5)
        if allergen_id:
            ttk.Button(btn_frame, text="🗑 Удалить", command=do_delete).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Отмена", command=win.destroy).pack(side=tk.LEFT, padx=5)

    def _create_zutaten_ingredients_list(self, parent):
        """Создание списка ингредиентов — на всю ширину, редактор в popup"""
        c = self.colors

        # Панель поиска и фильтров
        filter_frame = ttk.Frame(parent)
        filter_frame.pack(fill=tk.X, padx=5, pady=5)

        ttk.Label(filter_frame, text="🔍 Поиск:").pack(side=tk.LEFT)
        self.zutaten_search_var = tk.StringVar()
        self.zutaten_search_var.trace_add("write", lambda *_: self._filter_zutaten_ingredients())
        ttk.Entry(filter_frame, textvariable=self.zutaten_search_var, width=25).pack(side=tk.LEFT, padx=5)

        ttk.Label(filter_frame, text="Категория:").pack(side=tk.LEFT, padx=(10, 0))
        self.zutaten_category_filter = ttk.Combobox(filter_frame, values=["Все", "flour", "dairy", "egg", "nut", "fruit", "sugar", "chocolate", "flavoring", "other"], width=12)
        self.zutaten_category_filter.set("Все")
        self.zutaten_category_filter.bind("<<ComboboxSelected>>", lambda e: self._filter_zutaten_ingredients())
        self.zutaten_category_filter.pack(side=tk.LEFT, padx=5)

        ttk.Button(filter_frame, text="➕ Новый", command=lambda: self._open_ingredient_editor(None)).pack(side=tk.RIGHT, padx=2)
        ttk.Button(filter_frame, text="✏️ Редактировать", command=self._ingredient_edit_selected).pack(side=tk.RIGHT, padx=2)
        ttk.Button(filter_frame, text="🗑 Удалить", command=self._ingredient_delete_selected).pack(side=tk.RIGHT, padx=2)
        ttk.Button(filter_frame, text="🔄 Обновить", command=self._zutaten_request_data).pack(side=tk.RIGHT, padx=2)

        # Таблица ингредиентов на всю ширину
        tree_frame = tk.Frame(parent, bg=c["bg_card"])
        tree_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=(0, 5))

        cols = ('Код', 'DE', 'NL', 'FR', 'Аллерген', 'Категория')
        self.zutaten_tree = ttk.Treeview(tree_frame, columns=cols, show='headings', height=20)
        for col in cols:
            self.zutaten_tree.heading(col, text=col)
        self.zutaten_tree.column('Код', width=120)
        self.zutaten_tree.column('DE', width=200)
        self.zutaten_tree.column('NL', width=160)
        self.zutaten_tree.column('FR', width=160)
        self.zutaten_tree.column('Аллерген', width=100)
        self.zutaten_tree.column('Категория', width=100)

        scrollbar = ttk.Scrollbar(tree_frame, orient=tk.VERTICAL, command=self.zutaten_tree.yview)
        self.zutaten_tree.configure(yscroll=scrollbar.set)

        self.zutaten_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)

        self.zutaten_tree.bind('<Double-1>', lambda e: self._ingredient_edit_selected())
        self.zutaten_tree.bind('<Return>', lambda e: self._ingredient_edit_selected())
        self.zutaten_tree.bind('<Delete>', lambda e: self._ingredient_delete_selected())

        # Теги для аллергенов
        allergen_bg = '#3C3015' if self.is_dark_mode else '#FFF7E0'
        self.zutaten_tree.tag_configure('allergen', background=allergen_bg)

    def _create_zutaten_recipe_composition(self, parent):
        """Создание интерфейса для управления составом рецепта"""
        c = self.colors

        # Верхняя панель: выбор рецепта
        top_frame = ttk.Frame(parent)
