        ttk.Button(toolbar, text="🗑️ Удалить", command=self._zutaten_remove_recipe_ingredient).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="💾 Сохранить состав", command=self._zutaten_save_recipe_composition).pack(side=tk.RIGHT, padx=2)

        # Таблица
        cols = ('Ингредиент', 'Код', 'Вес (г)', 'QUID %', 'Аллерген')
