        self.zutaten_recipe_tree.column('Аллерген', width=100)

        scrollbar = ttk.Scrollbar(list_frame, orient=tk.VERTICAL, command=self.zutaten_recipe_tree.yview)
        self.zutaten_recipe_tree.configure(yscroll=scrollbar.set)

        self.zutaten_recipe_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=5, pady=5)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y, pady=5)
        self.zutaten_recipe_tree.bind('<Delete>', lambda e: self._zutaten_remove_recipe_ingredient())
        self.zutaten_recipe_tree.bind('<Double-1>', lambda e: self._zutaten_edit_recipe_ingredient())

        # Параметры рецепта (ПОСЛЕ ингредиентов)
        info_frame = ttk.LabelFrame(parent, text="📊 Параметры рецепта")
        info_frame.pack(fill=tk.X, padx=10, pady=5)

