        self.zutaten_allergens_label = ttk.Label(allergens_frame, text="", font=("Segoe UI", 10))
        self.zutaten_allergens_label.pack(anchor='w', padx=10, pady=8)

        print_box = ttk.LabelFrame(left_panel, text="Печать")
