    def _create_zutaten_recipe_tree_tab(self, parent):
        """Подвкладка: рекурсивное дерево рецепта + двухоконный состав"""
        c = self.colors

        # === ВЕРХНЯЯ ПАНЕЛЬ: выбор рецепта ===
