        top_frame.pack(fill=tk.X, padx=10, pady=(10, 5))

        tk.Label(top_frame, text="Рецепт:", bg=c["bg_card"], fg=c["text_main"],
                 font=("Segoe UI", 11)).pack(side=tk.LEFT)

        self.v2_tree_recipe_var = tk.StringVar()
        self.v2_tree_recipe_combo = ttk.Combobox(
            top_frame, textvariable=self.v2_tree_recipe_var, width=40, state='readonly'
        )
