    def article_mapping_refresh(self, mappings):
        """Обновление таблицы маппингов из серверных данных."""
        if not hasattr(self, 'article_mapping_tree'):
            return
        self.article_mapping_tree.delete(*self.article_mapping_tree.get_children())
        for m in mappings:
            price_str = f"{float(m.get('unit_price', 0)):.2f}" if float(m.get('unit_price', 0)) > 0 else ""
            self.article_mapping_tree.insert('', tk.END, values=(
                m.get('monolith_article_nr', ''),
                m.get('wiso_article_nr', ''),
                m.get('monolith_name', ''),
                price_str
            ))

    def article_mapping_add(self):
        """Диалог добавления маппинга артикула."""
        self._article_mapping_dialog()

    def article_mapping_edit(self):
        """Диалог редактирования выбранного маппинга."""
        sel = self.article_mapping_tree.selection()
        if not sel:
            return
        vals = self.article_mapping_tree.item(sel[0])['values']
        self._article_mapping_dialog(
            monolith_nr=str(vals[0]),
            wiso_nr=str(vals[1]),
            name=str(vals[2]),
            price=str(vals[3]) if vals[3] else ''
        )

    def _article_mapping_dialog(self, monolith_nr='', wiso_nr='', name='', price=''):
        """Диалог добавления/редактирования маппинга."""
        dialog = tk.Toplevel(self)
        dialog.title("Маппинг артикула")
        dialog.transient(self)
        dialog.geometry("400x300")

        c = self.colors
        frame = tk.Frame(dialog, bg=c["bg_main"], padx=20, pady=20)
        frame.pack(fill=tk.BOTH, expand=True)

        ttk.Label(frame, text="Monolith Nr:").pack(anchor='w')
        monolith_var = tk.StringVar(value=monolith_nr)
        e1 = ttk.Entry(frame, textvariable=monolith_var)
        e1.pack(fill=tk.X, pady=(0, 10))
        if monolith_nr:
            e1.config(state='readonly')

        ttk.Label(frame, text="WISO Nr:").pack(anchor='w')
        wiso_var = tk.StringVar(value=wiso_nr)
        ttk.Entry(frame, textvariable=wiso_var).pack(fill=tk.X, pady=(0, 10))

        ttk.Label(frame, text="Название:").pack(anchor='w')
        name_var = tk.StringVar(value=name)
        ttk.Entry(frame, textvariable=name_var).pack(fill=tk.X, pady=(0, 10))

        ttk.Label(frame, text="Цена за единицу (€):").pack(anchor='w')
        price_var = tk.StringVar(value=price)
        ttk.Entry(frame, textvariable=price_var).pack(fill=tk.X, pady=(0, 10))

        def save():
            m_nr = monolith_var.get().strip()
            w_nr = wiso_var.get().strip()
            if not m_nr or not w_nr:
                return
            try:
                p = float(price_var.get().replace(',', '.')) if price_var.get().strip() else 0.0
            except ValueError:
                p = 0.0

            self.send_ws_message({
                'type': 'save_article_mapping',
                'mapping': {
                    'monolith_article_nr': m_nr,
                    'wiso_article_nr': w_nr,
                    'monolith_name': name_var.get().strip(),
                    'unit_price': p
                }
            })
            dialog.destroy()

        ttk.Button(frame, text="Сохранить", command=save).pack(fill=tk.X, pady=(15, 0))

    def article_mapping_delete(self):
        """Удаление выбранного маппинга."""
        sel = self.article_mapping_tree.selection()
        if not sel:
            return
        vals = self.article_mapping_tree.item(sel[0])['values']
        monolith_nr = str(vals[0])

        from tkinter import messagebox
        if messagebox.askyesno("Удалить", f"Удалить маппинг для {monolith_nr}?"):
            self.send_ws_message({
                'type': 'delete_article_mapping',
                'monolith_article_nr': monolith_nr
            })

    def article_mapping_auto_prices(self):
        """Авто-заполнение цен из истории заказов."""
        self.send_ws_message({'type': 'auto_fill_prices'})

    def article_mapping_force_scan(self):
        """Принудительное сканирование API."""
        self.send_ws_message({'type': 'force_api_scan'})

