    def create_backup_settings_editor(self, parent):
        """Редактор ручного и автоматического backup (system + documents)."""
        c = self.colors
        container = tk.Frame(parent, bg=c["bg_card"])
        container.pack(fill=tk.BOTH, expand=True, padx=16, pady=16)

        tk.Label(
            container,
            text="Backup Center",
            font=("Segoe UI", 16, "bold"),
            bg=c["bg_card"],
            fg=c["text_main"]
        ).pack(anchor='w', pady=(0, 10))

        tk.Label(
            container,
            text="Separate rules for system and documents backups.",
            font=("Segoe UI", 10),
            bg=c["bg_card"],
            fg=c["text_light"]
        ).pack(anchor='w', pady=(0, 14))

        top_actions = tk.Frame(container, bg=c["bg_card"])
        top_actions.pack(fill=tk.X, pady=(0, 10))
        ttk.Button(
            top_actions,
            text="Backup History",
            command=self._open_backup_history_window
        ).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(
            top_actions,
            text="Refresh History",
            command=lambda: self.send_ws_message({'type': 'get_backup_history'})
        ).pack(side=tk.LEFT)

        self.backup_controls = {}
        self.backup_status_labels = {}
        self.backup_history_items = []

        self._create_backup_target_block(
            parent=container,
            title="System Backup",
            target='system',
            run_text="Run system backup now"
        )
        self._create_backup_target_block(
            parent=container,
            title="Documents Backup",
            target='documents',
            run_text="Run documents backup now"
        )

    def _create_backup_target_block(self, parent, title: str, target: str, run_text: str):
        c = self.colors
        frame = tk.LabelFrame(
            parent,
            text=title,
            bg=c["bg_card"],
            fg=c["text_main"],
            padx=12,
            pady=10
        )
        frame.pack(fill=tk.X, pady=(0, 14))

        enabled_var = tk.BooleanVar(value=False)
        mode_var = tk.StringVar(value='daily')
        time_var = tk.StringVar(value='03:00')
        weekday_var = tk.IntVar(value=6)

        row1 = tk.Frame(frame, bg=c["bg_card"])
        row1.pack(fill=tk.X, pady=(2, 8))
        ttk.Checkbutton(
            row1,
            text="Enable auto backup",
            variable=enabled_var
        ).pack(side=tk.LEFT, padx=(0, 20))

        ttk.Label(row1, text="Mode:").pack(side=tk.LEFT, padx=(0, 6))
        mode_combo = ttk.Combobox(
            row1,
            state='readonly',
            width=14,
            textvariable=mode_var,
            values=['daily', 'weekly']
        )
        mode_combo.pack(side=tk.LEFT, padx=(0, 14))

        ttk.Label(row1, text="Time (HH:MM):").pack(side=tk.LEFT, padx=(0, 6))
        ttk.Entry(row1, textvariable=time_var, width=8).pack(side=tk.LEFT, padx=(0, 16))

        ttk.Label(row1, text="Weekday:").pack(side=tk.LEFT, padx=(0, 6))
        weekday_combo = ttk.Combobox(
            row1,
            state='readonly',
            width=14,
            values=[
                "0 - Monday",
                "1 - Tuesday",
                "2 - Wednesday",
                "3 - Thursday",
                "4 - Friday",
                "5 - Saturday",
                "6 - Sunday"
            ]
        )
        weekday_combo.current(6)
        weekday_combo.pack(side=tk.LEFT)

        def on_weekday_select(_evt=None):
            raw = weekday_combo.get().split(' - ')[0].strip()
            try:
                weekday_var.set(int(raw))
            except Exception:
                weekday_var.set(6)

        weekday_combo.bind("<<ComboboxSelected>>", on_weekday_select)

        def update_mode_ui(_evt=None):
            is_weekly = (mode_var.get() == 'weekly')
            state = 'readonly' if is_weekly else 'disabled'
            weekday_combo.configure(state=state)
            if not is_weekly:
                weekday_var.set(6)
                weekday_combo.current(6)

        mode_combo.bind("<<ComboboxSelected>>", update_mode_ui)
        update_mode_ui()

        row2 = tk.Frame(frame, bg=c["bg_card"])
        row2.pack(fill=tk.X)
        ttk.Button(
            row2,
            text=run_text,
            command=lambda t=target: self._run_backup_now(t)
        ).pack(side=tk.LEFT, padx=(0, 8))

        ttk.Button(
            row2,
            text="Save settings",
            command=lambda t=target: self._save_backup_settings(t)
        ).pack(side=tk.LEFT, padx=(0, 8))

        status_lbl = tk.Label(
            row2,
            text="Status: -",
            font=("Segoe UI", 9),
            bg=c["bg_card"],
            fg=c["text_light"]
        )
        status_lbl.pack(side=tk.LEFT, padx=8)

        self.backup_controls[target] = {
            'enabled_var': enabled_var,
            'mode_var': mode_var,
            'time_var': time_var,
            'weekday_var': weekday_var,
            'weekday_combo': weekday_combo,
            'update_mode_ui': update_mode_ui
        }
        self.backup_status_labels[target] = status_lbl

    def _collect_backup_settings_from_ui(self, target: str) -> dict:
        controls = getattr(self, 'backup_controls', {}).get(target)
        if not controls:
            return {}
        settings = {
            'enabled': bool(controls['enabled_var'].get()),
            'mode': str(controls['mode_var'].get() or 'daily'),
            'time': str(controls['time_var'].get() or '03:00').strip(),
            'weekday': int(controls['weekday_var'].get() if controls['weekday_var'].get() is not None else 6)
        }
        return settings

    def _save_backup_settings(self, target: str):
        payload = self._collect_backup_settings_from_ui(target)
        if not payload:
            return
        self.send_ws_message({
            'type': 'save_backup_settings',
            'target': target,
            'settings': payload
        })

    def _run_backup_now(self, target: str):
        self.send_ws_message({
            'type': 'run_backup_now',
            'target': target
        })
        self._set_backup_status(target, "Status: running...")

    def _set_backup_status(self, target: str, text: str):
        lbl = getattr(self, 'backup_status_labels', {}).get(target)
        if lbl and lbl.winfo_exists():
            lbl.config(text=text)

    def _apply_backup_settings_to_ui(self, settings_map: dict):
        if not hasattr(self, 'backup_controls'):
            return
        if not isinstance(settings_map, dict):
            return
        targets = [t for t in ('system', 'documents') if t in settings_map]
        if not targets:
            return
        for target in targets:
            controls = self.backup_controls.get(target)
            settings = settings_map.get(target, {})
            if not controls:
                continue
            controls['enabled_var'].set(bool(settings.get('enabled', False)))
            mode = str(settings.get('mode', 'daily')).lower().strip()
            if mode not in ('daily', 'weekly'):
                mode = 'daily'
            controls['mode_var'].set(mode)
            controls['time_var'].set(str(settings.get('time', '03:00')))
            weekday = settings.get('weekday', 6)
            try:
                weekday = int(weekday)
            except Exception:
                weekday = 6
            weekday = max(0, min(6, weekday))
            controls['weekday_var'].set(weekday)
            controls['weekday_combo'].current(weekday)
            controls['update_mode_ui']()
            last_run = settings.get('last_run_at')
            if last_run:
                self._set_backup_status(target, f"Status: last run {str(last_run)[:19].replace('T', ' ')}")

    def _handle_backup_now_result(self, data: dict):
        result = data.get('result', {}) if isinstance(data, dict) else {}
        target = result.get('target', '')
        success = bool(result.get('success'))
        destination = result.get('destination', '')
        if success:
            self._set_backup_status(target, "Status: success")
            messagebox.showinfo("Backup", f"Backup completed successfully.\n\nFolder:\n{destination}")
        else:
            self._set_backup_status(target, "Status: error")
            messagebox.showerror("Backup", f"Backup error:\n{result.get('error', 'Unknown error')}")

    def _handle_backup_status_update(self, data: dict):
        result = data.get('result', {}) if isinstance(data, dict) else {}
        target = result.get('target', '')
        success = bool(result.get('success'))
        if success:
            self._set_backup_status(target, "Status: success")
        else:
            self._set_backup_status(target, "Status: error")

    def _open_backup_history_window(self):
        if hasattr(self, 'backup_history_window') and self.backup_history_window.winfo_exists():
            self.backup_history_window.lift()
            self.send_ws_message({'type': 'get_backup_history'})
            return

        win = tk.Toplevel(self)
        win.title("Backup History")
        win.transient(self)
        self.center_dialog(win, 980, 560)
        self.backup_history_window = win

        root = tk.Frame(win, bg=self.colors["bg_card"])
        root.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        top = tk.Frame(root, bg=self.colors["bg_card"])
        top.pack(fill=tk.X, pady=(0, 8))
        ttk.Button(top, text="Refresh", command=lambda: self.send_ws_message({'type': 'get_backup_history'})).pack(side=tk.LEFT)

        cols = ("Type", "Date", "Time", "Path")
        tree = ttk.Treeview(root, columns=cols, show='headings', height=22)
        tree.heading("Type", text="Type")
        tree.heading("Date", text="Date")
        tree.heading("Time", text="Time")
        tree.heading("Path", text="Path")
        tree.column("Type", width=120, anchor=tk.CENTER)
        tree.column("Date", width=120, anchor=tk.CENTER)
        tree.column("Time", width=100, anchor=tk.CENTER)
        tree.column("Path", width=620, anchor=tk.W)
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        y_scroll = ttk.Scrollbar(root, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscrollcommand=y_scroll.set)
        y_scroll.pack(side=tk.RIGHT, fill=tk.Y)

        self.backup_history_tree = tree
        self._render_backup_history()
        self.send_ws_message({'type': 'get_backup_history'})

    def _render_backup_history(self):
        if not hasattr(self, 'backup_history_tree'):
            return
        tree = self.backup_history_tree
        if not tree.winfo_exists():
            return
        tree.delete(*tree.get_children())
        items = getattr(self, 'backup_history_items', [])
        for item in items:
            target = str(item.get('target', ''))
            target_label = 'System' if target == 'system' else ('Documents' if target == 'documents' else target)
            tree.insert('', tk.END, values=(
                target_label,
                item.get('date', ''),
                item.get('time', ''),
                item.get('path', '')
            ))

    def _handle_backup_history_data(self, data: dict):
        items = data.get('items', []) if isinstance(data, dict) else []
        if not isinstance(items, list):
            items = []
        self.backup_history_items = items
        self._render_backup_history()

    def _client_history_format_ts(self, ts: str) -> str:
        ts_str = str(ts or '').strip()
        if not ts_str:
            return '-'
        ts_short = ts_str.replace('T', ' ')[:19]
        try:
            dt = datetime.fromisoformat(ts_str.replace('Z', '+00:00'))
            return dt.strftime('%d.%m.%Y %H:%M:%S')
        except Exception:
            return ts_short

    def _client_history_action_ru(self, action: str) -> str:
        mapping = {
            'start_viewing_order': 'Открыт заказ',
            'order_printed': 'Распечатан заказ',
            'labels_printed': 'Распечатаны этикетки',
            'boxes_info': 'Указано количество коробок',
            'boxes_info_saved': 'Подтверждено сохранение коробок',
            'get_customer_shipping_doc': 'Открыт документ отгрузки',
            'ui_interaction': 'Действие в интерфейсе',
        }
        a = str(action or '').strip()
        return mapping.get(a, a or '-')

