        self.admin_audit_tree.heading("Role", text="Роль")
        self.admin_audit_tree.heading("Action", text="Действие")
        self.admin_audit_tree.heading("IP", text="IP")
        self.admin_audit_tree.heading("Details", text="Детали")
        self.admin_audit_tree.column("Time", width=150, anchor=tk.CENTER)
        self.admin_audit_tree.column("User", width=130, anchor=tk.W)
        self.admin_audit_tree.column("Role", width=90, anchor=tk.CENTER)
        self.admin_audit_tree.column("Action", width=190, anchor=tk.W)
        self.admin_audit_tree.column("IP", width=120, anchor=tk.CENTER)
        self.admin_audit_tree.column("Details", width=550, anchor=tk.W)
