    def _admin_audit_request_logs(self):
        if not hasattr(self, 'admin_audit_date'):
            return
        password = (self.admin_audit_password_var.get().strip() if hasattr(self, 'admin_audit_password_var') else "")
        if not password:
            messagebox.showwarning("Админ", "Введите пароль.")
            return

        date_str = self.admin_audit_date.get_date().strftime('%Y-%m-%d')
        selected_user = ""
        if hasattr(self, 'admin_audit_user_var'):
            val = (self.admin_audit_user_var.get() or "").strip()
            if val and val != "Все":
                selected_user = val

        self.send_ws_message({
            'type': 'get_user_activity_logs',
            'admin_password': password,
            'date': date_str,
            'username': selected_user,
            'limit': 3000
        })

    def _handle_user_activity_logs_data(self, data: dict):
        if not bool(data.get('success')):
            messagebox.showerror("Админ", data.get('message', 'Ошибка загрузки журнала'))
            return
        if not hasattr(self, 'admin_audit_tree'):
            return

        logs = data.get('logs', []) if isinstance(data.get('logs', []), list) else []
        users = data.get('users', []) if isinstance(data.get('users', []), list) else []

        self.admin_audit_tree.delete(*self.admin_audit_tree.get_children())
        for item in logs:
            ts = str(item.get('event_time', '') or '')
            ts_view = ts.replace('T', ' ')[:19] if ts else ''
            self.admin_audit_tree.insert('', tk.END, values=(
                ts_view,
                item.get('username', ''),
                item.get('role', ''),
                item.get('action_type', ''),
                item.get('client_ip', ''),
                item.get('details', '')
            ))

        if hasattr(self, 'admin_audit_user_combo'):
            old_val = (self.admin_audit_user_var.get() or "Все").strip() if hasattr(self, 'admin_audit_user_var') else "Все"
            user_values = ["Все"] + [str(u.get('username', '')) for u in users if str(u.get('username', '')).strip()]
            # Убираем дубли, сохраняя порядок
            seen = set()
            compact = []
            for u in user_values:
                if u not in seen:
                    seen.add(u)
                    compact.append(u)
            self.admin_audit_user_combo.configure(values=compact)
            if old_val in compact:
                self.admin_audit_user_var.set(old_val)
            else:
                self.admin_audit_user_var.set("Все")

