    def _admin_server_disconnect_selected(self):
        if not hasattr(self, 'admin_server_sessions_tree'):
            return
        sel = self.admin_server_sessions_tree.selection()
        if not sel:
            messagebox.showwarning("Server", "Select a session first.")
            return
        sid = sel[0]
        vals = self.admin_server_sessions_tree.item(sel[0]).get('values', [])
        uname = vals[1] if len(vals) > 1 else sid
        if not messagebox.askyesno("Server", f"Disconnect user '{uname}'?"):
            return
        self.send_ws_message({'type': 'disconnect_session', 'session_id': sid})

    def _admin_server_restart(self):
        if not messagebox.askyesno("Server", "Restart server now? All clients will be disconnected."):
            return
        self.send_ws_message({'type': 'restart_server'})

    def _handle_server_status_data(self, data: dict):
        sessions = data.get('sessions', []) if isinstance(data, dict) else []
        stats = data.get('stats', {}) if isinstance(data, dict) else {}
        logs_tail = data.get('logs_tail', []) if isinstance(data, dict) else []

        if hasattr(self, 'admin_server_sessions_tree') and self.admin_server_sessions_tree.winfo_exists():
            tree = self.admin_server_sessions_tree
            tree.delete(*tree.get_children())
            for row in sessions:
                sid = row.get('session_id', '')
                connected = str(row.get('connected_at', '')).replace('T', ' ')[:19]
                tree.insert('', tk.END, iid=sid, values=(
                    row.get('session_short', ''),
                    row.get('username', ''),
                    row.get('role', ''),
                    row.get('warehouse_id', ''),
                    row.get('remote_ip', ''),
                    connected
                ))

        if hasattr(self, 'admin_server_stats_label') and self.admin_server_stats_label.winfo_exists():
            self.admin_server_stats_label.config(
                text=f"Online: {stats.get('active_total', 0)} | Admin: {stats.get('admins', 0)} | "
                     f"Operator: {stats.get('operators', 0)} | Warehouse: {stats.get('warehouses', 0)}"
            )

        if hasattr(self, 'admin_server_logs_text') and self.admin_server_logs_text.winfo_exists():
            text_widget = self.admin_server_logs_text
            text_widget.configure(state=tk.NORMAL)
            text_widget.delete('1.0', tk.END)
            if isinstance(logs_tail, list):
                text_widget.insert(tk.END, "\n".join(str(x) for x in logs_tail))
            text_widget.configure(state=tk.DISABLED)
            text_widget.see(tk.END)

