    def logistics_toggle_sort(self, column_name: str):
        """Переключение сортировки по колонке: asc -> desc -> off."""
        if self.logistics_sort_column != column_name:
            self.logistics_sort_column = column_name
            self.logistics_sort_mode = 'asc'
        else:
            if self.logistics_sort_mode == 'asc':
                self.logistics_sort_mode = 'desc'
            elif self.logistics_sort_mode == 'desc':
                self.logistics_sort_mode = None
                self.logistics_sort_column = None
            else:
                self.logistics_sort_mode = 'asc'
        self.logistics_filter_clients()

    def _refresh_logistics_headings(self):
        """Обновить заголовки колонок с индикатором сортировки."""
        if not hasattr(self, 'logistics_tree'):
            return
        base_titles = {
            'ID': 'ID',
            'Имя': 'Имя',
            'E-mail': 'E-mail',
            'PLZ': 'PLZ',
            'Город': 'Город',
            'Адрес': 'Адрес',
            'Маршрут': 'Маршрут',
            'Транспорт': 'Транспорт',
            'Точка': 'Точка',
            'Monolith': 'Monolith ID',
        }
        for col in self._logistics_cols:
            title = base_titles[col]
            if self.logistics_sort_column == col:
                title = f"{title} {'▲' if self.logistics_sort_mode == 'asc' else '▼'}"
            self.logistics_tree.heading(col, text=title)

    def _logistics_sort_key(self, row: tuple, col_idx: int):
        """Ключ сортировки для строки logistics_tree."""
        val = row[col_idx] if 0 <= col_idx < len(row) else ''
        sval = str(val or '').strip()
        if col_idx == 1 and sval.startswith("🆕 "):
            sval = sval[2:].strip()
        if col_idx in (0, 3, 9):
            try:
                return (0, int(sval))
            except Exception:
                return (1, sval.lower())
        return sval.lower()

    def logistics_filter_clients(self):
        """Фильтр с новыми полями и поддержкой NEW"""
        search = self.logistics_search_var.get().lower()
        show_new_only = self.logistics_show_new_only.get() if hasattr(self, 'logistics_show_new_only') else False
        self.logistics_tree.delete(*self.logistics_tree.get_children())
        self._refresh_logistics_headings()

        new_count = 0
        rows_data = []
        for item in self.logistics_clients:
            is_new = item.get('is_new', 0)

            # Фильтр "только новые"
            if show_new_only and not is_new:
                continue

            # Добавляем метку NEW к имени если клиент новый
            client_name = str(item['client_name'])
            if is_new:
                client_name = f"🆕 {client_name}"
                new_count += 1

            route_display = str(item.get('route_name') or '').strip()
            if not route_display or route_display.lower() in ('none', 'null', 'nan'):
                route_display = str(item.get('route_id') or 'Не назначен').strip() or 'Не назначен'

            row = (
                str(item['client_id']),
                client_name,
                str(item.get('email', '')),
                str(item.get('plz', '')),
                str(item.get('city', '')),
                str(item.get('address', '')),
                route_display,
                str(item.get('transport_type', '-')),
                str(item.get('delivery_point', '-')),
                str(item.get('monolith_client_id', ''))
            )

            full_str = " ".join(row).lower()
            if search and search not in full_str:
                continue

            rows_data.append({'row': row, 'is_new': bool(is_new)})

        if self.logistics_sort_column and self.logistics_sort_mode:
            col_map = {name: idx for idx, name in enumerate(self._logistics_cols)}
            col_idx = col_map.get(self.logistics_sort_column, 0)
            rows_data.sort(
                key=lambda x: self._logistics_sort_key(x['row'], col_idx),
                reverse=(self.logistics_sort_mode == 'desc')
            )

        for entry in rows_data:
            row = entry['row']
            is_new = entry['is_new']
            item_id = self.logistics_tree.insert('', tk.END, values=row)
            if is_new:
                self.logistics_tree.item(item_id, tags=('new',))

        # Настройка цвета для новых клиентов (жёлтый фон)
        self.logistics_tree.tag_configure('new', background='#FFFACD')

        # Обновляем заголовок с количеством новых
        if new_count > 0:
            print(f"[Logistics] Новых клиентов: {new_count}")

    def open_client_editor(self, event):
        """Открыть общий редактор клиента (единое окно)."""
        sel = self.logistics_tree.selection()
        if not sel:
            return
        item_vals = self.logistics_tree.item(sel[0])['values']
        client_id = str(item_vals[0])
        client_data = next((c for c in self.logistics_clients if str(c.get('client_id')) == client_id), None)
        if client_data:
            self.client_editor_dialog(mode='edit', data=client_data)

    def mark_all_clients_reviewed(self):
        """Отметить всех клиентов как просмотренных (снять метку NEW)"""
        self.send_ws_message({'type': 'mark_all_clients_reviewed'})

    def mark_client_reviewed(self, client_id):
        """Отметить одного клиента как просмотренного"""
        self.send_ws_message({'type': 'mark_client_reviewed', 'client_id': client_id})

    def logistics_on_client_select(self, event):
        """Обработка выбора клиента из списка"""
        selection = self.logistics_tree.selection()
        if not selection:
            return

        item = self.logistics_tree.item(selection[0])
        client_id = item['values'][0]

        # Находим данные клиента
        client_data = next((c for c in self.logistics_clients if c['client_id'] == client_id), None)

        if not client_data:
            return

        self.logistics_current_client = client_data

        # Обновляем интерфейс
        self.logistics_client_info.config(text=f"Клиент: {client_data['client_name']} (ID: {client_data['client_id']})")

        # Устанавливаем выбранный маршрут
        current_route = client_data.get('route_id', 'free')
        self.logistics_route_var.set(current_route)

        # Обновляем информацию о маршруте
        self.logistics_update_route_info(current_route)

    def logistics_on_route_select(self, event):
        """Обработка выбора маршрута из комбобокса"""
        selected_route = self.logistics_route_var.get()
        self.logistics_update_route_info(selected_route)

    def logistics_update_route_info(self, route_id):
        """Обновить отображение информации о маршруте"""
        # Находим данные маршрута
        route_data = next((r for r in self.logistics_routes if r['route_id'] == route_id), None)

        if not route_data:
            self.logistics_days_label.config(text="-")
            self.logistics_mode_label.config(text="-")
            return

        # Форматируем дни доставки
        day_names = ['Понедельник', 'Вторник', 'Среда', 'Четверг', 'Пятница', 'Суббота', 'Воскресенье']
        delivery_days = route_data.get('delivery_days', [])

        if delivery_days:
            days_str = ', '.join([day_names[d] for d in delivery_days if d < len(day_names)])
        else:
            days_str = "Не установлены (ручной режим)"

        self.logistics_days_label.config(text=days_str)
        rules = self._get_route_schedule_rules(route_data)
        self.logistics_leadtime_label.config(text=f"{len(rules)} правил" if rules else "По товарам")

        mode = "Ручное планирование" if route_data.get('is_manual') else "Автоматическое планирование"
        self.logistics_mode_label.config(text=mode)

    def logistics_save_rule(self):
        """Сохранить назначение маршрута (ИСПРАВЛЕНО)"""
        # 1. Берем ID клиента из ВЫДЕЛЕННОЙ СТРОКИ (надежнее)
        selection = self.logistics_tree.selection()
        if not selection:
            messagebox.showwarning("Внимание", "Выберите клиента в списке слева!")
            return

        item = self.logistics_tree.item(selection[0])
        client_id = str(item['values'][0])
        client_name = str(item['values'][1])

        # 2. Берем Маршрут из КОМБОБОКСА
        selected_route = self.logistics_route_var.get()
        if not selected_route:
            messagebox.showwarning("Внимание", "Выберите маршрут!")
            return

        # 3. Отправляем
        self.send_ws_message({
            'type': 'save_logistics_rule',
            'client_id': client_id,
            'client_name': client_name,
            'route_id': selected_route
        })
        
        # 4. Обновляем локально (для мгновенной реакции интерфейса)
        # Находим клиента в списке и обновляем ему маршрут
        route_name = selected_route
        route_match = next((r for r in self.logistics_routes if str(r.get('route_id')) == selected_route), None)
        if route_match:
            route_name = str(route_match.get('route_name') or selected_route)

        for i, client in enumerate(self.logistics_clients):
            if str(client['client_id']) == client_id:
                self.logistics_clients[i]['route_id'] = selected_route
                self.logistics_clients[i]['route_name'] = route_name
                break
        
        # Обновляем строку в таблице, сохраняя остальные значения
        old_vals = list(self.logistics_tree.item(selection[0], 'values'))
        if len(old_vals) >= 10:
            old_vals[6] = route_name
            self.logistics_tree.item(selection[0], values=tuple(old_vals))

        if self._apply_logistics_routes_to_local_orders():
            self.admin_refresh_orders()
            self.operator_apply_filter()
            self.warehouse_filter_orders()
            self.update_dashboard()
            if hasattr(self, 'warehouse_refresh_jobs'):
                self.warehouse_refresh_jobs()

        messagebox.showinfo("Успех", f"Клиент {client_name} переведен на маршрут {selected_route}")

    def _get_route_schedule_rules(self, route_data):
        day_names = ['Понедельник', 'Вторник', 'Среда', 'Четверг', 'Пятница', 'Суббота', 'Воскресенье']
        normalized = []

        raw_rules = route_data.get('schedule_rules', [])
        if isinstance(raw_rules, list):
            for rule in raw_rules:
                try:
                    cutoff_day = int(rule.get('cutoff_day'))
                    delivery_day = int(rule.get('delivery_day'))
                    production_day = int(rule.get('production_day'))
                    cutoff_time = datetime.strptime(str(rule.get('cutoff_time') or '14:00').strip(), "%H:%M").strftime("%H:%M")
                    if 0 <= cutoff_day <= 6 and 0 <= delivery_day <= 6 and 0 <= production_day <= 6:
                        normalized.append({
                            'cutoff_day': cutoff_day,
                            'cutoff_time': cutoff_time,
                            'delivery_day': delivery_day,
                            'production_day': production_day
                        })
                except Exception:
                    continue

        if not normalized:
            current_days = route_data.get('delivery_days', []) or []
            cutoff_time = str(route_data.get('cutoff_time') or '14:00').strip() or '14:00'
            for delivery_day in current_days:
                if not isinstance(delivery_day, int) or delivery_day < 0 or delivery_day > 6:
                    continue
                production_day = (delivery_day - 1) % 7
                normalized.append({
                    'cutoff_day': production_day,
                    'cutoff_time': cutoff_time,
                    'delivery_day': delivery_day,
                    'production_day': production_day
                })

        normalized.sort(key=lambda x: (x['cutoff_day'], x['cutoff_time'], x['delivery_day'], x['production_day']))
        return normalized

    def _format_route_schedule_rules(self, route_data):
        short_days = ['Пн', 'Вт', 'Ср', 'Чт', 'Пт', 'Сб', 'Вс']
        rules = self._get_route_schedule_rules(route_data)
        if not rules:
            return 'Правила не настроены'

        parts = []
        for rule in rules[:3]:
            parts.append(
                f"до {short_days[rule['cutoff_day']]} {rule['cutoff_time']} -> "
                f"{short_days[rule['delivery_day']]} / сборка {short_days[rule['production_day']]}"
            )
        if len(rules) > 3:
            parts.append(f"+ ещё {len(rules) - 3}")
        return ' | '.join(parts)

    def logistics_on_route_edit_select(self, event):
        """Обработка выбора маршрута для редактирования"""
        selected_route_id = self.logistics_route_edit_var.get()
        if not selected_route_id:
            return

        route_data = next((r for r in self.logistics_routes if r['route_id'] == selected_route_id), None)
        if not route_data:
            return

        self.logistics_route_edit_info.config(text=self._format_route_schedule_rules(route_data))

    def logistics_edit_route_dialog(self):
        """Диалог редактирования правил маршрута"""
        selected_route_id = self.logistics_route_edit_var.get()
        if not selected_route_id:
            messagebox.showwarning("Внимание", "Сначала выберите маршрут для редактирования")
            return

        route_data = next((r for r in self.logistics_routes if r['route_id'] == selected_route_id), None)
        if not route_data:
            return

        dialog = tk.Toplevel(self)
        dialog.title(f"Редактирование маршрута: {route_data['route_name']}")
        dialog.transient(self)
        dialog.grab_set()
        self.center_dialog(dialog, 760, 560)

        ttk.Label(
            dialog,
            text=f"Маршрут: {route_data['route_name']} ({route_data['route_id']})",
            font=("Arial", 12, "bold")
        ).pack(pady=10)

        ttk.Label(
            dialog,
            text="Если заказ поступил до указанного дня и времени, он попадёт в выбранные доставку и сборку.",
            font=("Arial", 10)
        ).pack(padx=20, anchor='w')

        rules_frame = ttk.LabelFrame(dialog, text="Правила маршрута")
        rules_frame.pack(fill=tk.BOTH, expand=True, padx=20, pady=10)

        columns = ('cutoff_day', 'cutoff_time', 'delivery_day', 'production_day')
        rules_tree = ttk.Treeview(rules_frame, columns=columns, show='headings', height=8)
        rules_tree.heading('cutoff_day', text='Заказ до дня')
        rules_tree.heading('cutoff_time', text='Время')
        rules_tree.heading('delivery_day', text='Доставка')
        rules_tree.heading('production_day', text='Сборка')
        rules_tree.column('cutoff_day', width=170, anchor=tk.CENTER)
        rules_tree.column('cutoff_time', width=90, anchor=tk.CENTER)
        rules_tree.column('delivery_day', width=130, anchor=tk.CENTER)
        rules_tree.column('production_day', width=130, anchor=tk.CENTER)
        rules_tree.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        full_days = ['Понедельник', 'Вторник', 'Среда', 'Четверг', 'Пятница', 'Суббота', 'Воскресенье']
        rules_data = list(self._get_route_schedule_rules(route_data))
        selected_index = {'value': None}

        def sort_rules():
            rules_data.sort(key=lambda x: (int(x['cutoff_day']), str(x['cutoff_time']), int(x['delivery_day']), int(x['production_day'])))

        def refresh_rules_tree():
            sort_rules()
            rules_tree.delete(*rules_tree.get_children())
            for idx, rule in enumerate(rules_data):
                rules_tree.insert(
                    '',
                    'end',
                    iid=str(idx),
                    values=(
                        full_days[int(rule['cutoff_day'])],
                        str(rule['cutoff_time']),
                        full_days[int(rule['delivery_day'])],
                        full_days[int(rule['production_day'])]
                    )
                )

        editor_frame = ttk.Frame(dialog)
        editor_frame.pack(fill=tk.X, padx=20, pady=5)

        ttk.Label(editor_frame, text="Заказ до:").grid(row=0, column=0, padx=5, pady=5, sticky='w')
        cutoff_day_var = tk.StringVar(value=full_days[0])
        cutoff_day_combo = ttk.Combobox(editor_frame, textvariable=cutoff_day_var, values=full_days, state='readonly', width=16)
        cutoff_day_combo.grid(row=0, column=1, padx=5, pady=5, sticky='w')

        cutoff_time_var = tk.StringVar(value='14:00')
        ttk.Entry(editor_frame, textvariable=cutoff_time_var, width=10).grid(row=0, column=2, padx=5, pady=5, sticky='w')

        ttk.Label(editor_frame, text="Доставка:").grid(row=0, column=3, padx=5, pady=5, sticky='w')
        delivery_day_var = tk.StringVar(value=full_days[0])
        ttk.Combobox(editor_frame, textvariable=delivery_day_var, values=full_days, state='readonly', width=16).grid(row=0, column=4, padx=5, pady=5, sticky='w')

        ttk.Label(editor_frame, text="Сборка:").grid(row=0, column=5, padx=5, pady=5, sticky='w')
        production_day_var = tk.StringVar(value=full_days[0])
        ttk.Combobox(editor_frame, textvariable=production_day_var, values=full_days, state='readonly', width=16).grid(row=0, column=6, padx=5, pady=5, sticky='w')

        def clear_rule_editor():
            selected_index['value'] = None
            rules_tree.selection_remove(rules_tree.selection())
            cutoff_day_var.set(full_days[0])
            cutoff_time_var.set('14:00')
            delivery_day_var.set(full_days[0])
            production_day_var.set(full_days[0])

        def build_rule_from_editor():
            try:
                cutoff_time = datetime.strptime(str(cutoff_time_var.get() or '').strip(), "%H:%M").strftime("%H:%M")
            except Exception:
                messagebox.showwarning("Внимание", "Время должно быть в формате HH:MM")
                return None

            return {
                'cutoff_day': full_days.index(cutoff_day_var.get()),
                'cutoff_time': cutoff_time,
                'delivery_day': full_days.index(delivery_day_var.get()),
                'production_day': full_days.index(production_day_var.get())
            }

        buttons_inner = ttk.Frame(dialog)
        buttons_inner.pack(fill=tk.X, padx=20, pady=5)

        def add_or_update_rule():
            rule = build_rule_from_editor()
            if not rule:
                return

            idx = selected_index['value']
            if idx is None:
                rules_data.append(rule)
            else:
                rules_data[idx] = rule
            refresh_rules_tree()
            clear_rule_editor()

        def remove_rule():
            idx = selected_index['value']
            if idx is None:
                return
            del rules_data[idx]
            refresh_rules_tree()
            clear_rule_editor()

        ttk.Button(buttons_inner, text="Добавить / обновить правило", command=add_or_update_rule).pack(side=tk.LEFT, padx=5)
        ttk.Button(buttons_inner, text="Удалить правило", command=remove_rule).pack(side=tk.LEFT, padx=5)
        ttk.Button(buttons_inner, text="Очистить выбор", command=clear_rule_editor).pack(side=tk.LEFT, padx=5)

        def on_rule_select(event=None):
            selection = rules_tree.selection()
            if not selection:
                selected_index['value'] = None
                return

            idx = int(selection[0])
            selected_index['value'] = idx
            rule = rules_data[idx]
            cutoff_day_var.set(full_days[int(rule['cutoff_day'])])
            cutoff_time_var.set(str(rule['cutoff_time']))
            delivery_day_var.set(full_days[int(rule['delivery_day'])])
            production_day_var.set(full_days[int(rule['production_day'])])

        rules_tree.bind('<<TreeviewSelect>>', on_rule_select)
        refresh_rules_tree()

        button_frame = ttk.Frame(dialog)
        button_frame.pack(fill=tk.X, padx=20, pady=20)

        def save_route():
            if not rules_data:
                messagebox.showwarning("Внимание", "Добавьте хотя бы одно правило маршрута")
                return

            sort_rules()
            delivery_days = sorted({int(rule['delivery_day']) for rule in rules_data})
            cutoff_time = str(rules_data[0]['cutoff_time'])

            self.send_ws_message({
                'type': 'update_logistics_route',
                'route_id': route_data['route_id'],
                'delivery_days': delivery_days,
                'lead_time': route_data.get('lead_time', 1),
                'cutoff_time': cutoff_time,
                'schedule_rules': rules_data
            })

            messagebox.showinfo("Успех", f"Маршрут '{route_data['route_name']}' обновлён")
            dialog.destroy()

        ttk.Button(button_frame, text="💾 Сохранить", command=save_route).pack(side=tk.LEFT, padx=5)
        ttk.Button(button_frame, text="❌ Отмена", command=dialog.destroy).pack(side=tk.LEFT, padx=5)

    def _create_monolith_documents_subtab(self, parent):
        wrap = ttk.Frame(parent, padding=12)
        wrap.pack(fill=tk.BOTH, expand=True)

        top = ttk.Frame(wrap)
        top.pack(fill=tk.X, pady=(0, 8))
