        self.monolith_history_tree.heading('route', text='Маршрут')
        self.monolith_history_tree.heading('vehicle', text='Машина')
        self.monolith_history_tree.heading('boxes', text='Коробки')
        self.monolith_history_tree.heading('pallets', text='Паллеты')
        self.monolith_history_tree.heading('email', text='Email статус')
        self.monolith_history_tree.column('created', width=155, anchor=tk.CENTER)
        self.monolith_history_tree.column('delivery', width=120, anchor=tk.CENTER)
        self.monolith_history_tree.column('route', width=100, anchor=tk.CENTER)
        self.monolith_history_tree.column('vehicle', width=140, anchor=tk.CENTER)
        self.monolith_history_tree.column('boxes', width=90, anchor=tk.CENTER)
        self.monolith_history_tree.column('pallets', width=90, anchor=tk.CENTER)
        self.monolith_history_tree.column('email', width=220, anchor=tk.CENTER)
