    def admin_refresh_orders(self, orders_to_show=None):
        """
        ПОЛНАЯ ВЕРСИЯ: Заполнение таблицы данными.
        Включает: Склад, Лейблы, Маршрут, Сумму.
        """
        if not hasattr(self, 'admin_orders_tree'): return

        # Сохраняем текущее выделение и позицию скролла
        saved_selection = set()
        for item in self.admin_orders_tree.selection():
            vals = self.admin_orders_tree.item(item, 'values')
            if vals and vals[0] and not str(vals[0]).startswith('  â""'):
                saved_selection.add(str(vals[0]))
        saved_yview = self.admin_orders_tree.yview()

        # Настройка цветов
        self._configure_tree_tags(self.admin_orders_tree)

        self.admin_orders_tree.delete(*self.admin_orders_tree.get_children())

        source = orders_to_show if orders_to_show is not None else self.orders
        if not source: return

        # Диапазон дат из пикеров
        try:
            d_from = self.admin_date_from.get_date()
            d_to = self.admin_date_to.get_date()
        except:
            d_from = datetime.now().date()
            d_to = d_from + timedelta(days=365)

        today_str = datetime.now().strftime('%Y-%m-%d')
        grouped = {}
        search_query = self.admin_search_var.get().strip().lower() if hasattr(self, 'admin_search_var') else ''
        requires_boxes_only = bool(self.admin_requires_boxes_only_var.get()) if hasattr(self, 'admin_requires_boxes_only_var') else False

        # 1. ГРУППИРОВКА
        for oid, info in source.items():
            data = info.get('data', info)
            d = (data.get('production_date') or data.get('delivery_date') or "0000-00-00")

            # Фильтр по диапазону дат
            if d != "0000-00-00":
                try:
                    prod_dt = datetime.strptime(d, "%Y-%m-%d").date()
                    if not (d_from <= prod_dt <= d_to): continue
                except: pass
            if requires_boxes_only and not self._admin_order_needs_boxes(data):
                continue
            if not self._admin_order_matches_search(oid, data, search_query):
                continue

            if d not in grouped: grouped[d] = []
            grouped[d].append((oid, data))

        # 2. ОТРИСОВКА
        for d_key in sorted(grouped.keys()):
            # Заголовок даты
            try:
                if d_key == "0000-00-00": title = "📅 Дата не указана"
                else:
                    dt = datetime.strptime(d_key, "%Y-%m-%d")
                    wd_map = {"Monday":"Пн","Tuesday":"Вт","Wednesday":"Ср","Thursday":"Чт","Friday":"Пт","Saturday":"Сб","Sunday":"Вс"}
                    title = f"📅 {dt.strftime('%d.%m.%Y')} ({wd_map.get(dt.strftime('%A'), dt.strftime('%A'))})"
            except: title = f"❓ {d_key}"

            tag_date = 'today_group' if d_key == today_str else 'date_group'
            
            # Вставляем строку-группу (заглушки для колонок, чтобы не сдвигалось)
            # В values должно быть столько же элементов, сколько колонок.
            date_node = self.admin_orders_tree.insert('', tk.END, text='📅',
                values=("", "", title, "", f"{len(grouped[d_key])} зак.", "", "", "", "", "", "", "", ""),
                tags=(tag_date,), open=True)

            # Сортировка
            grouped[d_key].sort(key=lambda x: x[1].get('created_at', ''), reverse=True)

            for order_id, d_obj in grouped[d_key]:
                # --- ПОДГОТОВКА ДАННЫХ ---
                
                # 1. Прогресс
                arts = d_obj.get('artikel', [])
                s_req = sum(float(a.get('menge', 0)) for a in arts)
                s_got = sum(float(a.get('picked', 0)) for a in arts)
                
                # 2. Сборщик
                assigned = d_obj.get('assignment', {})
                worker = (
                    assigned.get('display_name')
                    or assigned.get('username')
                    or '-'
                ) if isinstance(assigned, dict) else "-"
                status_str = f"👷 {worker}" if worker != '-' else "⏳ Ждет"

                # 3. Статусы (Склад, Лейблы)
                wh_id = d_obj.get('warehouse_id', '1')
                is_printed = bool(d_obj.get('printed', False))
                lbl_str = "✅ ДА" if is_printed else "⏳ НЕТ"
                
                box_count = int(d_obj.get('boxes_count', 0))
                
                # 4. Маршрут и Сумма
                route_id_val = str(d_obj.get('route_id') or '').strip()
                route_name = d_obj.get('route_name') or route_id_val or '-'
                # Fallback: если в заказе "free/Свободный", пробуем показать маршрут из логистики клиента.
                route_name_l = str(route_name).lower()
                needs_route_fallback = (
                    route_id_val == 'free'
                    or not route_name
                    or 'свобод' in route_name_l
                    or route_name_l in ('free', 'free route')
                )
                if needs_route_fallback:
                    kunden_nr = str(d_obj.get('kunden_nr') or '').strip()
                    if kunden_nr:
                        kunden_norm = kunden_nr.lstrip('0') or kunden_nr
                        for lc in getattr(self, 'logistics_clients', []):
                            cid = str(lc.get('client_id') or '').strip()
                            cid_norm = cid.lstrip('0') or cid
                            if cid and (cid == kunden_nr or cid_norm == kunden_norm):
                                route_name = (
                                    lc.get('route_name')
                                    or lc.get('route_id')
                                    or route_name
                                )
                                break
                total_val = float(d_obj.get('total_value', 0))
                sum_str = f"{total_val:.2f} €" if total_val > 0 else ""
                email_sent = bool(d_obj.get('customer_email_sent'))
                mail_img = self._mail_icon_sent if email_sent else self._mail_icon_unsent
                mail_text_fallback = "📧" if email_sent else "-"

                # 5. Цвет строки (жирный для новых API заказов)
                is_api_new = d_obj.get('is_api_new', False)
                tag = 'order'
                if is_api_new:
                    tag = 'api_new'
                if worker != '-':
                    tag = 'api_new_in_progress' if is_api_new else 'order_in_progress'
                if is_printed and box_count > 0 and s_got >= s_req and s_req > 0:
                    tag = 'order_completed'

                # 6. Чистый ID (MO- заказы показываем с префиксом)
                if str(order_id).startswith('MO-'):
                    clean_id = str(order_id)
                else:
                    clean_id = str(order_id).replace('AB-', '').replace(' ', '').replace(',', '').split('.')[0]

                # --- ВСТАВКА ЗАКАЗА (13 колонок) ---
                order_node = self.admin_orders_tree.insert(
                    date_node,
                    tk.END,
                    text='',
                    image=(mail_img if email_sent else ''),
                    values=(
                        clean_id,                           # 1. ID
                        d_obj.get('created_at', '')[11:16], # 2. Время
                        d_obj.get('kunde', ''),             # 3. Клиент
                        mail_text_fallback,                 # 4. E-mail (гарантированно видимый индикатор)
                        f"{int(s_got)}/{int(s_req)}",      # 5. Прогресс
                        status_str,                        # 6. Статус
                        wh_id,                             # 7. Склад
                        lbl_str,                           # 8. Лейблы
                        route_name,                        # 9. Маршрут
                        sum_str,                           # 10. Сумма
                        d_obj.get('invoice_status', '⏳'),  # 11. Счет
                        f"📦 {box_count}" if box_count > 0 else "-", # 12. Коробки
                        d_key                              # 13. Дата
                    ),
                    tags=(tag,)
                )

        # Восстанавливаем выделение и позицию скролла
        if saved_selection:
            for date_node in self.admin_orders_tree.get_children():
                for order_node in self.admin_orders_tree.get_children(date_node):
                    vals = self.admin_orders_tree.item(order_node, 'values')
                    if vals and str(vals[0]) in saved_selection:
                        self.admin_orders_tree.selection_add(order_node)
        if saved_yview:
            self.admin_orders_tree.yview_moveto(saved_yview[0])

        # Обновляем кнопку переноса просроченных
        self._update_overdue_btn()
        self._admin_update_control_buttons()

    def _update_overdue_btn(self):
        """Обновить состояние кнопки переноса просроченных заказов"""
        if not hasattr(self, '_overdue_btn'):
            return
        today_str = datetime.now().strftime('%Y-%m-%d')
        count = 0
        for info in self.orders.values():
            o = info.get('data', info)
            if o.get('delivery_date', '9999') >= today_str:
                continue
            if o.get('status', '') in ('completed', 'archived'):
                continue
            # Если хоть одно из полей отгрузки заполнено — заказ отгружен
            if o.get('printed') or o.get('printed') == 1:
                continue
            if '✅' in str(o.get('invoice_status', '')):
                continue
            if int(o.get('boxes_count') or 0) > 0:
                continue
            count += 1
        btn = self._overdue_btn
        if count > 0:
            style = ToolbarButton.STYLES['warning']
            btn.bg_color = style['bg']
            btn.hover_color = style['hover']
            btn.fg_color = style['fg']
        else:
            style = ToolbarButton.STYLES['default']
            btn.bg_color = style['bg']
            btn.hover_color = style['hover']
            btn.fg_color = style['fg']
        # Обновляем текст с числом
        btn.text = f"📅 Перенос ({count})"
        btn.width = len(btn.text) * 8 + btn.padding * 2
        btn.config(width=btn.width)
        btn._draw()

    def create_admin_resources_tab(self, parent):
        """Вкладка управления производственными ресурсами"""
        # Панель инструментов
        toolbar = ttk.Frame(parent)
        toolbar.pack(fill=tk.X, padx=5, pady=5)

        ttk.Button(toolbar, text="🔄 Обновить", command=self.admin_resources_refresh).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="➕ Добавить", command=self.admin_resources_add).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="✏️ Редактировать", command=self.admin_resources_edit).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="🗑️ Удалить", command=self.admin_resources_delete).pack(side=tk.LEFT, padx=2)

        # Таблица ресурсов (однооконный layout без правой пустой панели)
        table_frame = ttk.Frame(parent)
        table_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)

        columns = ('ID', 'Ресурс', 'Тип', 'Кол-во', 'Смен', 'Смена (мин)', 'КПД', 'Мощность (ч)', 'Статус')
        self.admin_resources_tree = ttk.Treeview(table_frame, columns=columns, show='headings', height=15)

        # Заголовки и ширина колонок
        widths = [40, 200, 100, 80, 60, 100, 80, 120, 80]
        for col, width in zip(columns, widths):
            self.admin_resources_tree.heading(col, text=col)
            self.admin_resources_tree.column(col, width=width, anchor='center' if col != 'Ресурс' else 'w')

        scrollbar = ttk.Scrollbar(table_frame, orient=tk.VERTICAL, command=self.admin_resources_tree.yview)
        self.admin_resources_tree.configure(yscrollcommand=scrollbar.set)

        self.admin_resources_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=5, pady=5)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        self.admin_resources_tree.bind('<Double-Button-1>', lambda _: self.admin_resources_edit())

        # Подсказка
        hint_frame = ttk.Frame(parent)
        hint_frame.pack(fill=tk.X, padx=10, pady=5)

        ttk.Label(hint_frame,
                 text="💡 Управление производственными мощностями. Измените количество печей/смен для масштабирования",
                 font=("Arial", 9), foreground='gray').pack(anchor='w')

        # Загрузка данных
        self.admin_resources_refresh()

    def admin_resources_refresh(self):
        """Обновление списка ресурсов"""
        if not hasattr(self, 'ws') or not self.ws:
            messagebox.showwarning("Предупреждение", "Нет подключения к серверу")
            return

        try:
            asyncio.run_coroutine_threadsafe(
                self.ws.send(json.dumps({'type': 'get_resources'})),
                self.ws_loop
            )
        except Exception as e:
            messagebox.showerror("Ошибка", f"Не удалось обновить ресурсы: {e}")

    def admin_resources_edit(self):
        """Редактирование выбранного ресурса"""
        selection = self.admin_resources_tree.selection()
        if not selection:
            messagebox.showwarning("Предупреждение", "Выберите ресурс для редактирования")
            return

        item = self.admin_resources_tree.item(selection[0])
        values = item['values']

        resource_id = values[0]
        resource_name = values[1]
        quantity = values[3]
        shifts = values[4]
        duration = values[5]
        efficiency_str = values[6]

        # Преобразование КПД из строки "90%" в 0.9
        efficiency = float(efficiency_str.rstrip('%')) / 100.0

        # Диалог редактирования
        self.show_resource_edit_dialog(resource_id, resource_name, quantity, shifts, duration, efficiency)

    def show_resource_edit_dialog(self, resource_id, name, quantity, shifts, duration, efficiency):
        """Диалог редактирования ресурса"""
        dialog = tk.Toplevel(self)
        dialog.title(f"Редактирование: {name}")
        dialog.transient(self)
        dialog.grab_set()

        # Центрирование
        self.center_dialog(dialog, 550, 450)

        # Заголовок
        header = ttk.Label(dialog, text=f"🏭 {name}", font=("Arial", 14, "bold"))
        header.pack(pady=10)

        # Форма
        form = ttk.Frame(dialog)
        form.pack(fill=tk.BOTH, expand=True, padx=20, pady=10)

        # Количество оборудования/мест
        ttk.Label(form, text="Количество единиц:", font=("Arial", 10, "bold")).grid(row=0, column=0, sticky='w', pady=5)
        quantity_var = tk.IntVar(value=quantity)
        quantity_spin = ttk.Spinbox(form, from_=1, to=20, textvariable=quantity_var, width=15)
        quantity_spin.grid(row=0, column=1, sticky='w', pady=5, padx=5)
        ttk.Label(form, text="(печей, рабочих мест, линий)").grid(row=0, column=2, sticky='w', padx=5)

        # Количество смен
        ttk.Label(form, text="Количество смен:", font=("Arial", 10, "bold")).grid(row=1, column=0, sticky='w', pady=5)
        shifts_var = tk.IntVar(value=shifts)
        shifts_spin = ttk.Spinbox(form, from_=1, to=3, textvariable=shifts_var, width=15)
        shifts_spin.grid(row=1, column=1, sticky='w', pady=5, padx=5)
        ttk.Label(form, text="(1, 2 или 3 смены)").grid(row=1, column=2, sticky='w', padx=5)

        # Длительность смены
        ttk.Label(form, text="Длительность смены (мин):", font=("Arial", 10, "bold")).grid(row=2, column=0, sticky='w', pady=5)
        duration_var = tk.IntVar(value=duration)
        duration_spin = ttk.Spinbox(form, from_=60, to=720, increment=30, textvariable=duration_var, width=15)
        duration_spin.grid(row=2, column=1, sticky='w', pady=5, padx=5)
        duration_label = ttk.Label(form, text=f"({duration/60:.1f} часов)")
        duration_label.grid(row=2, column=2, sticky='w', padx=5)

        # Эффективность
        ttk.Label(form, text="Эффективность (КПД):", font=("Arial", 10, "bold")).grid(row=3, column=0, sticky='w', pady=5)
        efficiency_var = tk.DoubleVar(value=efficiency)
        efficiency_spin = ttk.Spinbox(form, from_=0.5, to=1.0, increment=0.05, textvariable=efficiency_var, width=15, format="%.2f")
        efficiency_spin.grid(row=3, column=1, sticky='w', pady=5, padx=5)
        efficiency_label = ttk.Label(form, text=f"({efficiency*100:.0f}% - учет простоев)")
        efficiency_label.grid(row=3, column=2, sticky='w', padx=5)

        # Разделитель
        ttk.Separator(form, orient='horizontal').grid(row=4, column=0, columnspan=3, sticky='ew', pady=15)

        # Предпросмотр мощности
        preview_label = ttk.Label(form, text="Новая мощность:", font=("Arial", 11, "bold"))
        preview_label.grid(row=5, column=0, sticky='w', pady=5)

        preview_value = ttk.Label(form, text="", font=("Arial", 12, "bold"), foreground="blue")
        preview_value.grid(row=5, column=1, columnspan=2, sticky='w', pady=5)

        def update_preview(*args):
            """Обновление предпросмотра мощности"""
            try:
                q = quantity_var.get()
                s = shifts_var.get()
                d = duration_var.get()
                e = efficiency_var.get()

                total_min = q * s * d * e
                total_hours = total_min / 60

                preview_value.config(text=f"{total_hours:.1f} часов/день ({total_min:.0f} минут)")
                duration_label.config(text=f"({d/60:.1f} часов)")
                efficiency_label.config(text=f"({e*100:.0f}% - учет простоев)")
            except:
                preview_value.config(text="---")

        # Привязка обновления предпросмотра
        quantity_var.trace_add('write', update_preview)
        shifts_var.trace_add('write', update_preview)
        duration_var.trace_add('write', update_preview)
        efficiency_var.trace_add('write', update_preview)

        update_preview()  # Начальное значение

        # Кнопки
        buttons = ttk.Frame(dialog)
        buttons.pack(fill=tk.X, padx=20, pady=15)

        def save_changes():
            """Сохранение изменений"""
            updates = {
                'quantity': quantity_var.get(),
                'shifts_count': shifts_var.get(),
                'shift_duration_min': duration_var.get(),
                'efficiency': efficiency_var.get()
            }

            try:
                asyncio.run_coroutine_threadsafe(
                    self.ws.send(json.dumps({
                        'type': 'update_resource',
                        'resource_id': resource_id,
                        'updates': updates
                    })),
                    self.ws_loop
                )

                dialog.destroy()
                messagebox.showinfo("Успешно", f"Ресурс '{name}' обновлен")

                # Обновление списка
                self.admin_resources_refresh()

            except Exception as e:
                messagebox.showerror("Ошибка", f"Не удалось сохранить изменения: {e}")

        ttk.Button(buttons, text="💾 Сохранить изменения", command=save_changes, width=25).pack(side=tk.LEFT, padx=5)
        ttk.Button(buttons, text="❌ Отмена", command=dialog.destroy, width=15).pack(side=tk.LEFT, padx=5)

        # Биндинг Enter для сохранения
        dialog.bind('<Return>', lambda e: save_changes())
        dialog.bind('<Escape>', lambda e: dialog.destroy())

