    def _build_unique_download_path(self, folder: Path, filename: str) -> Path:
        safe_name = str(filename or '').strip() or 'invoice.pdf'
        safe_name = Path(safe_name).name
        stem = Path(safe_name).stem or 'invoice'
        suffix = Path(safe_name).suffix or '.pdf'
        candidate = folder / f"{stem}{suffix}"
        index = 1
        while candidate.exists():
            candidate = folder / f"{stem}_{index}{suffix}"
            index += 1
        return candidate

    def admin_download_invoices(self):
        order_ids = self.get_all_selected_order_ids(self.admin_orders_tree)
        if not order_ids:
            messagebox.showwarning("Invoices", "Select at least one order with an invoice")
            return

        requests = []
        missing_orders = []
        seen_keys = set()

        for order_id in order_ids:
            order_info = self.orders.get(order_id, {})
            order_data = order_info.get('data', order_info) if isinstance(order_info, dict) else {}
            invoice_file = str(order_data.get('invoice_file') or '').strip()
            invoice_number = self._extract_order_invoice_for_monolith(order_id, order_data)
            fallback_name = invoice_file or (f"{invoice_number}.pdf" if invoice_number else f"invoice_{order_id}.pdf")
            dedupe_key = str(invoice_file or invoice_number or order_id).strip().lower()
            if not invoice_file and not invoice_number:
                missing_orders.append(str(order_id))
                continue
            if dedupe_key in seen_keys:
                continue
            seen_keys.add(dedupe_key)
            requests.append({
                'order_id': str(order_id),
                'invoice_file': invoice_file,
                'invoice_number': invoice_number,
                'suggested_name': Path(fallback_name).name,
            })

        if not requests:
            messagebox.showwarning("Invoices", "No linked invoice was found for the selected orders")
            return

        if len(requests) == 1:
            save_path = filedialog.asksaveasfilename(
                title="Download Invoice",
                initialfile=requests[0]['suggested_name'],
                defaultextension=".pdf",
                filetypes=[("PDF files", "*.pdf")]
            )
            if not save_path:
                return
            requests[0]['save_path'] = str(save_path)
        else:
            target_dir = filedialog.askdirectory(title="Choose Folder For Invoices")
            if not target_dir:
                return
            target_root = Path(target_dir)
            for req in requests:
                req['save_path'] = str(self._build_unique_download_path(target_root, req['suggested_name']))

        self.invoice_download_queue = list(requests)
        self.invoice_download_current = None
        self.invoice_download_results = []
        self.invoice_download_errors = []
        self.invoice_download_missing_orders = list(missing_orders)
        self._request_next_invoice_download()

    def _request_next_invoice_download(self):
        queue = list(getattr(self, 'invoice_download_queue', []) or [])
        if not queue:
            saved = list(getattr(self, 'invoice_download_results', []) or [])
            errors = list(getattr(self, 'invoice_download_errors', []) or [])
            missing = list(getattr(self, 'invoice_download_missing_orders', []) or [])
            self.invoice_download_current = None

            parts = []
            if saved:
                parts.append(f"Downloaded: {len(saved)}")
            if missing:
                parts.append(f"Without invoice: {len(missing)}")
            if errors:
                parts.append(f"Errors: {len(errors)}")
            message = "\n".join(parts) if parts else "No files to download."
            if saved and not errors:
                messagebox.showinfo("Invoices", message)
            elif saved or missing or errors:
                messagebox.showwarning("Invoices", message)
            else:
                messagebox.showinfo("Invoices", message)
            return

        current = queue.pop(0)
        self.invoice_download_queue = queue
        self.invoice_download_current = current
        sent = self.send_ws_message({
            'type': 'download_invoice_file',
            'order_id': current['order_id'],
            'invoice_file': current.get('invoice_file', ''),
            'invoice_number': current.get('invoice_number', ''),
        })
        if not sent:
            self.invoice_download_errors.append(f"{current['order_id']}: server connection unavailable")
            self.invoice_download_current = None
            self.after(0, self._request_next_invoice_download)

    def _handle_invoice_file_data(self, data: dict):
        current = getattr(self, 'invoice_download_current', None) or {}
        payload = str(data.get('file_data_b64') or '')
        if not payload:
            self.invoice_download_errors.append(f"{current.get('order_id', '?')}: empty file payload")
            self.invoice_download_current = None
            self._request_next_invoice_download()
            return

        save_path_raw = str(current.get('save_path') or '').strip()
        if not save_path_raw:
            self.invoice_download_errors.append(f"{current.get('order_id', '?')}: save path is missing")
            self.invoice_download_current = None
            self._request_next_invoice_download()
            return

        save_path = Path(save_path_raw)
        try:
            raw = base64.b64decode(payload.encode('ascii'), validate=False)
            save_path.parent.mkdir(parents=True, exist_ok=True)
            with open(save_path, 'wb') as f:
                f.write(raw)
            self.invoice_download_results.append(str(save_path))
        except Exception as e:
            self.invoice_download_errors.append(f"{current.get('order_id', '?')}: {e}")
        finally:
            self.invoice_download_current = None
            self._request_next_invoice_download()

    def _handle_invoice_file_error(self, data: dict):
        current = getattr(self, 'invoice_download_current', None) or {}
        order_id = str(data.get('order_id') or current.get('order_id') or '?')
        message = str(data.get('message') or 'failed to download invoice').strip()
        self.invoice_download_errors.append(f"{order_id}: {message}")
        self.invoice_download_current = None
        self._request_next_invoice_download()

