    def create_operator_interface_content(self, parent):
        """Интерфейс оператора (ИСПРАВЛЕННЫЙ РОДИТЕЛЬ)"""
        # Панель фильтров (используем parent!)
        filter_frame = ttk.Frame(parent)
        filter_frame.pack(fill=tk.X, padx=10, pady=5)

        ttk.Label(filter_frame, text="📅 Доставки С:", font=("Arial", 10)).pack(side=tk.LEFT, padx=5)
        self.op_date_from = DateEntry(filter_frame, width=12, date_pattern='yyyy-mm-dd')
        self.op_date_from.set_date(datetime.now())
        self.op_date_from.pack(side=tk.LEFT, padx=5)

        ttk.Label(filter_frame, text="ПО:", font=("Arial", 10)).pack(side=tk.LEFT, padx=5)
        self.op_date_to = DateEntry(filter_frame, width=12, date_pattern='yyyy-mm-dd')
        self.op_date_to.set_date(datetime.now() + timedelta(days=7))
        self.op_date_to.pack(side=tk.LEFT, padx=5)

        ttk.Button(filter_frame, text="🔎 Показать", command=self.operator_apply_filter).pack(side=tk.LEFT, padx=10)
        
        ttk.Button(filter_frame, text="🗑️ Очистить старые", command=self.operator_clear_old).pack(side=tk.RIGHT, padx=5)
        ttk.Button(filter_frame, text="📊 Статистика", command=self.operator_show_statistics).pack(side=tk.RIGHT, padx=5)
        ttk.Button(filter_frame, text="🔄 Обновить", command=self.operator_request_refresh).pack(side=tk.RIGHT, padx=5)

        # Таблица (используем parent!)
        columns = ('ID', 'Kunden-Nr', 'Клиент', 'Адрес', 'Артикулы', 'Этикетки', 'Счет', 'Коробки', 'Статус')
        self.operator_tree = ttk.Treeview(parent, columns=columns, show='tree headings', height=30)

        self.operator_tree.column('#0', width=40) 
        for col in columns:
            self.operator_tree.heading(col, text=col)
            if col == 'Адрес': self.operator_tree.column(col, width=300)
            elif col == 'Клиент': self.operator_tree.column(col, width=200)
            else: self.operator_tree.column(col, width=100)

        self._configure_tree_tags(self.operator_tree)

        # Скроллбар
        scrollbar = ttk.Scrollbar(parent, orient=tk.VERTICAL, command=self.operator_tree.yview)
        self.operator_tree.configure(yscrollcommand=scrollbar.set)

        self.operator_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=10)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        self.after(500, self.operator_apply_filter)

    def operator_apply_filter(self):
        """Фильтр оператора: Группировка по ДАТЕ ДОСТАВКИ"""
        if not hasattr(self, 'operator_tree'): return
        self.operator_tree.delete(*self.operator_tree.get_children())
        
        # Берем даты из календарей (DateEntry)
        d_from = self.op_date_from.get_date()
        d_to = self.op_date_to.get_date()
        
        orders_by_delivery = {}

        for order_id, info in self.orders.items():
            # ГИБКАЯ ПРОВЕРКА (Фикс KeyError 'data')
            data = info.get('data', info)
            
            # Фильтруем по дате доставки
            delivery_str = data.get('delivery_date')
            if not delivery_str:
                delivery_str = "0000-00-00"
            
            try:
                if delivery_str != "0000-00-00":
                    del_date = datetime.strptime(delivery_str, "%Y-%m-%d").date()
                    if not (d_from <= del_date <= d_to):
                        continue
            except:
                continue # Пропускаем битые даты
                
            if delivery_str not in orders_by_delivery:
                orders_by_delivery[delivery_str] = []
            orders_by_delivery[delivery_str].append((order_id, data))

        # Сортировка по датам
        for date_str in sorted(orders_by_delivery.keys()):
            orders = orders_by_delivery[date_str]
            
            # Заголовок группы даты
            try:
                if date_str == "0000-00-00":
                    d_disp = "📅 Дата не назначена"
                else:
                    d_obj = datetime.strptime(date_str, "%Y-%m-%d")
                    weekdays = ['Пн','Вт','Ср','Чт','Пт','Сб','Вс']
                    d_disp = f"🚚 {d_obj.strftime('%d.%m.%Y')} ({weekdays[d_obj.weekday()]})"
            except: d_disp = date_str

            grp_id = self.operator_tree.insert('', tk.END, text='📅',
                values=(d_disp, "", "", "", f"{len(orders)} зак.", "", "", "", ""),
                tags=('date_group',), open=True
            )
            
            for order_id, data in orders:
                art_list = data.get('artikel', [])
                total = len(art_list)
                picked_count = sum(1 for a in art_list if a.get('checked'))
                
                # Статусы и иконки
                tag = 'not_started'
                is_printed = data.get('printed', False)
                if picked_count >= total and total > 0: tag = 'completed'
                elif picked_count > 0: tag = 'in_progress'
                elif is_printed: tag = 'printed'
                
                lbl_st = '✅' if is_printed else '⏳'
                inv_st = data.get('invoice_status', '⏳')
                box_st = f"📦 {data.get('boxes_count')}" if data.get('boxes_count') else '-'
                
                self.operator_tree.insert(grp_id, tk.END, text='📦',
                    values=(
                        str(order_id).replace('AB-', ''),
                        data.get('kunden_nr', ''),
                        data.get('kunde', ''),
                        data.get('address', ''),
                        f"{picked_count}/{total} поз.",
                        lbl_st,
                        inv_st,
                        box_st,
                        data.get('status', '')
                    ), tags=(tag,))
    def operator_request_refresh(self):
        """Запросить обновление данных с сервера + проверка новых заказов из API"""
        self._do_refresh_with_api_scan()

    def operator_refresh(self):
        """Обновить отображение списка заказов"""
        # Применяем текущий фильтр к текущим данным
        self.operator_apply_filter()

    def operator_clear_old(self):
        """Удалить старые заказы (старше 7 дней)"""
        result = messagebox.askyesno("Подтверждение", "Удалить заказы старше 7 дней?")
        if not result:
            return

        cutoff_date = (datetime.now() - timedelta(days=7)).date()
        to_delete = []

        for order_id, order_info in self.orders.items():
            data = order_info['data']
            order_date_str = data.get('date', '')
            try:
                # Пробуем разные форматы даты
                if '.' in order_date_str:
                    order_date = datetime.strptime(order_date_str, "%d.%m.%Y").date()
                else:
                    order_date = datetime.strptime(order_date_str, "%Y-%m-%d").date()
                if order_date < cutoff_date:
                    to_delete.append(order_id)
            except:
                pass

        for order_id in to_delete:
            del self.orders[order_id]

        self.operator_apply_filter()
        messagebox.showinfo("Готово", f"Удалено {len(to_delete)} заказов")

    def operator_show_statistics(self):
        """Окно статистики: Графики и KPI сборщиков (Админ + Оператор)"""
        from tkcalendar import DateEntry
        try:
            from matplotlib.figure import Figure
            from matplotlib.backends.backend_tkagg import FigureCanvasTkAgg
        except ImportError:
            messagebox.showerror("Ошибка", "Библиотека Matplotlib не установлена. Выполните: pip install matplotlib")
            return

        # Создаем окно
        stats_window = tk.Toplevel(self)
        stats_window.title("📊 Эффективность работы склада (KPI)")
        stats_window.geometry("1100x750")
        stats_window.transient(self)
        stats_window.grab_set()

        # Панель фильтров
        filter_frame = ttk.Frame(stats_window)
        filter_frame.pack(fill=tk.X, padx=10, pady=10)

        ttk.Label(filter_frame, text="Период статистики:", font=("Arial", 10, "bold")).pack(side=tk.LEFT, padx=5)

        ttk.Label(filter_frame, text="С:").pack(side=tk.LEFT, padx=2)
        start_date_picker = DateEntry(filter_frame, width=12, date_pattern='yyyy-mm-dd')
        start_date_picker.set_date(datetime.now() - timedelta(days=7)) # За неделю по умолчанию
        start_date_picker.pack(side=tk.LEFT, padx=5)

        ttk.Label(filter_frame, text="По:").pack(side=tk.LEFT, padx=2)
        end_date_picker = DateEntry(filter_frame, width=12, date_pattern='yyyy-mm-dd')
        end_date_picker.set_date(datetime.now())
        end_date_picker.pack(side=tk.LEFT, padx=5)

        # Контент (Таблица + График)
        content_frame = ttk.Frame(stats_window)
        content_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=5)

        # ЛЕВО: ТАБЛИЦА
        left_f = ttk.LabelFrame(content_frame, text="Детальный отчет")
        left_f.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        cols = ('Сборщик', 'Заказов', 'Тортов (шт)')
        self.current_stats_tree = ttk.Treeview(left_f, columns=cols, show='headings')
        for c in cols: self.current_stats_tree.heading(c, text=c)
        self.current_stats_tree.pack(fill=tk.BOTH, expand=True)

        # ПРАВО: ГРАФИК
        right_f = ttk.LabelFrame(content_frame, text="Диаграмма нагрузки")
        right_f.pack(side=tk.RIGHT, fill=tk.BOTH, expand=True, padx=(10, 0))

        self.current_stats_figure = Figure(figsize=(5, 5), dpi=100)
        self.current_stats_canvas = FigureCanvasTkAgg(self.current_stats_figure, master=right_f)
        self.current_stats_canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)

        def request_data():
            """Отправить запрос на сервер"""
            self.send_ws_message({
                'type': 'get_picking_statistics',
                'start_date': start_date_picker.get_date().strftime('%Y-%m-%d'),
                'end_date': end_date_picker.get_date().strftime('%Y-%m-%d')
            })

        ttk.Button(filter_frame, text="🔄 Обновить данные", command=request_data).pack(side=tk.LEFT, padx=10)

        # Запрашиваем данные сразу при открытии
        request_data()

