    def warehouse_search_clients(self):
        query = self.wh_client_search_var.get().strip() if hasattr(self, 'wh_client_search_var') else ''
        self.warehouse_fill_clients_search_from_known(query)
        self.send_ws_message({'type': 'search_warehouse_clients', 'query': query})

    def warehouse_fill_clients_search_from_known(self, query=''):
        if not hasattr(self, 'wh_client_search_tree'):
            return
        q = str(query or '').strip().lower()
        all_clients = list((self.wh_client_known or {}).values())
        if q:
            filtered = [c for c in all_clients if q in str(c.get('client_id', '')).lower() or q in str(c.get('client_name', '')).lower()]
        else:
            filtered = all_clients
        filtered.sort(key=lambda x: (str(x.get('client_name', '')).lower(), str(x.get('client_id', ''))))
        self.wh_client_search_tree.delete(*self.wh_client_search_tree.get_children())
        for cl in filtered[:200]:
            cid = str(cl.get('client_id', '')).strip()
            if not cid:
                continue
            self.wh_client_search_tree.insert('', tk.END, iid=f"search_{cid}", values=(cid, cl.get('client_name', '')))

    def warehouse_fill_clients_search(self, clients):
        self.wh_client_search_results = clients or []
        for cl in self.wh_client_search_results:
            cid = str(cl.get('client_id', '')).strip()
            if cid:
                self.wh_client_known[cid] = {'client_id': cid, 'client_name': cl.get('client_name', '')}
        current_query = self.wh_client_search_var.get().strip() if hasattr(self, 'wh_client_search_var') else ''
        self.warehouse_fill_clients_search_from_known(current_query)

    def warehouse_add_client_from_search(self):
        if not hasattr(self, 'wh_client_search_tree'):
            return
        sel = self.wh_client_search_tree.selection()
        if not sel:
            return
        vals = self.wh_client_search_tree.item(sel[0], 'values')
        if not vals:
            return
        cid = str(vals[0])
        cname = str(vals[1]) if len(vals) > 1 else ''

        exists = any(str(x.get('client_id')) == cid for x in self.wh_client_print_selected)
        if not exists:
            self.wh_client_print_selected.append({'client_id': cid, 'client_name': cname})
        norm = self._normalize_client_id(cid)
        if cid not in self.wh_client_print_settings and norm not in self.wh_client_print_settings:
            self.wh_client_print_settings[cid] = {
                'language': 'DE (+7°C)',
                'use_conditional': True,
                'client_name': cname
            }
        self.warehouse_refresh_selected_clients_tree()

    def warehouse_refresh_selected_clients_tree(self):
        if not hasattr(self, 'wh_client_selected_tree'):
            return
        self.wh_client_selected_tree.delete(*self.wh_client_selected_tree.get_children())
        for cl in self.wh_client_print_selected:
            cid = str(cl.get('client_id', ''))
            norm = self._normalize_client_id(cid)
            cfg = self.wh_client_print_settings.get(cid) or self.wh_client_print_settings.get(norm) or {}
            lang = cfg.get('language', 'DE (+7°C)')
            mode = 'Условные' if cfg.get('use_conditional', False) else 'Все'
            self.wh_client_selected_tree.insert('', tk.END, iid=f"cfg_{cid}", values=(cid, cl.get('client_name', ''), lang, mode))

    def warehouse_open_client_settings_dialog(self, event=None):
        if not hasattr(self, 'wh_client_selected_tree'):
            return
        sel = self.wh_client_selected_tree.selection()
        if not sel:
            return
        vals = self.wh_client_selected_tree.item(sel[0], 'values')
        if not vals:
            return
        cid = str(vals[0])
        cname = str(vals[1]) if len(vals) > 1 else ''
        norm = self._normalize_client_id(cid)
        cfg = self.wh_client_print_settings.get(cid) or self.wh_client_print_settings.get(norm) or {}
        dialog = tk.Toplevel(self)
        dialog.title(f"Настройки печати: {cid}")
        dialog.transient(self)
        dialog.grab_set()
        self.center_dialog(dialog, 500, 240)

        frame = ttk.Frame(dialog, padding=14)
        frame.pack(fill=tk.BOTH, expand=True)

        ttk.Label(frame, text=f"{cid} - {cname}", font=("Segoe UI", 11, "bold")).grid(row=0, column=0, columnspan=4, sticky='w', pady=(0, 10))
        ttk.Label(frame, text="Язык этикеток:").grid(row=1, column=0, sticky='w', padx=(0, 6), pady=4)
        lang_var = tk.StringVar(value=cfg.get('language', 'DE (+7°C)'))
        ttk.Combobox(frame, textvariable=lang_var, values=list(CONFIG['LABEL_LANGUAGES'].keys()),
                     state='readonly', width=28).grid(row=1, column=1, sticky='w', pady=4)

        ttk.Label(frame, text="Печатать:").grid(row=2, column=0, sticky='w', padx=(0, 6), pady=4)
        mode_var = tk.StringVar(value='conditional' if cfg.get('use_conditional', False) else 'all')
        ttk.Radiobutton(frame, text='Все этикетки', value='all', variable=mode_var).grid(row=2, column=1, sticky='w', pady=4)
        ttk.Radiobutton(frame, text='Только не условные', value='conditional', variable=mode_var).grid(row=3, column=1, sticky='w', pady=2)

        btns = ttk.Frame(frame)
        btns.grid(row=4, column=0, columnspan=4, sticky='e', pady=(12, 0))

        def _save():
            self.wh_client_print_settings[cid] = {
                'language': lang_var.get(),
                'use_conditional': mode_var.get() == 'conditional',
                'client_name': cname
            }
            self.wh_client_print_settings[norm] = dict(self.wh_client_print_settings[cid])
            self.warehouse_refresh_selected_clients_tree()
            dialog.destroy()

        ttk.Button(btns, text="Отмена", command=dialog.destroy).pack(side=tk.RIGHT, padx=(6, 0))
        ttk.Button(btns, text="Сохранить", style="Accent.TButton", command=_save).pack(side=tk.RIGHT)

    def warehouse_remove_client_from_selected(self):
        if not hasattr(self, 'wh_client_selected_tree'):
            return
        sel = self.wh_client_selected_tree.selection()
        if not sel:
            return
        vals = self.wh_client_selected_tree.item(sel[0], 'values')
        if not vals:
            return
        cid = str(vals[0])
        norm = self._normalize_client_id(cid)
        self.wh_client_print_selected = [cl for cl in self.wh_client_print_selected if str(cl.get('client_id')) != cid]
        self.wh_client_print_settings.pop(cid, None)
        self.wh_client_print_settings.pop(norm, None)
        self.warehouse_refresh_selected_clients_tree()

    def warehouse_save_print_settings(self):
        settings_to_save = {}
        for cl in self.wh_client_print_selected:
            cid = str(cl.get('client_id', '')).strip()
            if not cid:
                continue
            norm = self._normalize_client_id(cid)
            cfg = self.wh_client_print_settings.get(cid) or self.wh_client_print_settings.get(norm) or {}
            settings_to_save[norm] = {
                'language': cfg.get('language', 'DE (+7°C)'),
                'use_conditional': bool(cfg.get('use_conditional', True)),
                'client_name': cl.get('client_name', '')
            }
        if hasattr(self, 'wh_client_save_status_var'):
            self.wh_client_save_status_var.set("Сохранение...")
        self.send_ws_message({'type': 'save_warehouse_print_settings', 'settings': settings_to_save})

