    def warehouse_refresh_jobs(self):
        """Обновить задания (По дате доставки)"""
        self.warehouse_jobs_tree.delete(*self.warehouse_jobs_tree.get_children())

        d_from = self.wh_date_from.get_date()
        d_to = self.wh_date_to.get_date()

        orders_by_delivery = {}

        for order_id, order_info in self.orders.items():
            data = order_info['data']
            if data.get('warehouse_id') != self.warehouse_id: continue

            # Дата ДОСТАВКИ
            del_str = data.get('delivery_date', '')
            if not del_str: continue # Без даты доставки пропускаем (или кидаем в errors)
            
            try:
                del_date = datetime.strptime(del_str, "%Y-%m-%d").date()
            except: continue

            # ФИЛЬТР КАЛЕНДАРЯ
            if not (d_from <= del_date <= d_to):
                continue

            if del_str not in orders_by_delivery:
                orders_by_delivery[del_str] = []
            orders_by_delivery[del_str].append((order_id, data))

        # Сортировка
        sorted_dates = sorted(orders_by_delivery.keys())

        for date_str in sorted_dates:
            # ... (Код отображения группы и заказов такой же как раньше) ...
            pass 
            # (Скопируй внутренности цикла из моего предыдущего сообщения про Склад,
            # где формируется date_item и order_item)

    def warehouse_reset_picking_date_filters_today(self):
        """Быстрый возврат фильтра вкладки комплектации к сегодняшней дате."""
        if not hasattr(self, 'pick_date_from') or not hasattr(self, 'pick_date_to'):
            return
        today = datetime.now()
        self.pick_date_from.set_date(today)
        self.pick_date_to.set_date(today + timedelta(days=365))
        self.warehouse_filter_orders()

    def warehouse_reset_jobs_date_filters_today(self):
        """Быстрый возврат фильтра вкладки заданий к сегодняшней дате."""
        if not hasattr(self, 'wh_date_from') or not hasattr(self, 'wh_date_to'):
            return
        today = datetime.now()
        self.wh_date_from.set_date(today)
        self.wh_date_to.set_date(today + timedelta(days=365))
        self.warehouse_refresh_jobs()

