    def _warehouse_init_search_paned_sash(self):
        paned = getattr(self, 'search_labels_paned', None)
        if paned is None or not paned.winfo_exists():
            return
        total_h = paned.winfo_height()
        if total_h < 220:
            try:
                self.after(120, self._warehouse_init_search_paned_sash)
            except Exception:
                pass
            return
        # Стартовое деление: журнал ~28%, далее пользователь двигает разделитель вручную.
        top_h = int(total_h * 0.72)
        top_h = max(170, min(total_h - 100, top_h))
        try:
            paned.sashpos(0, top_h)
        except Exception:
            pass

