    def _refresh_comm_dialogs_ui(self):
        if not hasattr(self, 'comm_dialogs_list'):
            return
        active_idx = None
        self.comm_dialogs_list.delete(0, tk.END)
        for i, d in enumerate((self.comm_dialogs or [])):
            did = int(d.get('dialog_id', 0)) if str(d.get('dialog_id', '')).isdigit() else 0
            unread_cnt = int(self.comm_unread_by_dialog.get(did, 0))
            title = str(d.get('title') or f"Dialog {d.get('dialog_id')}")
            sender = str(self.comm_last_sender_by_dialog.get(did, '') or '').strip()
            txt = title
            if unread_cnt > 0:
                txt = f"{title} - {sender or 'новые'} - {unread_cnt}"
            self.comm_dialogs_list.insert(tk.END, txt)
            try:
                if unread_cnt > 0:
                    self.comm_dialogs_list.itemconfig(i, font=("Segoe UI", 11, "bold"))
                else:
                    self.comm_dialogs_list.itemconfig(i, font=("Segoe UI", 11, "normal"))
            except Exception:
                pass
            if self.comm_active_dialog_id and int(self.comm_active_dialog_id) == did:
                active_idx = i
        if active_idx is not None:
            self.comm_dialogs_list.selection_clear(0, tk.END)
            self.comm_dialogs_list.selection_set(active_idx)

    def _refresh_comm_users_ui(self):
        if not hasattr(self, 'comm_users_list'):
            return
        self.comm_users_list.delete(0, tk.END)
        self.comm_private_user_ids_by_index = []
        me = int(self.current_user_id) if str(self.current_user_id).isdigit() else 0
        for u in sorted((self.comm_users or []), key=lambda x: self._comm_user_display(x).lower()):
            uid = int(u.get('user_id')) if str(u.get('user_id', '')).isdigit() else 0
            if uid <= 0 or uid == me:
                continue
            label = self._comm_user_display(u)
            self.comm_private_user_ids_by_index.append(uid)
            self.comm_users_list.insert(tk.END, label)

    def _refresh_comm_members_label(self):
        if not hasattr(self, 'comm_members_label'):
            return
        did = int(self.comm_active_dialog_id or 0)
        members = self.comm_members_by_dialog.get(did, []) if did > 0 else []
        if not members:
            self.comm_members_label.config(text="Участники: -")
            return
        names = ", ".join(self._comm_user_display(m) for m in members)
        self.comm_members_label.config(text=f"Участники: {names}", wraplength=900)

    def _comm_load_older_messages(self):
        dialog_id = int(self.comm_active_dialog_id or 0)
        if dialog_id <= 0:
            return
        if dialog_id in self.comm_no_more_old_by_dialog:
            return
        if dialog_id in self.comm_loading_old_dialogs:
            return
        msgs = self.comm_messages_cache.get(dialog_id, []) or []
        if not msgs:
            return
        oldest = msgs[0]
        before_id = int(oldest.get('message_id') or 0) if str(oldest.get('message_id', '')).isdigit() else 0
        if before_id <= 0:
            return
        self.comm_loading_old_dialogs.add(dialog_id)
        self.send_ws_message({
            'type': 'get_comm_messages',
            'dialog_id': dialog_id,
            'limit': 50,
            'before_message_id': before_id,
            'mode': 'prepend'
        })

    def _comm_show_scrollbar_temporarily(self, ms: int = 900):
        if not hasattr(self, 'comm_msg_scrollbar'):
            return
        try:
            if not self.comm_msg_scrollbar.winfo_ismapped():
                self.comm_msg_scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
            if self._comm_scroll_hide_after_id is not None:
                self.after_cancel(self._comm_scroll_hide_after_id)
                self._comm_scroll_hide_after_id = None

            def _hide():
                self._comm_scroll_hide_after_id = None
                try:
                    if self.comm_msg_scrollbar.winfo_exists():
                        self.comm_msg_scrollbar.pack_forget()
                except Exception:
                    pass

            self._comm_scroll_hide_after_id = self.after(int(ms), _hide)
        except Exception:
            pass

    def _bind_comm_global_mousewheel(self, _event=None):
        return

    def _unbind_comm_global_mousewheel(self, _event=None):
        return

    def _on_comm_mousewheel(self, event):
        if not hasattr(self, 'comm_messages_canvas'):
            return
        self._comm_show_scrollbar_temporarily(1100)
        delta_steps = 0
        if hasattr(event, 'delta') and event.delta:
            delta_steps = -1 if event.delta > 0 else 1
        elif getattr(event, 'num', None) == 4:
            delta_steps = -1
        elif getattr(event, 'num', None) == 5:
            delta_steps = 1
        if delta_steps != 0:
            try:
                self.comm_messages_canvas.yview_scroll(delta_steps * 3, "units")
            except Exception:
                pass
        try:
            top = float(self.comm_messages_canvas.yview()[0])
        except Exception:
            return
        is_up = False
        if hasattr(event, 'delta') and event.delta:
            is_up = event.delta > 0
        elif getattr(event, 'num', None) == 4:
            is_up = True
        if is_up and top <= 0.02:
            self._comm_load_older_messages()
        return "break"

    def _comm_send_attachment(self):
        if self.comm_active_dialog_id is None:
            messagebox.showwarning('Communication', 'Select a dialog')
            return
        path = filedialog.askopenfilename(
            title="Выберите файл",
            filetypes=[("All files", "*.*")]
        )
        if not path:
            return
        try:
            file_size = os.path.getsize(path)
            if file_size > 8 * 1024 * 1024:
                messagebox.showwarning("Файл", "Максимальный размер файла 8MB")
                return
            with open(path, 'rb') as f:
                data = f.read()
            file_name = os.path.basename(path)
            mime_type = mimetypes.guess_type(path)[0] or "application/octet-stream"
            self._comm_send_attachment_payload(file_name, mime_type, data)
        except Exception as e:
            messagebox.showerror("Файл", f"Ошибка отправки: {e}")

    def _comm_download_attachment(self, message_id: int):
        if int(message_id or 0) <= 0:
            return
        self.send_ws_message({'type': 'get_comm_attachment', 'message_id': int(message_id)})

    def _comm_send_attachment_payload(self, file_name: str, mime_type: str, data: bytes):
        if self.comm_active_dialog_id is None:
            return
        if not data:
            return
        self.send_ws_message({
            'type': 'send_comm_attachment',
            'dialog_id': int(self.comm_active_dialog_id),
            'file_name': str(file_name or 'file.bin'),
            'mime_type': str(mime_type or 'application/octet-stream'),
            'file_data_b64': base64.b64encode(bytes(data)).decode('ascii')
        })

    def _comm_entry_ctrl_c(self, event):
        try:
            event.widget.event_generate("<<Copy>>")
        except Exception:
            pass
        return "break"

    def _comm_entry_ctrl_x(self, event):
        try:
            event.widget.event_generate("<<Cut>>")
        except Exception:
            pass
        return "break"

    def _comm_entry_ctrl_v(self, event):
        # 1) Try image from clipboard first (screenshot / copied image)
        try:
            from PIL import ImageGrab
            img = ImageGrab.grabclipboard()
        except Exception:
            img = None
        if img is None:
            # 2) regular text paste fallback
            try:
                event.widget.event_generate("<<Paste>>")
            except Exception:
                pass
            return "break"

        # ImageGrab on Windows can return list of file paths; send first file
        if isinstance(img, list) and img:
            path = img[0]
            try:
                with open(path, 'rb') as f:
                    data = f.read()
                if len(data) > 8 * 1024 * 1024:
                    messagebox.showwarning("Файл", "Максимальный размер файла 8MB")
                    return "break"
                file_name = os.path.basename(path)
                mime_type = mimetypes.guess_type(path)[0] or "application/octet-stream"
                self._comm_send_attachment_payload(file_name, mime_type, data)
            except Exception as e:
                messagebox.showerror("Буфер", f"Ошибка вставки файла: {e}")
            return "break"

        # PIL Image object -> convert to PNG bytes
        try:
            import io
            buf = io.BytesIO()
            img.save(buf, format='PNG')
            data = buf.getvalue()
            if len(data) > 8 * 1024 * 1024:
                messagebox.showwarning("Скриншот", "Скриншот больше 8MB, уменьшите размер")
                return "break"
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            self._comm_send_attachment_payload(f"screenshot_{ts}.png", "image/png", data)
        except Exception as e:
            messagebox.showerror("Скриншот", f"Ошибка вставки скриншота: {e}")
        return "break"

    def _on_private_user_double_click(self):
        if not hasattr(self, 'comm_users_list'):
            return
        sel = self.comm_users_list.curselection()
        if not sel:
            return
        idx = sel[0]
        if idx < 0 or idx >= len(self.comm_private_user_ids_by_index):
            return
        uid = int(self.comm_private_user_ids_by_index[idx])
        self.send_ws_message({'type': 'open_private_dialog', 'other_user_id': uid})

    def _on_comm_dialog_right_click(self, event):
        if not hasattr(self, 'comm_dialogs_list'):
            return
        idx = self.comm_dialogs_list.nearest(event.y)
        if idx < 0 or idx >= len(self.comm_dialogs or []):
            return
        self.comm_dialogs_list.selection_clear(0, tk.END)
        self.comm_dialogs_list.selection_set(idx)
        self.comm_dialogs_list.activate(idx)
        dialog = self.comm_dialogs[idx]
        dialog_id = int(dialog.get('dialog_id') or 0) if str(dialog.get('dialog_id', '')).isdigit() else 0
        if dialog_id <= 0:
            return
        is_owner = int(dialog.get('created_by') or 0) == int(self.current_user_id or 0)
        menu = tk.Menu(self, tearoff=0)
        if is_owner or str(self.user_role) == 'admin':
            menu.add_command(
                label='Удалить группу',
                command=lambda did=dialog_id: self._comm_leave_or_delete_dialog(did, 'delete')
            )
        menu.add_command(
            label='Выйти из группы',
            command=lambda did=dialog_id: self._comm_leave_or_delete_dialog(did, 'leave')
        )
        try:
            menu.tk_popup(event.x_root, event.y_root)
        finally:
            menu.grab_release()

    def _comm_leave_or_delete_dialog(self, dialog_id: int, action: str):
        if int(dialog_id or 0) <= 0:
            return
        if action == 'delete':
            if not messagebox.askyesno('Диалоги', 'Удалить группу для всех участников?'):
                return
        else:
            if not messagebox.askyesno('Диалоги', 'Выйти из выбранной группы?'):
                return
        self.send_ws_message({
            'type': 'leave_or_delete_comm_dialog',
            'dialog_id': int(dialog_id),
            'action': action
        })

    def _refresh_comm_messages_ui(self):
        if not hasattr(self, 'comm_messages_frame'):
            return
        for child in self.comm_messages_frame.winfo_children():
            child.destroy()
        self.comm_message_cards = {}
        self._refresh_comm_members_label()

        if self.comm_active_dialog_id is None:
            return
        msgs = self.comm_messages_cache.get(int(self.comm_active_dialog_id), []) or []
        if not msgs:
            tk.Label(
                self.comm_messages_frame,
                text="Нет сообщений",
                bg=self.colors["bg_card"],
                fg=self.colors["text_light"],
                font=("Segoe UI", 10)
            ).pack(pady=20)
            return

        batch_size = 16

        def render_batch(start_idx=0):
            end_idx = min(start_idx + batch_size, len(msgs))
            for m in msgs[start_idx:end_idx]:
                self._append_comm_message_card(m, animate=False, auto_scroll=False)
            if end_idx < len(msgs):
                self.after(1, lambda: render_batch(end_idx))
            else:
                self.after_idle(self._scroll_comm_to_bottom)

        render_batch(0)

    def _scroll_comm_to_bottom(self):
        if hasattr(self, 'comm_messages_canvas'):
            try:
                self.comm_messages_canvas.yview_moveto(1.0)
                self.after(24, lambda: self.comm_messages_canvas.yview_moveto(1.0))
                self.after(90, lambda: self.comm_messages_canvas.yview_moveto(1.0))
                self.after(180, lambda: self.comm_messages_canvas.yview_moveto(1.0))
            except Exception:
                pass

    def _append_comm_message_card(self, m: dict, animate: bool = True, auto_scroll: bool = True):
        if not hasattr(self, 'comm_messages_frame'):
            return
        c = self.colors
        who = str(m.get('sender_name') or m.get('sender_id') or '-')
        ts = str(m.get('created_at') or '')[11:16]
        txt = str(m.get('message_text') or '')
        msg_id = int(m.get('message_id') or 0) if str(m.get('message_id', '')).isdigit() else 0
        is_mine = bool(self.current_user_id and str(m.get('sender_id', '')).isdigit() and int(m.get('sender_id')) == int(self.current_user_id))
        has_attachment = int(m.get('has_attachment') or 0) == 1
        attachment_name = str(m.get('attachment_name') or '').strip()
        try:
            attachment_size = int(m.get('attachment_size') or 0)
        except Exception:
            attachment_size = 0
        row = tk.Frame(self.comm_messages_frame, bg=c["bg_card"])
        row.pack(fill=tk.X, padx=10, pady=5)

        canvas_w = self.comm_messages_canvas.winfo_width() if hasattr(self, 'comm_messages_canvas') else 980
        bubble_max = max(320, int(canvas_w * 0.60))
        bubble_bg = "#DDE9FF" if is_mine else "#F8FAFF"

        if is_mine:
            content = tk.Frame(row, bg=c["bg_card"])
            content.pack(side=tk.RIGHT, anchor='e')
            bubble = tk.Frame(content, bg=bubble_bg, highlightbackground="#C8D8FF", highlightthickness=1, bd=0)
            bubble.pack(side=tk.LEFT, padx=(0, 6))
            header = tk.Frame(bubble, bg=bubble_bg)
            header.pack(fill=tk.X, padx=12, pady=(8, 2))
            tk.Label(header, text=ts, bg=bubble_bg, fg=c["text_light"], font=("Segoe UI", 10)).pack(side=tk.LEFT)
            receipt = "✓✓" if int(m.get('seen_by_all') or 0) == 1 else "✓"
            rl = tk.Label(header, text=receipt, bg=bubble_bg, fg="#3D7BEB", font=("Segoe UI", 10, "bold"))
            rl.pack(side=tk.LEFT, padx=(8, 0))
            tk.Label(
                bubble, text=txt, bg=bubble_bg, fg=c["text_main"], font=("Segoe UI", 12),
                anchor='w', justify='left', wraplength=bubble_max
            ).pack(fill=tk.X, padx=12, pady=(0, 8))
            if has_attachment:
                ftxt = f"📎 {attachment_name or 'file'} ({max(1, attachment_size // 1024)} KB)"
                fl = tk.Label(
                    bubble, text=ftxt, bg=bubble_bg, fg="#1F4FAE", cursor="hand2",
                    font=("Segoe UI", 10, "underline"), anchor='w', justify='left'
                )
                fl.pack(fill=tk.X, padx=12, pady=(0, 8))
                if msg_id > 0:
                    fl.bind("<Button-1>", lambda _e, mid=msg_id: self._comm_download_attachment(mid))
            avatar = tk.Canvas(content, width=38, height=38, bg=c["bg_card"], highlightthickness=0, bd=0)
            avatar.pack(side=tk.RIGHT, padx=(0, 2), pady=2)
            avatar.create_oval(2, 2, 36, 36, fill="#5D8EF4", outline="#5D8EF4")
            avatar.create_text(19, 19, text=(who[:1] or "?").upper(), fill="#FFFFFF", font=("Segoe UI", 11, "bold"))
            if msg_id > 0:
                self.comm_message_cards[msg_id] = {'card': bubble, 'receipt': rl}
        else:
            content = tk.Frame(row, bg=c["bg_card"])
            content.pack(side=tk.LEFT, anchor='w')
            avatar = tk.Canvas(content, width=38, height=38, bg=c["bg_card"], highlightthickness=0, bd=0)
            avatar.pack(side=tk.LEFT, padx=(2, 6), pady=2)
            avatar.create_oval(2, 2, 36, 36, fill="#5D8EF4", outline="#5D8EF4")
            avatar.create_text(19, 19, text=(who[:1] or "?").upper(), fill="#FFFFFF", font=("Segoe UI", 11, "bold"))
            bubble = tk.Frame(content, bg=bubble_bg, highlightbackground=c["border"], highlightthickness=1, bd=0)
            bubble.pack(side=tk.LEFT)
            header = tk.Frame(bubble, bg=bubble_bg)
            header.pack(fill=tk.X, padx=12, pady=(8, 2))
            tk.Label(header, text=who, bg=bubble_bg, fg=c["text_main"], font=("Segoe UI", 12, "bold")).pack(side=tk.LEFT)
            tk.Label(header, text=ts, bg=bubble_bg, fg=c["text_light"], font=("Segoe UI", 10)).pack(side=tk.LEFT, padx=(8, 0))
            tk.Label(
                bubble, text=txt, bg=bubble_bg, fg=c["text_main"], font=("Segoe UI", 12),
                anchor='w', justify='left', wraplength=bubble_max
            ).pack(fill=tk.X, padx=12, pady=(0, 8))
            if has_attachment:
                ftxt = f"📎 {attachment_name or 'file'} ({max(1, attachment_size // 1024)} KB)"
                fl = tk.Label(
                    bubble, text=ftxt, bg=bubble_bg, fg="#1F4FAE", cursor="hand2",
                    font=("Segoe UI", 10, "underline"), anchor='w', justify='left'
                )
                fl.pack(fill=tk.X, padx=12, pady=(0, 8))
                if msg_id > 0:
                    fl.bind("<Button-1>", lambda _e, mid=msg_id: self._comm_download_attachment(mid))

        if animate:
            self._animate_message_card(bubble, bubble_bg)
        if auto_scroll:
            self.after_idle(self._scroll_comm_to_bottom)

    def _animate_message_card(self, card: tk.Widget, target_bg: str):
        shades = ["#E5EEFF", "#EBF2FF", "#F0F5FF", target_bg]
        def step(i=0):
            if not card.winfo_exists():
                return
            color = shades[min(i, len(shades) - 1)]
            try:
                card.configure(bg=color)
                for ch in card.winfo_children():
                    if ch.winfo_class() != 'Canvas':
                        ch.configure(bg=color)
            except Exception:
                return
            if i + 1 < len(shades):
                card.after(28, lambda: step(i + 1))
        step(0)

    def _refresh_tasks_ui(self):
        if not hasattr(self, 'tasks_tree'):
            return
        self.tasks_tree.delete(*self.tasks_tree.get_children())
        self.tasks_tree.tag_configure('task_unread', font=("Segoe UI", 10, "bold"))
        self.tasks_tree.tag_configure('task_read', font=("Segoe UI", 10))

        status_counts = {'new': 0, 'in_progress': 0, 'done': 0}
        for t in (self.comm_tasks or []):
            st = str(t.get('status', 'new'))
            if st in status_counts:
                status_counts[st] += 1

        if hasattr(self, 'task_filter_buttons'):
            labels = {
                'in_progress': f"Выполняется {status_counts['in_progress']}",
                'new': f"Новые {status_counts['new']}",
                'done': f"Выполнено {status_counts['done']}",
                'all': f"Все {len(self.comm_tasks or [])}"
            }
            for key, btn in self.task_filter_buttons.items():
                active = (self.task_filter_var.get() == key)
                btn.config(
                    text=labels.get(key, key),
                    bg=("#3D7BEB" if active else self.colors["bg_card"]),
                    fg=("#FFFFFF" if active else self.colors["text_main"]),
                    activebackground=("#2B66D9" if active else self.colors["border"]),
                    activeforeground=("#FFFFFF" if active else self.colors["text_main"])
                )

        current_filter = self.task_filter_var.get() if hasattr(self, 'task_filter_var') else 'all'
        for t in (self.comm_tasks or []):
            st = str(t.get('status', 'new'))
            if current_filter != 'all' and st != current_filter:
                continue
            dl = str(t.get('deadline_date', '') or '-')
            left_txt = "-"
            try:
                if dl and dl != '-':
                    days = (datetime.strptime(dl, "%Y-%m-%d").date() - datetime.now().date()).days
                    left_txt = f"{days} дн." if days >= 0 else f"просрочено {-days} дн."
            except Exception:
                left_txt = "-"
            st_txt = {'new': 'Новая', 'in_progress': 'В работе', 'done': 'Выполнено'}.get(st, st)
            tid = int(t.get('task_id', 0)) if str(t.get('task_id', '')).isdigit() else 0
            row_tag = 'task_unread' if tid in self.task_unread_ids else 'task_read'
            self.tasks_tree.insert('', tk.END, values=(
                t.get('task_id'),
                t.get('title', ''),
                t.get('description', ''),
                t.get('assignees_display', ''),
                t.get('watchers_display', ''),
                dl,
                left_txt,
                st_txt
            ), tags=(row_tag,))

    def _task_filter_set(self, status_key):
        if hasattr(self, 'task_filter_var'):
            self.task_filter_var.set(status_key)
        self._refresh_tasks_ui()

    def _on_comm_dialog_select(self):
        if not hasattr(self, 'comm_dialogs_list'):
            return
        sel = self.comm_dialogs_list.curselection()
        if not sel:
            return
        idx = sel[0]
        if idx >= len(self.comm_dialogs):
            return
        dialog_id = int(self.comm_dialogs[idx].get('dialog_id'))
        self.comm_active_dialog_id = dialog_id
        self.comm_no_more_old_by_dialog.discard(dialog_id)
        self.comm_loading_old_dialogs.discard(dialog_id)
        if dialog_id in self.comm_unread_dialog_ids:
            self.comm_unread_dialog_ids.discard(dialog_id)
            if dialog_id in self.comm_unread_by_dialog:
                del self.comm_unread_by_dialog[dialog_id]
            self.comm_unread_count = int(sum(self.comm_unread_by_dialog.values()))
            self._update_sidebar_badges()
            self._refresh_comm_dialogs_ui()
        self.send_ws_message({'type': 'get_comm_messages', 'dialog_id': dialog_id, 'limit': 120})
        self.send_ws_message({'type': 'get_comm_dialog_members', 'dialog_id': dialog_id})

    def _on_task_select(self):
        if not hasattr(self, 'tasks_tree'):
            return
        sel = self.tasks_tree.selection()
        if not sel:
            return
        vals = self.tasks_tree.item(sel[0], 'values')
        if not vals:
            return
        tid = str(vals[0]).strip()
        if not tid.isdigit():
            return
        task_id = int(tid)
        if task_id in self.task_unread_ids:
            self.task_unread_ids.discard(task_id)
            self.tasks_unread_count = max(0, self.tasks_unread_count - 1)
            self._update_sidebar_badges()
            self._refresh_tasks_ui()

    def _comm_create_dialog(self):
        data = self._comm_open_create_dialog()
        if not data:
            return
        self.send_ws_message({'type': 'create_comm_dialog', 'dialog': data})

    def _comm_create_all_group(self):
        all_ids = [int(u.get('user_id')) for u in (self.comm_users or []) if str(u.get('user_id', '')).isdigit()]
        if not all_ids:
            return
        self.send_ws_message({'type': 'create_comm_dialog', 'dialog': {
            'title': 'All users',
            'participant_ids': all_ids,
            'is_group': True
        }})

    def _comm_add_participants(self):
        if self.comm_active_dialog_id is None:
            messagebox.showwarning('Communication', 'Select a dialog first')
            return
        picks = self._comm_open_user_picker('Add participants')
        if not picks:
            return
        self.send_ws_message({'type': 'add_comm_dialog_participants', 'dialog_id': int(self.comm_active_dialog_id), 'participant_ids': picks})

    def _comm_send_message(self):
        if self.comm_active_dialog_id is None:
            messagebox.showwarning('Communication', 'Select a dialog')
            return
        txt = (self.comm_message_var.get() or '').strip()
        if not txt:
            return
        self.send_ws_message({'type': 'send_comm_message', 'dialog_id': int(self.comm_active_dialog_id), 'text': txt})
        self.comm_message_var.set('')

    def _task_create(self):
        title = (self.task_title_var.get() or '').strip()
        if not title or not self.task_assignee_ids:
            messagebox.showwarning('Tasks', 'Fill title and assignees')
            return
        deadline = self.task_deadline_entry.get_date().strftime('%Y-%m-%d') if hasattr(self, 'task_deadline_entry') else ''
        self.send_ws_message({'type': 'create_comm_task', 'task': {
            'title': title,
            'description': (self.task_desc_entry.get("1.0", tk.END).strip() if hasattr(self, 'task_desc_entry') else ''),
            'assignee_ids': list(self.task_assignee_ids),
            'watcher_ids': list(self.task_watcher_ids),
            'deadline_date': deadline
        }})
        self.task_title_var.set('')
        if hasattr(self, 'task_desc_entry'):
            self.task_desc_entry.delete("1.0", tk.END)
        self.task_assignee_ids = []
        self.task_watcher_ids = []
        self.task_assignees_var.set('')
        self.task_watchers_var.set('')

    def _task_open_people_picker(self, target='assignees'):
        # Страховка: окно выбора исполнителей открываем только во вкладке "Задания".
        if getattr(self, 'current_page_key', '') != 'tasks_main':
            return
        pre = self.task_assignee_ids if target == 'assignees' else self.task_watcher_ids
        picked = self._comm_open_user_picker(
            'Исполнители' if target == 'assignees' else 'Наблюдатели (@видят)',
            preselected=set(pre)
        )
        if picked is None:
            return
        user_map = self._comm_user_map()
        if target == 'assignees':
            self.task_assignee_ids = [int(x) for x in picked if int(x) in user_map]
        else:
            self.task_watcher_ids = [int(x) for x in picked if int(x) in user_map]
        assignee_names = [self._comm_user_display(user_map.get(uid, {})) or str(uid) for uid in self.task_assignee_ids]
        watcher_names = [self._comm_user_display(user_map.get(uid, {})) or str(uid) for uid in self.task_watcher_ids]
        self.task_assignees_var.set(", ".join(assignee_names))
        self.task_watchers_var.set(", ".join(watcher_names))

    def _task_update_status(self, status):
        if not hasattr(self, 'tasks_tree'):
            return
        sel = self.tasks_tree.selection()
        if not sel:
            return
        vals = self.tasks_tree.item(sel[0], 'values')
        if not vals:
            return
        task_id = str(vals[0]).strip()
        if not task_id.isdigit():
            return
        self.send_ws_message({'type': 'update_comm_task_status', 'task_id': int(task_id), 'status': status})

