    def _shared_files_transfer_update(self, direction: str, text: str, value: int = None, done: bool = False, hide_delay_ms: int = 1400):
        direction = str(direction or '').strip().lower()
        safe_value = None
        if value is not None:
            try:
                safe_value = max(0, min(100, int(value)))
            except Exception:
                safe_value = None
        if not hasattr(self, 'shared_files_transfer_overlay'):
            return
        if self.shared_files_transfer_hide_after_id:
            try:
                self.after_cancel(self.shared_files_transfer_hide_after_id)
            except Exception:
                pass
            self.shared_files_transfer_hide_after_id = None
        prefix = "Передача"
        if direction == 'upload':
            prefix = "Загрузка"
        elif direction == 'download':
            prefix = "Скачивание"
        self.shared_files_transfer_text_var.set(f"{prefix}: {str(text or '').strip()}")
        if safe_value is not None:
            self.shared_files_transfer_progress_var.set(safe_value)
        place_kwargs = {'x': 0, 'y': 0}
        try:
            top = getattr(self, 'shared_files_top_frame', None)
            btns = getattr(self, 'shared_files_btns_frame', None)
            if top is not None and btns is not None:
                top.update_idletasks()
                btns.update_idletasks()
                btns_x = int(btns.winfo_x() or 0)
                if btns_x > 280:
                    place_kwargs['width'] = max(260, btns_x - 8)
                else:
                    top_w = int(top.winfo_width() or top.winfo_reqwidth() or 0)
                    place_kwargs['width'] = max(260, int(top_w * 0.55))
            else:
                place_kwargs['relwidth'] = 0.55
        except Exception:
            place_kwargs['relwidth'] = 0.55
        self.shared_files_transfer_overlay.place(**place_kwargs)
        self.shared_files_transfer_overlay.lift()
        if done:
            self.shared_files_transfer_hide_after_id = self.after(
                max(300, int(hide_delay_ms or 1400)),
                self._shared_files_transfer_hide
            )

    def _shared_files_transfer_hide(self):
        if hasattr(self, 'shared_files_transfer_overlay'):
            self.shared_files_transfer_overlay.place_forget()
        self.shared_files_transfer_hide_after_id = None

    def _shared_files_upload_start_next(self):
        if self.shared_files_upload_in_progress:
            return
        if not self.shared_files_upload_queue:
            total = int(self.shared_files_upload_total or 0)
            done = int(self.shared_files_upload_done or 0)
            if total > 0:
                self._shared_files_transfer_update('upload', f"готово {done}/{total}", 100, done=True, hide_delay_ms=1800)
            self.shared_files_upload_total = 0
            self.shared_files_upload_done = 0
            return
        path = self.shared_files_upload_queue.pop(0)
        self.shared_files_upload_in_progress = True
        self._shared_files_upload_send_one(path)

    def _shared_files_upload_schedule_next(self, delay_ms: int = 10):
        self.after(max(0, int(delay_ms or 0)), self._shared_files_upload_start_next)

    def _shared_files_upload_send_one(self, path: str):
        try:
            total = max(1, int(self.shared_files_upload_total or 1))
            current = int(self.shared_files_upload_done or 0) + 1
            name = os.path.basename(path)
            self.shared_files_last_upload_name = name
            self._shared_files_transfer_update('upload', f"файл {current}/{total}: чтение «{name}»", 12)
            with open(path, 'rb') as f:
                raw = f.read()
            self._shared_files_transfer_update('upload', f"файл {current}/{total}: подготовка «{name}»", 45)
            payload = {
                'parent_id': int(self.shared_files_current_folder_id or 0),
                'file_name': name,
                'mime_type': mimetypes.guess_type(path)[0] or 'application/octet-stream',
                'file_data_b64': base64.b64encode(raw).decode('ascii')
            }
            self.shared_files_active_upload_payload = dict(payload)
            self._shared_files_store_pending('upload_file', payload)
            self._shared_files_transfer_update('upload', f"файл {current}/{total}: отправка «{name}»", 80)
            self.send_ws_message({'type': 'upload_shared_file', **payload})
            self._shared_files_upload_arm_timeout()
        except Exception as e:
            self.shared_files_upload_done += 1
            self.shared_files_upload_in_progress = False
            self.shared_files_active_upload_payload = None
            self._shared_files_transfer_update('upload', f"ошибка чтения ({e})", 0, done=True, hide_delay_ms=2500)
            if self.shared_files_upload_queue:
                self._shared_files_upload_start_next()
            else:
                messagebox.showerror("Файлы", f"Не удалось загрузить файл:\n{e}")

    def _shared_files_upload_arm_timeout(self, timeout_ms: int = 30000):
        if self.shared_files_upload_wait_after_id:
            try:
                self.after_cancel(self.shared_files_upload_wait_after_id)
            except Exception:
                pass
        self.shared_files_upload_wait_after_id = self.after(
            max(5000, int(timeout_ms or 30000)),
            self._shared_files_upload_on_timeout
        )

    def _shared_files_upload_clear_timeout(self):
        if self.shared_files_upload_wait_after_id:
            try:
                self.after_cancel(self.shared_files_upload_wait_after_id)
            except Exception:
                pass
            self.shared_files_upload_wait_after_id = None

    def _shared_files_upload_on_timeout(self):
        self.shared_files_upload_wait_after_id = None
        if not self.shared_files_upload_in_progress:
            return
        self.shared_files_upload_in_progress = False
        self.shared_files_active_upload_payload = None
        self.shared_files_upload_done += 1
        self._shared_files_transfer_update('upload', "таймаут ответа, продолжаю очередь", 0, done=(not self.shared_files_upload_queue), hide_delay_ms=2200)
        self._shared_files_upload_schedule_next()

    def _shared_files_upload_finish_current(self):
        if not self.shared_files_upload_in_progress and not self.shared_files_upload_queue:
            self._shared_files_upload_schedule_next()
            return
        self._shared_files_upload_clear_timeout()
        if self.shared_files_upload_in_progress:
            self.shared_files_upload_done += 1
        self.shared_files_upload_in_progress = False
        self.shared_files_active_upload_payload = None
        self._shared_files_upload_schedule_next()

    def _shared_files_conflict_dialog(self, file_name: str) -> str:
        result = {'value': 'skip'}
        dlg = tk.Toplevel(self)
        dlg.title("Файл уже существует")
        dlg.transient(self)
        dlg.grab_set()
        self.center_dialog(dlg, 480, 170)
        c = self.colors
        body = tk.Frame(dlg, bg=c["bg_card"], padx=16, pady=16)
        body.pack(fill=tk.BOTH, expand=True)
        tk.Label(
            body,
            text=f"Файл «{file_name}» уже существует.\nЧто сделать?",
            bg=c["bg_card"],
            fg=c["text_main"],
            font=("Segoe UI", 10),
            justify=tk.LEFT,
            anchor="w"
        ).pack(anchor='w')
        btns = tk.Frame(body, bg=c["bg_card"])
        btns.pack(anchor='e', pady=(16, 0))

        def _set(choice: str):
            result['value'] = choice
            dlg.destroy()

        ttk.Button(btns, text="Пропустить", command=lambda: _set('skip')).pack(side=tk.RIGHT, padx=4)
        ttk.Button(btns, text="Удалить", command=lambda: _set('delete')).pack(side=tk.RIGHT, padx=4)
        ttk.Button(btns, text="Заменить", command=lambda: _set('replace')).pack(side=tk.RIGHT, padx=4)
        dlg.bind('<Escape>', lambda _e: _set('skip'))
        self.wait_window(dlg)
        return str(result.get('value') or 'skip')

    def _shared_files_format_size(self, size: int) -> str:
        try:
            value = float(size or 0)
        except Exception:
            value = 0.0
        if value <= 0:
            return ""
        units = ['B', 'KB', 'MB', 'GB']
        idx = 0
        while value >= 1024 and idx < len(units) - 1:
            value /= 1024.0
            idx += 1
        return f"{value:.1f} {units[idx]}"

    def _shared_files_selected_entry(self):
        if not hasattr(self, 'shared_files_tree'):
            return None
        sel = self.shared_files_tree.selection()
        if not sel:
            return None
        if sel[0] == '__parent__':
            return {'entry_id': int(self.shared_files_parent_id or 0), 'entry_type': 'parent', 'name': '..'}
        try:
            entry_id = int(sel[0])
        except Exception:
            return None
        return (self.shared_files_entries_by_id or {}).get(entry_id)

    def _shared_files_selected_entries(self):
        if not hasattr(self, 'shared_files_tree'):
            return []
        result = []
        for iid in self.shared_files_tree.selection() or ():
            if str(iid) == '__parent__':
                continue
            try:
                eid = int(iid)
            except Exception:
                continue
            item = (self.shared_files_entries_by_id or {}).get(eid)
            if item:
                result.append(item)
        return result

    def shared_files_update_buttons(self):
        entries = self._shared_files_selected_entries()
        has_sel = bool(entries)
        self._shared_files_render_fixed_up_row()
        if hasattr(self, 'shared_files_status_var'):
            if not has_sel:
                self.shared_files_status_var.set("Выбери папку или файл.")
            elif len(entries) > 1:
                self.shared_files_status_var.set(f"Выбрано объектов: {len(entries)}")
            else:
                entry = entries[0]
                who = str(entry.get('last_opened_by_username') or '—')
                when = str(entry.get('last_opened_at') or '—')
                self.shared_files_status_var.set(f"Последнее открытие: {when} | Кто открывал: {who}")

    def _shared_files_render_fixed_up_row(self):
        tree = getattr(self, 'shared_files_up_tree', None)
        if tree is None:
            return
        try:
            tree.delete(*tree.get_children())
        except Exception:
            return
        can_go_up = int(self.shared_files_current_folder_id or 0) > 0
        text = "[..]"
        if can_go_up:
            values = ("Переход вверх", "", "", "", "", "", "")
        else:
            values = ("Корневая папка", "", "", "", "", "", "")
        try:
            tree.insert('', tk.END, iid='__fixed_parent__', text=text, values=values)
            if can_go_up:
                tree.tag_configure('fixed_up_active', foreground=self.colors.get("accent", "#2563EB"))
                tree.item('__fixed_parent__', tags=('fixed_up_active',))
            else:
                tree.tag_configure('fixed_up_idle', foreground=self.colors.get("text_light", "#6B7280"))
                tree.item('__fixed_parent__', tags=('fixed_up_idle',))
        except Exception:
            pass

    def _shared_files_click_fixed_up_row(self, _event=None):
        if int(self.shared_files_current_folder_id or 0) > 0:
            self.shared_files_go_up()
        return "break"

    def _shared_files_store_pending(self, action: str, request_data: dict):
        self.shared_files_pending_request = {
            'requested_action': str(action or ''),
            'request_data': dict(request_data or {})
        }

    def shared_files_refresh(self, folder_id=None):
        if folder_id is None:
            folder_id = int(self.shared_files_current_folder_id or 0)
        self._shared_files_request_listing(folder_id, track_pending=True)

    def _shared_files_request_listing(self, folder_id, track_pending: bool = True):
        folder_id = int(folder_id or 0)
        if bool(track_pending):
            self._shared_files_store_pending('open_folder', {'folder_id': folder_id})
        sent = self.send_ws_message({'type': 'get_shared_files_listing', 'folder_id': folder_id})
        if not sent:
            if hasattr(self, 'shared_files_status_var'):
                self.shared_files_status_var.set("Нет связи с сервером. Повторяю запрос...")
            if self.current_page_key == 'files_main':
                if self.shared_files_retry_after_id:
                    try:
                        self.after_cancel(self.shared_files_retry_after_id)
                    except Exception:
                        pass
                self.shared_files_retry_after_id = self.after(
                    1200,
                    lambda fid=folder_id: self._shared_files_request_listing(fid, track_pending=False)
                )

    def shared_files_go_up(self):
        if int(self.shared_files_current_folder_id or 0) <= 0:
            return
        self.shared_files_refresh(int(self.shared_files_parent_id or 0))

    def shared_files_create_folder(self):
        name = simpledialog.askstring("Новая папка", "Название новой папки:", parent=self)
        if name is None:
            return
        name = str(name or '').strip()
        if not name:
            return
        payload = {'parent_id': int(self.shared_files_current_folder_id or 0), 'name': name}
        self._shared_files_store_pending('create_folder', payload)
        self.send_ws_message({'type': 'create_shared_folder', **payload})

    def shared_files_upload_files(self):
        paths = filedialog.askopenfilenames(
            title="Выберите файлы",
            filetypes=[("All files", "*.*")]
        )
        if not paths:
            return
        incoming = [str(p) for p in paths if str(p).strip()]
        if not incoming:
            return
        if self.shared_files_upload_in_progress:
            self.shared_files_upload_queue.extend(incoming)
            self.shared_files_upload_total += len(incoming)
            self._shared_files_transfer_update(
                'upload',
                f"добавлено в очередь: {len(incoming)} (всего {self.shared_files_upload_total})",
                80
            )
            return
        self.shared_files_upload_queue = incoming
        self.shared_files_upload_total = len(incoming)
        self.shared_files_upload_done = 0
        self._shared_files_upload_start_next()

    def shared_files_open_selected(self):
        entry = self._shared_files_selected_entry()
        if not entry:
            return
        if entry.get('entry_type') == 'parent':
            self.shared_files_go_up()
        elif entry.get('entry_type') == 'folder':
            self.shared_files_refresh(int(entry.get('entry_id') or 0))
        else:
            self.shared_files_download_selected()

    def shared_files_download_selected(self):
        entry = self._shared_files_selected_entry()
        if not entry or entry.get('entry_type') != 'file':
            return
        payload = {'entry_id': int(entry.get('entry_id') or 0)}
        self.shared_files_last_download_name = str(entry.get('name') or 'file.bin')
        self._shared_files_transfer_update('download', f"запрос «{self.shared_files_last_download_name}»", 20)
        self._shared_files_store_pending('download_file', payload)
        self.send_ws_message({'type': 'download_shared_file', **payload})

    def shared_files_delete_selected(self):
        entries = self._shared_files_selected_entries()
        if not entries:
            return
        denied = [e for e in entries if not e.get('can_delete')]
        if denied:
            if len(denied) == len(entries):
                messagebox.showwarning("Файлы", "Удалять можно только свои объекты (или под админом).")
                return
            messagebox.showwarning("Файлы", f"Часть объектов пропущена (нет прав): {len(denied)}")
        targets = [e for e in entries if e.get('can_delete')]
        if not targets:
            return
        if len(targets) == 1:
            entry = targets[0]
            kind = "папку" if entry.get('entry_type') == 'folder' else "файл"
            if not messagebox.askyesno("Удаление", f"Удалить {kind} «{entry.get('name', '')}»?"):
                return
        else:
            if not messagebox.askyesno("Массовое удаление", f"Удалить выбранные объекты: {len(targets)} шт.?"):
                return
        for entry in targets:
            self.send_ws_message({'type': 'delete_shared_file_entry', 'entry_id': int(entry.get('entry_id') or 0)})

    def shared_files_set_password(self):
        entries = self._shared_files_selected_entries()
        if not entries:
            return
        denied = [e for e in entries if not e.get('can_set_password')]
        if denied and len(denied) == len(entries):
            messagebox.showwarning("Файлы", "Пароль можно назначать только на свои объекты.")
            return
        targets = [e for e in entries if e.get('can_set_password')]
        if denied:
            messagebox.showwarning("Файлы", f"Часть объектов пропущена (нет прав): {len(denied)}")
        password = simpledialog.askstring(
            "Пароль",
            "Введи пароль для выбранных объектов.\nОставь поле пустым, чтобы снять пароль у всех выбранных.",
            parent=self,
            show='*'
        )
        if password is None:
            return
        for entry in targets:
            self.send_ws_message({
                'type': 'set_shared_file_password',
                'entry_id': int(entry.get('entry_id') or 0),
                'password': str(password)
            })

    def _shared_files_apply_listing(self, data):
        if self.shared_files_retry_after_id:
            try:
                self.after_cancel(self.shared_files_retry_after_id)
            except Exception:
                pass
            self.shared_files_retry_after_id = None
        self.shared_files_current_folder_id = int(data.get('folder_id') or 0)
        self.shared_files_parent_id = int(data.get('parent_id') or 0)
        self.shared_files_path = data.get('path') if isinstance(data.get('path'), list) else [{'entry_id': 0, 'name': 'Файлы'}]
        self.shared_files_entries = data.get('entries') if isinstance(data.get('entries'), list) else []
        self.shared_files_entries_by_id = {}
        if hasattr(self, 'shared_files_tree'):
            self.shared_files_tree.delete(*self.shared_files_tree.get_children())
            for entry in self.shared_files_entries:
                entry_id = int(entry.get('entry_id') or 0)
                self.shared_files_entries_by_id[entry_id] = entry
                icon_name = "📁 " if entry.get('entry_type') == 'folder' else "📄 "
                if entry.get('has_password'):
                    icon_name = "🔒 " + icon_name
                self.shared_files_tree.insert(
                    '',
                    tk.END,
                    iid=str(entry_id),
                    text=f"{icon_name}{entry.get('name', '')}",
                    values=(
                        'Папка' if entry.get('entry_type') == 'folder' else 'Файл',
                        '' if entry.get('entry_type') == 'folder' else self._shared_files_format_size(entry.get('file_size', 0)),
                        entry.get('created_by_username', ''),
                        entry.get('created_at', ''),
                        'Да' if entry.get('has_password') else '',
                        entry.get('last_opened_at', ''),
                        entry.get('last_opened_by_username', ''),
                    )
                )
        names = [str(x.get('name') or '') for x in (self.shared_files_path or [])[1:] if str(x.get('name') or '').strip()]
        path_text = "/" if not names else "/" + "/".join(names)
        if hasattr(self, 'shared_files_path_var'):
            self.shared_files_path_var.set(f"Путь: {path_text}")
        self.shared_files_update_buttons()

    def _shared_files_handle_password_required(self, data):
        requested_action = str(data.get('requested_action') or '').strip()
        request_data = data.get('request_data') if isinstance(data.get('request_data'), dict) else {}
        pending = self.shared_files_pending_request if isinstance(self.shared_files_pending_request, dict) else {}
        if pending.get('requested_action') == requested_action and isinstance(pending.get('request_data'), dict):
            merged_request = dict(request_data)
            merged_request.update(pending.get('request_data') or {})
        else:
            merged_request = dict(request_data)
        password = simpledialog.askstring(
            "Пароль",
            f"Для элемента «{data.get('entry_name', '')}» нужен пароль.",
            parent=self,
            show='*'
        )
        if password is None:
            return
        self.send_ws_message({
            'type': 'unlock_shared_file_entry',
            'entry_id': int(data.get('entry_id') or 0),
            'password': str(password),
            'requested_action': requested_action,
            'request_data': merged_request
        })

    def send_ws_message(self, data):
        """Отправка сообщения на сервер"""
        msg_type = data.get('type', 'unknown')
        silent_inventory = bool(data.get('_inventory_silent'))
        if not hasattr(self, '_offline_ws_queue'):
            self._offline_ws_queue = []

        if self.ws and self.ws_loop and self.authenticated:
            print(f"[WS] Отправка сообщения типа '{msg_type}' на сервер")
            future = asyncio.run_coroutine_threadsafe(
                self.ws.send(json.dumps(data)),
                self.ws_loop
            )
            # Важно: контролируем реальный результат отправки.
            def _on_done(fut, payload=data, mtype=msg_type):
                try:
                    fut.result()
                except Exception as e:
                    print(f"[WS] ❌ Ошибка отправки '{mtype}': {e}")
                    # Для инвентаризации сохраняем в очередь и отправим при реконнекте.
                    if mtype == 'save_daily_stock_report':
                        if not silent_inventory:
                            self._offline_ws_queue.append(payload)
                        if not silent_inventory:
                            self.after(0, lambda: messagebox.showwarning(
                                "Связь потеряна",
                                "Инвентаризация временно не отправлена.\n"
                                "Запись добавлена в очередь и будет отправлена после переподключения."
                            ))
                    self.after(0, self.update_connection_status, False)
            future.add_done_callback(_on_done)
            return True
        else:
            print(f"[WS] ❌ НЕ отправлено '{msg_type}': ws={bool(self.ws)}, loop={bool(self.ws_loop)}, auth={self.authenticated}")
            if msg_type == 'save_daily_stock_report':
                if not silent_inventory:
                    self._offline_ws_queue.append(data)
                if not silent_inventory:
                    self.after(0, lambda: messagebox.showwarning(
                        "Нет подключения",
                        "Инвентаризация не отправлена на сервер.\n"
                        "Запись сохранена в очередь и будет отправлена после переподключения."
                    ))
            elif msg_type == 'get_daily_stock_report':
                self.after(0, lambda: messagebox.showwarning(
                    "Нет подключения",
                    "Не удалось загрузить отчет за выбранную дату: нет связи с сервером."
                ))
            return False

    def update_connection_status(self, connected):
        """Обновление статуса подключения"""
        if hasattr(self, 'status_label') and self.status_label.winfo_exists():
            if connected:
                self.status_label.config(text="🟢 Подключен")
            else:
                self.status_label.config(text="🔴 Отключен")

    def on_double_click(self, event, tree):
        """
        ИСПРАВЛЕННАЯ ЛОГИКА: Разделение действий без конфликтов.
        """
        region = tree.identify_region(event.x, event.y)
        if region != "cell": return
    
        column = tree.identify_column(event.x)
        item_id = tree.identify_row(event.y)
        
        # Если кликнули по дочерней строке (самому заказу) - выходим
        if tree.parent(item_id): return

        try:
            col_idx = int(column[1:]) - 1
        except: return
        
        values = tree.item(item_id)['values']
        if not values: return

        # === 1. ЛОГИКА РАСКРЫТИЯ (Только колонка ПЛАН - индекс 6) ===
        if col_idx == 6:
            # Переключаем состояние
            if tree.item(item_id, 'open'):
                tree.item(item_id, open=False)
            else:
                tree.item(item_id, open=True)
                # Подгружаем данные
                self.on_plan_tree_open(None) 
            # ВАЖНО: return "break" предотвращает дальнейшую обработку события системой
            return "break" 

        # === 2. БЫСТРОЕ РЕДАКТИРОВАНИЕ (Запас - 4, Факт - 7) ===
        if col_idx in [4, 7]:
            current_val = values[col_idx]
            display_val = str(current_val)
            if display_val == "-" or display_val == "0": display_val = ""
        
            x, y, w, h = tree.bbox(item_id, column)
            entry = tk.Entry(tree, font=("Arial", 10))
            entry.insert(0, display_val)
            entry.place(x=x, y=y, width=w, height=h)
            entry.focus_set()
            entry.selection_range(0, tk.END)

            def save_edit(event_inner=None):
                new_val = entry.get().strip().replace(',', '.')
                num_val = float(new_val) if new_val else 0.0
                
                # Обновляем визуально
                new_values_list = list(tree.item(item_id)['values'])
                new_values_list[col_idx] = num_val if num_val != 0 else "-"
                tree.item(item_id, values=new_values_list)
                
                art_nr = str(new_values_list[1])
                date_str = self.plan_date_entry.get_date().strftime('%Y-%m-%d')
                
                if col_idx == 7: # Факт
                    self.send_ws_message({'type': 'update_production_fact', 'date': date_str, 'article_nr': art_nr, 'fact_qty': num_val})
                elif col_idx == 4: # Запас
                    self.send_ws_message({'type': 'adjust_stock', 'date': date_str, 'article_nr': art_nr, 'new_qty': num_val})

                entry.destroy()
                tree.focus_set()

            entry.bind("<Return>", save_edit)
            entry.bind("<KP_Enter>", save_edit)
            entry.bind("<Escape>", lambda e: entry.destroy())
            entry.bind("<FocusOut>", lambda e: entry.destroy())
            return "break" # Блокируем, чтобы окно не открылось

        # === 3. БОЛЬШАЯ КАРТОЧКА (Все остальные колонки) ===
        # Сюда код дойдет только если это НЕ План, НЕ Факт и НЕ Запас
        self.show_production_detail_dialog(event)
        return "break"

    def save_substitution(self):
        old_a = self.old_art_var.get().strip().zfill(5)
        new_a = self.new_art_var.get().strip().zfill(5)
        if old_a and new_a:
            self.send_ws_message({
                'type': 'save_substitution',
                'old': old_a,
                'new': new_a
            })
            self.old_art_var.set("")
            self.new_art_var.set("")
            messagebox.showinfo("Успех", f"Товары связаны! Прогноз для {new_a} будет браться из истории {old_a}")    
            
    def keyboard_edit_cell(self, tree):
        """Активирует редактирование ячейки 'Факт' для выбранной строки через F10"""
        selected = tree.selection()
        if not selected: 
            return
        
        item_id = selected[0]
        # Определяем колонку "Факт". В вашей таблице (11 колонок) это будет индекс #8
        # (0:Цех, 1:Арт, 2:Торт, 3:Прогноз, 4:Запас, 5:Спрос, 6:План, 7:Факт)
        target_col = "#8" 
        
        # Получаем координаты ячейки, чтобы "нарисовать" там поле ввода
        bbox = tree.bbox(item_id, target_col)
        if bbox:
            # Создаем фейковое событие, чтобы использовать уже готовый метод on_double_click
            class FakeEvent:
                def __init__(self, x, y):
                    self.x = x
                    self.y = y
            
            # Передаем координаты центра нужной ячейки
            fake_e = FakeEvent(bbox[0] + bbox[2]//2, bbox[1] + bbox[3]//2)
            self.on_double_click(fake_e, tree)        

            

